-- Poems batch 25
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('52e5a6f6-2c67-4977-9eba-b255737e68ba','上巳日贈都上人 二','殷堯藩','唐','唐诗','tang','','[]','曲水公卿宴，香塵盡滿街。',48,'全唐诗/poet.tang.26000.json','["曲水公卿宴，香塵盡滿街。", "無心修禊事，獨步到禪齋。", "細草縈愁目，繁花逆旅懷。", "綺羅人走馬，遺落鳳皇釵。"]'),
('59e31364-11d7-422a-b2a3-d0142a85608a','送沈亞之尉南康','殷堯藩','唐','唐诗','tang','','[]','行邁南康路，客心離怨多。',48,'全唐诗/poet.tang.26000.json','["行邁南康路，客心離怨多。", "暮煙葵葉屋，秋月竹枝歌。", "孤鶴唳殘夢，驚猨嘯薜蘿。", "對江翹首望，愁淚疊如波。"]'),
('d4e6da3d-9bd2-4d7e-89b8-2c775c3837b1','奉送劉使君王屋山隱居','殷堯藩','唐','唐诗','tang','','[]','散髮風簷下，沈沈日漸曛。',48,'全唐诗/poet.tang.26000.json','["散髮風簷下，沈沈日漸曛。", "鷹拳擒野雀，蛛網獵飛蚊。", "羣動能歸計，吾生亦謾勤。", "塵緣難著眼，晚興寄青雲。"]'),
('249acc9f-3402-4fd5-a184-5c8de6bc2e6d','寄許渾秀才','殷堯藩','唐','唐诗','tang','','[]','文字飢難煮，爲農策最良。',48,'全唐诗/poet.tang.26000.json','["文字飢難煮，爲農策最良。", "興來鉏曉月，倦後臥斜陽。", "秋稼連千頃，春花醉幾場。", "任他名利客，車馬鬧康莊。"]'),
('eddfe9a7-6e8f-4184-b074-0fbbac6d2a23','送客遊吳','殷堯藩','唐','唐诗','tang','','[]','吳國水中央，波濤白渺茫。',48,'全唐诗/poet.tang.26000.json','["吳國水中央，波濤白渺茫。", "衣逢梅雨漬，船入稻花香。", "海戍通鹽竈，山村帶蜜房。", "欲知蘇小小，君試到錢塘。"]'),
('9fa0163f-9a64-46c0-8177-ad3aa1e328f7','陸丞相故宅','殷堯藩','唐','唐诗','tang','','[]','衣冠零落久，今日事堪傷。',48,'全唐诗/poet.tang.26000.json','["衣冠零落久，今日事堪傷。", "廚起青烟薄，門開白日長。", "殘梅欹古道，名石臥頹牆。", "山色依然好，興衰未可量。"]'),
('73fb4393-c9cf-4599-b0ca-3ef1f61eb9e5','中元日觀諸道士步虛','殷堯藩','唐','唐诗','tang','','[]','玄都開秘籙，白石禮先生。',72,'全唐诗/poet.tang.26000.json','["玄都開秘籙，白石禮先生。", "上界秋光淨，中元夜氣清。", "星辰朝帝處，鸞鶴步虛聲。", "玉洞花長發，珠宮月最明。", "掃壇天地肅，投簡鬼神驚。", "儻賜刀圭藥，還留不死名。"]'),
('da5667b8-5454-42eb-a593-24ec36a52c44','醉贈劉十二','殷堯藩','唐','唐诗','tang','','[]','春草正淒淒，知君過惡溪。',72,'全唐诗/poet.tang.26000.json','["春草正淒淒，知君過惡溪。", "鶯將吉了語，猿共猓然啼。", "別路魂先斷，還家夢幾迷。", "定尋雷令劒，應識越王笄。", "樹色多於北，潮聲少向西。", "椰花好爲酒，誰伴醉如泥。"]'),
('29eef040-1804-4265-9c38-5248be13fd83','早朝','殷堯藩','唐','唐诗','tang','','[]','曙鍾催入紫宸朝，列炬流虹映絳綃。',64,'全唐诗/poet.tang.26000.json','["曙鍾催入紫宸朝，列炬流虹映絳綃。", "天近鰲頭花簇杖，風低豹尾樂鳴韶。", "衣冠一變無夷俗，律令重頒有正條。", "昨日鍾山甘露降，玻璃滿賜出宮瓢。"]'),
('a81c2c8f-25ce-4ae1-b2d1-cb3530865370','帝京二首 一','殷堯藩','唐','唐诗','tang','','[]','列郡徵才起俊髦，萬機獨使聖躬勞。',64,'全唐诗/poet.tang.26000.json','["列郡徵才起俊髦，萬機獨使聖躬勞。", "開藩上相頒龍節，破虜將軍展豹韜。", "地入黃圖三輔壯，天垂華蓋七星高。", "迎春別賜瑤池宴，捧進金盤五色桃。"]'),
('23ffab61-1c67-43ed-b2b6-5928ce04d052','帝京二首 二','殷堯藩','唐','唐诗','tang','','[]','龍虎山河御氣通，遙瞻帝闕五雲紅。',64,'全唐诗/poet.tang.26000.json','["龍虎山河御氣通，遙瞻帝闕五雲紅。", "英雄盡入江東籍，將相多收薊北功。", "禮樂日稽三代盛，梯航歲貢萬方同。", "都將儉德熙文治，淳俗應還太古風。"]'),
('c9825c19-aa51-4fbf-93f0-3d940f13e2de','宮詞','殷堯藩','唐','唐诗','tang','','[]','悄悄深宮不見人，倚闌惟見石麒麟。',64,'全唐诗/poet.tang.26000.json','["悄悄深宮不見人，倚闌惟見石麒麟。", "芙蓉帳冷愁長夜，翡翠簾垂隔小春。", "天遠難通青鳥信，風寒欲動錦花茵。", "夜深怕有羊車過，自起籠燈看雪紋。"]'),
('224283cd-4894-4b68-ac4f-9011f1dfa59c','郊居作','殷堯藩','唐','唐诗','tang','','[]','碧樹濃陰護短垣，蒼江春煖渚鳧喧。',64,'全唐诗/poet.tang.26000.json','["碧樹濃陰護短垣，蒼江春煖渚鳧喧。", "買魚試喚鳴榔艇，尋鶴因行隔壠村。", "生理何憑文是業，世情縱遣酒盈樽。", "相逢謂我迂疎甚，欲辨還憎恐失言。"]'),
('d475d066-270f-4466-aef1-ed6c8cf346fc','閑居','殷堯藩','唐','唐诗','tang','','[]','茂苑閑居木石同，旋開小逕翦蒿蓬。',64,'全唐诗/poet.tang.26000.json','["茂苑閑居木石同，旋開小逕翦蒿蓬。", "虛遊心在鴻蒙外，穴處身疑培塿中。", "花影一闌吟夜月，松聲半榻臥秋風。", "百年寄傲聊容膝，何必高車駟馬通。"]'),
('80971174-d3d6-44ac-879c-7aaab5058a8a','暮春述懷','殷堯藩','唐','唐诗','tang','','[]','爲客山南二十年，愁來怳近落花天。',64,'全唐诗/poet.tang.26000.json','["爲客山南二十年，愁來怳近落花天。", "陰雲帶雨連山脊，濕氣成嵐滴樹巔。", "隣屋有聲敲石火，野禽無語避茶煙。", "此時若遇孫陽顧，肯服鹽車不受鞭。"]'),
('508e5a40-2ce9-41af-9bf5-7c58830b0fae','端午日','殷堯藩','唐','唐诗','tang','','["\u4eba\u751f", "\u7aef\u5348\u8282", "\u611f\u53f9"]','少年佳節倍多情，老去誰知感慨生。',64,'全唐诗/poet.tang.26000.json','["少年佳節倍多情，老去誰知感慨生。", "不効艾符趨習俗，但祈蒲酒話昇平。", "鬢絲日日添頭白，榴錦年年照眼明。", "千載賢愚同瞬息，幾人湮沒幾垂名。"]'),
('fd14cb55-cb21-4ae0-99b0-763b408906c0','九日','殷堯藩','唐','唐诗','tang','','[]','萬里飄零十二秋，不堪今倚夕陽樓。',64,'全唐诗/poet.tang.26000.json','["萬里飄零十二秋，不堪今倚夕陽樓。", "壯懷空擲班超筆，久客誰憐季子裘。", "瘴雨蠻煙朝暮景，平蕪野草古今愁。", "酣歌欲盡登高興，強把黃花插滿頭。"]'),
('9443bc15-f9d4-44c7-908c-86bc2fe051d6','九日病起','殷堯藩','唐','唐诗','tang','','[]','重陽開滿菊花金，病起榰牀惜賞心。',64,'全唐诗/poet.tang.26000.json','["重陽開滿菊花金，病起榰牀惜賞心。", "紫蟹霜肥秋縱好，綠醅蟻滑晚慵斟。", "眼窺薄霧行殊倦，身怯寒風坐未禁。", "沈醉又成來歲約，遣懷聊作記時吟。"]'),
('d08de206-97dd-42ef-8bd6-c81a3e6496e0','寒夜','殷堯藩','唐','唐诗','tang','','[]','雲冷江空歲暮時，竹陰梅影月參差。',64,'全唐诗/poet.tang.26000.json','["雲冷江空歲暮時，竹陰梅影月參差。", "雞催夢枕司晨早，更咽寒城報點遲。", "人事紛華潛動息，天心靜默運推移。", "憑誰蕩滌窮殘候，入眼東風喜在期。"]'),
('973d40f8-bd19-485b-b579-b994216de74a','喜雨','殷堯藩','唐','唐诗','tang','','[]','臨岐終日自裴回，乾我茅齋半畝苔。',64,'全唐诗/poet.tang.26000.json','["臨岐終日自裴回，乾我茅齋半畝苔。", "山上亂雲隨手變，淛東飛雨過江來。", "一元和氣歸中正，百怪蒼淵起蟄雷。", "千里稻花應秀色，酒樽風月醉亭臺。"]'),
('f9c874ec-1437-4b41-891b-055e4b17d08d','春遊','殷堯藩','唐','唐诗','tang','','[]','明日城東看杏花，叮嚀童子蚤將車。',64,'全唐诗/poet.tang.26000.json','["明日城東看杏花，叮嚀童子蚤將車。", "路從丹鳳樓前過，酒向金魚館裏賒。", "綠水滿溝生杜若，暖雲將雨濕泥沙。", "絕勝羊傅襄陽道，車騎西風擁鼓笳。"]'),
('19bfcf79-65ed-4366-929a-17dadd48a13c','夜酌溪樓','殷堯藩','唐','唐诗','tang','','[]','樓居溪上涼生早，坐對城頭起暮笳。',64,'全唐诗/poet.tang.26000.json','["樓居溪上涼生早，坐對城頭起暮笳。", "打鼓泊船何處客，搗衣隔竹是誰家。", "玉繩低轉宵初迥，銀燭高燒月近斜。", "得意引杯須痛飲，好懷那許負年華。"]'),
('4f8b9123-32a0-4680-af8c-5e951b48c1b2','旅行','殷堯藩','唐','唐诗','tang','','[]','煙樹寒林半有無，野人行李更蕭疎。',64,'全唐诗/poet.tang.26000.json','["煙樹寒林半有無，野人行李更蕭疎。", "堠長堠短逢官馬，山北山南聞鷓鴣。", "萬里關河成傳舍，五更風雨憶呼盧。", "寂寥一點寒燈在，酒熟隣家許夜沽。"]'),
('1fc26018-2064-4d31-a8d3-24cf504cdf2a','下第東歸作','殷堯藩','唐','唐诗','tang','','[]','十載驅馳倦荷鋤，三年生計鬢蕭疎。',64,'全唐诗/poet.tang.26000.json','["十載驅馳倦荷鋤，三年生計鬢蕭疎。", "辛勤幾逐英雄後，乙榜猶然姓氏虛。", "欲射狼星把弓箭，休將螢火讀詩書。", "身賤自慙貧骨相，朗嘯東歸學釣魚。"]'),
('c6362ff5-193b-47ff-8c28-2fe2f3bb4748','還京口','殷堯藩','唐','唐诗','tang','','[]','黃鶴山頭雪未消，行人歸計在今朝。',64,'全唐诗/poet.tang.26000.json','["黃鶴山頭雪未消，行人歸計在今朝。", "城高鐵甕江山壯，地接金陵草木彫。", "北府市樓聞舊酒，南橋官柳識歸橈。", "吏民莫見參軍面，水宿風餐鬢髮焦。"]'),
('8312baaf-e786-428b-87a9-abf170987597','襄口阻風','殷堯藩','唐','唐诗','tang','','[]','雪浪排空接海門，孤舟三日阻龍津。',64,'全唐诗/poet.tang.26000.json','["雪浪排空接海門，孤舟三日阻龍津。", "曹瞞曾墮周郎計，王導難遮庚亮塵。", "鷗散白雲沈遠浦，花飛紅雨送殘春。", "篙師整纜候明發，仍謁荒祠問鬼神。"]'),
('6f838f56-3248-4e2f-9cc1-2500f9917744','潭州獨步','殷堯藩','唐','唐诗','tang','','[]','鶴髮垂肩懶著巾，晚涼獨步楚江濱。',64,'全唐诗/poet.tang.26000.json','["鶴髮垂肩懶著巾，晚涼獨步楚江濱。", "一帆暝色鷗邊雨，數尺筇枝物外身。", "習巧未逢醫拙手，聞歌先識採蓮人。", "笑看斥鷃飛翔去，樂處蓬萊便有春。"]'),
('86837d23-eab6-4655-85d4-2eef4e834377','金陵懷古','殷堯藩','唐','唐诗','tang','','[]','黃道天清擁珮珂，東南王氣秣陵多。',64,'全唐诗/poet.tang.26000.json','["黃道天清擁珮珂，東南王氣秣陵多。", "江吞彭蠡來三蜀，地接崑崙帶九河。", "鳳闕曉霞紅散綺，龍池春水綠生波。", "華夷混一歸真主，端拱無爲樂太和。"]'),
('c8bc5926-51e9-4ce6-8a27-eb11747359e7','登鳳凰臺二首 一','殷堯藩','唐','唐诗','tang','','[]','鳳凰臺上望長安，五色宮袍照水寒。',64,'全唐诗/poet.tang.26000.json','["鳳凰臺上望長安，五色宮袍照水寒。", "綵筆十年留翰墨，銀河一夜臥闌干。", "三山飛鳥江天暮，六代離宮草樹殘。", "始信人生如一夢，壯懷莫使酒杯乾。"]'),
('471b6247-847c-4875-988a-2f4848374c88','登鳳凰臺二首 二','殷堯藩','唐','唐诗','tang','','[]','梧桐葉落秋風老，人去臺空鳳不來。',64,'全唐诗/poet.tang.26000.json','["梧桐葉落秋風老，人去臺空鳳不來。", "梁武臺成芳草合，吳王宮殿野花開。", "石頭城下春生水，燕子堂前雨長苔。", "莫問人間興廢事，百年相遇且銜杯。"]'),
('de9f8c26-1560-4366-9272-914b47f7d0f8','韓信廟','殷堯藩','唐','唐诗','tang','','[]','長空鳥盡將軍死，無復中原入馬蹄。',64,'全唐诗/poet.tang.26000.json','["長空鳥盡將軍死，無復中原入馬蹄。", "身向九泉還屬漢，功超諸將合封齊。", "荒涼古廟惟松柏，咫尺長陵又鹿麋。", "此日深憐蕭相國，竟無一語到金閨。"]'),
('50f5d5d9-4318-46dd-8db5-dd46c302ca72','訪許渾','殷堯藩','唐','唐诗','tang','','[]','去郭來尋隱者居，柳陰假步小籃輿。',64,'全唐诗/poet.tang.26000.json','["去郭來尋隱者居，柳陰假步小籃輿。", "每期會面初償約，却計論心舊得書。", "淺綠垣牆綿薜荔，淡紅池沼映芙蕖。", "爲言肯共留連飲，澗有青芹罟有魚。"]'),
('a33fc062-a8c2-4b8b-b5f0-477bfdc3beb6','李舍人席上感遇','殷堯藩','唐','唐诗','tang','','[]','微雲歛雨天氣清，松聲出樹秋泠泠。',64,'全唐诗/poet.tang.26000.json','["微雲歛雨天氣清，松聲出樹秋泠泠。", "窗戶長含碧蘿色，溪流時帶蛟龍腥。", "一官到手不可避，萬事役我徒勞形。", "飄然曳杖出門去，無數好山江上橫。"]'),
('256c5592-148e-490a-8fe7-f60b89a7b9c4','和趙相公登鸛雀樓','殷堯藩','唐','唐诗','tang','','[]','危樓高架泬寥天，上相閑登立綵旃。',64,'全唐诗/poet.tang.26000.json','["危樓高架泬寥天，上相閑登立綵旃。", "樹色到京三百里，河流歸漢幾千年。", "晴峰聳日當周道，秋穀垂花滿舜田。", "雲路何人見高志，最看西面赤闌前。"]'),
('87415ae6-c00a-4e83-a8a6-10962c744c36','冬至酬劉使君','殷堯藩','唐','唐诗','tang','','[]','異鄉冬至又今朝，回首家山入夢遙。',64,'全唐诗/poet.tang.26000.json','["異鄉冬至又今朝，回首家山入夢遙。", "漸喜一陽從地復，却憐羣沴逐冰消。", "梅含露蘂知迎臘，柳拂宮袍憶候朝。", "多少故人承宴賞，五雲堆裏聽簫韶。"]'),
('4e05996a-1b8c-4927-9b04-cc0c55a3b28e','李節度平虜詩','殷堯藩','唐','唐诗','tang','','[]','百萬王師下日邊，將軍雄略可圖全。',64,'全唐诗/poet.tang.26000.json','["百萬王師下日邊，將軍雄略可圖全。", "元勳未論封茅異，捷勢應知破竹然。", "燕警無烽清朔漠，秦文有寶進藍田。", "太平從此銷兵甲，記取紅羊換劫年。"]'),
('32518b87-8559-473b-b0b9-734549503863','金陵上李公垂侍郎','殷堯藩','唐','唐诗','tang','','["\u957f\u6c5f"]','海國微茫散曉暾，鬱葱佳氣滿乾坤。',64,'全唐诗/poet.tang.26000.json','["海國微茫散曉暾，鬱葱佳氣滿乾坤。", "六朝空據長江險，一統今歸聖代尊。", "西北諸峰連朔漠，東南衆水合崑崙。", "願從吾道禧文運，再使河清俗化淳。"]'),
('ebb080f5-34bb-42fa-b766-1151e5ab367c','贈惟儼師','殷堯藩','唐','唐诗','tang','','[]','煥然文采照青春，一策江湖自在身。',64,'全唐诗/poet.tang.26000.json','["煥然文采照青春，一策江湖自在身。", "雲鎖木龕聊息影，雪香紙襖不生塵。", "談禪早續燈無盡，護法重編論有神。", "擬掃綠陰浮佛寺，桫欏高樹結爲隣。"]'),
('239e2af4-d0c2-4a39-b0c8-3c327ad7f30f','寄許渾秀才','殷堯藩','唐','唐诗','tang','','[]','萬木驚秋葉漸稀，靜探造化見玄機。',64,'全唐诗/poet.tang.26000.json','["萬木驚秋葉漸稀，靜探造化見玄機。", "眼前誰悟先天理，去後還知今日非。", "樹擁秣陵千嶂合，雲開蕭寺一僧歸。", "漢廷累下徵賢詔，未許嚴陵老釣磯。"]'),
('14ceb01c-86b9-47dc-a51f-912013abd5c3','送白舍人渡江','殷堯藩','唐','唐诗','tang','','[]','曉發龍江第一程，諸公同濟似登瀛。',64,'全唐诗/poet.tang.26000.json','["曉發龍江第一程，諸公同濟似登瀛。", "海門日上千峰出，桃葉波平一棹輕。", "橫鎖已沈王濬筏，投鞭難阻謝玄兵。", "片時喜得東風便，回首鐘聲隔鳳城。"]'),
('3781db86-9a0f-4243-806a-63bfbd4bc927','送劉禹錫侍御出刺連州','殷堯藩','唐','唐诗','tang','','[]','遐荒迢遰五羊城，歸興濃消客裏情。',64,'全唐诗/poet.tang.26000.json','["遐荒迢遰五羊城，歸興濃消客裏情。", "家近似忘山路險，土甘殊覺瘴煙輕。", "梅花清入羅浮夢，荔子紅分廣海程。", "此去定知償隱趣，石田春雨讀書耕。"]'),
('eab25ce2-70a6-4ea4-b1a6-fb9ecfd56419','送韋侍御報使西蕃','殷堯藩','唐','唐诗','tang','','[]','歸奏聖朝行萬里，却銜天詔報蕃臣。',64,'全唐诗/poet.tang.26000.json','["歸奏聖朝行萬里，却銜天詔報蕃臣。", "本是諸生守文墨，今將匹馬靜煙塵。", "旅宿關河逢暮雨，春耕亭障識遺民。", "此去多應收故地，寧辭沙塞往來頻。"]'),
('1c215a9b-bcc9-47d8-9442-c5178ddc2158','寒食城南即事因訪藍田韋明府','殷堯藩','唐','唐诗','tang','','[]','閑出城南禁火天，路傍騎馬獨搖鞭。',64,'全唐诗/poet.tang.26000.json','["閑出城南禁火天，路傍騎馬獨搖鞭。", "青松古墓傷碑碣，紅杏春園羨管弦。", "徒說鸊鵜膏玉劒，漫誇蚨血點銅錢。", "世間盡是悠悠事，且飲韋家冷酒眠。"]'),
('3875233a-01b7-4468-a0d9-3df625ed03eb','送源中丞使新羅','殷堯藩','唐','唐诗','tang','','[]','赤墀奉命使殊方，官重霜臺紫綬光。',64,'全唐诗/poet.tang.26000.json','["赤墀奉命使殊方，官重霜臺紫綬光。", "玉節在船清海怪，金函開詔撫夷王。", "雲晴漸覺山川異，風便寧知道路長。", "誰得似君將雨露，海東萬里灑扶桑。"]'),
('e1e41cea-639f-4c69-b858-41e5b6063ceb','送景玄上人還山','殷堯藩','唐','唐诗','tang','','[]','嵩陽聽罷講經鐘，遠訪庭闈錫度空。',64,'全唐诗/poet.tang.26000.json','["嵩陽聽罷講經鐘，遠訪庭闈錫度空。", "蒲履謾從歸後織，衲衣猶記別時縫。", "地橫龍朔連沙暝，山入烏桓碧樹重。", "梵宇傳來金貝葉，花前拜捧慰親容。"]'),
('7e3186c9-6cbc-45c1-a558-767973706727','宮人入道','殷堯藩','唐','唐诗','tang','','[]','卸却宮妝錦繡衣，黃冠素服製相宜。',64,'全唐诗/poet.tang.26000.json','["卸却宮妝錦繡衣，黃冠素服製相宜。", "錫名近奉君王旨，佩籙新參老氏師。", "白晝無情趨玉陛，清宵有夢步瑤池。", "綠鬟女伴含愁別，釋盡當年妬寵私。"]'),
('7f86f129-519b-46fd-a95f-b9f1f29c352d','友人山中梅花','殷堯藩','唐','唐诗','tang','','[]','南國看花動遠情，沈郎詩苦瘦容生。',64,'全唐诗/poet.tang.26000.json','["南國看花動遠情，沈郎詩苦瘦容生。", "鐵心自儗山中賦，玉笛誰將月下橫。", "臨水一枝春占早，照人千樹雪同清。", "好風吹醒羅浮夢，莫聽空林翠羽聲。"]'),
('775398c8-b809-40aa-af2f-93746dbc82ca','客中有感','殷堯藩','唐','唐诗','tang','','[]','天地一身在，頭顱五十過。',24,'全唐诗/poet.tang.26000.json','["天地一身在，頭顱五十過。", "流年消壯志，空使淚成河。"]'),
('0454b343-4523-408c-8506-63cde404cd84','憶家二首 一','殷堯藩','唐','唐诗','tang','','[]','新霽颺林初，蘋花貼岸舒。',24,'全唐诗/poet.tang.26000.json','["新霽颺林初，蘋花貼岸舒。", "故鄉今夜月，猶得照孤廬。"]'),
('7c052c1e-110f-4411-91c0-4330065c29ff','憶家二首 二','殷堯藩','唐','唐诗','tang','','[]','樹擁溪邊閣，山浮雨後嵐。',24,'全唐诗/poet.tang.26000.json','["樹擁溪邊閣，山浮雨後嵐。", "白頭歸未得，夢裏望江南。"]'),
('1a689898-1c77-46ae-b059-bc4ca2963ec1','江行二首 一','殷堯藩','唐','唐诗','tang','','[]','暝色滄州迥，秋聲玉峽長。',24,'全唐诗/poet.tang.26000.json','["暝色滄州迥，秋聲玉峽長。", "只因江上月，不覺過潯陽。"]'),
('381f5d55-87b3-41c8-9ce1-a9b3f745d50a','江行二首 二','殷堯藩','唐','唐诗','tang','','["\u957f\u6c5f"]','晚泊長江口，寒沙白似霜。',24,'全唐诗/poet.tang.26000.json','["晚泊長江口，寒沙白似霜。", "年光流不盡，東去水聲長。"]'),
('c525574a-b5a7-478f-af9b-4c1869a81dd5','偶題','殷堯藩','唐','唐诗','tang','','[]','越女收龍眼，蠻兒拾象牙。',24,'全唐诗/poet.tang.26000.json','["越女收龍眼，蠻兒拾象牙。", "長安千萬里，走馬送誰家。"]'),
('002f4e51-2332-4f16-a5c9-31bad79b8f16','關中傷亂後','殷堯藩','唐','唐诗','tang','','[]','去歲干戈險，今年蝗旱憂。',24,'全唐诗/poet.tang.26000.json','["去歲干戈險，今年蝗旱憂。", "關西歸戰馬，海內賣耕牛。"]'),
('80596e47-dd8a-4e79-b9c0-cafb5e26a857','楚江懷古','殷堯藩','唐','唐诗','tang','','[]','騷靈不可見，楚些竟誰聞。',24,'全唐诗/poet.tang.26000.json','["騷靈不可見，楚些竟誰聞。", "欲采蘋花去，滄州隔暮雲。"]'),
('2cd4650e-1f41-413e-8611-027882561915','張飛廟','殷堯藩','唐','唐诗','tang','','[]','威名垂萬古，勇力冠當時。',24,'全唐诗/poet.tang.26000.json','["威名垂萬古，勇力冠當時。", "回首三分國，何人賦黍離。"]'),
('1f4c4d35-c226-42e3-960e-581851f93f53','生公講臺','殷堯藩','唐','唐诗','tang','','[]','暝色護樓臺，陰雲晝未開。',24,'全唐诗/poet.tang.26000.json','["暝色護樓臺，陰雲晝未開。", "一塵無處著，花雨遍蒼苔。"]'),
('fb247193-1b85-41c1-8acd-1385d918b8a5','席上聽琴','殷堯藩','唐','唐诗','tang','','[]','高堂流月明，萬籟不到耳。',24,'全唐诗/poet.tang.26000.json','["高堂流月明，萬籟不到耳。", "一聽清心魂，飛絮春紛起。"]'),
('1fad6962-b685-4393-87bb-b3abec93f17f','酬雍秀才二首 一','殷堯藩','唐','唐诗','tang','','[]','晚市人煙合，歸帆帶夕陽。',24,'全唐诗/poet.tang.26000.json','["晚市人煙合，歸帆帶夕陽。", "棲遲未歸客，猶著錦衣裳。"]'),
('cac427db-6703-4f85-b134-b306273c6a50','酬雍秀才二首 二','殷堯藩','唐','唐诗','tang','','[]','臥病茅窗下，驚聞兩月過。',24,'全唐诗/poet.tang.26000.json','["臥病茅窗下，驚聞兩月過。", "興來聊賦詠，清婉逼陰何。"]'),
('0d740990-b897-4b98-b836-800bb0831c42','竹','殷堯藩','唐','唐诗','tang','','[]','窗戶盡蕭森，空堦凝碧陰。',24,'全唐诗/poet.tang.26000.json','["窗戶盡蕭森，空堦凝碧陰。", "不緣冰雪裏，爲識歲寒心。"]'),
('0dacd468-9b4c-4962-8581-9ffc1c03e009','春怨','殷堯藩','唐','唐诗','tang','','[]','柳花撲簾春欲盡，綠陰障林鶯亂啼。',32,'全唐诗/poet.tang.26000.json','["柳花撲簾春欲盡，綠陰障林鶯亂啼。", "秖愁明日送春去，落日滿園啼竹雞。"]'),
('01561bdb-edd8-42be-9c9c-e9cc215c4419','館娃宮','殷堯藩','唐','唐诗','tang','','[]','宮女三千去不回，真珠翠羽是塵埃。',32,'全唐诗/poet.tang.26000.json','["宮女三千去不回，真珠翠羽是塵埃。", "夫差舊國久破碎，紅燕自歸花自開。"]'),
('f9c60eea-df9b-4e43-ad73-efd9995488fc','漢宮詞三首 一','殷堯藩','唐','唐诗','tang','','[]','成帝夫人淚滿懷，璧宮相趁落空堦。',32,'全唐诗/poet.tang.26000.json','["成帝夫人淚滿懷，璧宮相趁落空堦。", "可憐玉貌花前死，惟有君恩白燕釵。"]'),
('3381f3b8-d80d-4a5a-80c4-46cddb27b1dd','漢宮詞三首 二','殷堯藩','唐','唐诗','tang','','[]','霍家有女字成君，年少教人著繡裙。',32,'全唐诗/poet.tang.26000.json','["霍家有女字成君，年少教人著繡裙。", "枉殺宮中許皇后，椒房恩澤是浮雲。"]'),
('2fb16db8-4174-4bee-8fd6-edd40ac8b14d','漢宮詞三首 三','殷堯藩','唐','唐诗','tang','','[]','駿馬金鞍白玉鞭，宮中來取李延年。',32,'全唐诗/poet.tang.26000.json','["駿馬金鞍白玉鞭，宮中來取李延年。", "承恩直日鴛鴦殿，一曲清歌在九天。"]'),
('f8071036-9e39-49c2-b3e9-09fdeb4a5f82','同州端午','殷堯藩','唐','唐诗','tang','','["\u5f52\u4e61", "\u7aef\u5348\u8282"]','鶴髮垂肩尺許長，離家三十五端陽。',32,'全唐诗/poet.tang.26000.json','["鶴髮垂肩尺許長，離家三十五端陽。", "兒童見說深驚訝，却問何方是故鄉。"]'),
('0a511791-268e-4e61-975c-6fbd0018a8da','夜過洞庭','殷堯藩','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','笙歌只解鬧花天，誰是敲冰掉小船。',32,'全唐诗/poet.tang.26000.json','["笙歌只解鬧花天，誰是敲冰掉小船。", "爲覓瀟湘幽隱處，夜深載月聽鳴泉。"]'),
('7ddfd5c3-0a0f-4d2f-b92d-413946b29a6e','遊山南寺二首 一','殷堯藩','唐','唐诗','tang','','[]','山中盡日無人到，竹外交加百鳥鳴。',32,'全唐诗/poet.tang.26000.json','["山中盡日無人到，竹外交加百鳥鳴。", "昨日小樓微雨過，櫻桃花落晚風晴。"]'),
('2e2f6b41-9470-41a3-8a03-ca77b668bc49','遊山南寺二首 二','殷堯藩','唐','唐诗','tang','','[]','踏碎羊山黃葉堆，天飛細雨隱輕雷。',32,'全唐诗/poet.tang.26000.json','["踏碎羊山黃葉堆，天飛細雨隱輕雷。", "朗陵莫訝來何晚，不忍聽君話別杯。"]'),
('df22a14d-cb97-4ce9-a855-630f5d40587e','寄太僕田卿二首 一','殷堯藩','唐','唐诗','tang','','[]','客窗強飲太怱怱，急雨寒風意萬重。',32,'全唐诗/poet.tang.26000.json','["客窗強飲太怱怱，急雨寒風意萬重。", "驀上心來消未得，夢回又聽五更鐘。"]'),
('e8b764f6-a1f0-46d5-95ef-5324058f3ea0','寄太僕田卿二首 二','殷堯藩','唐','唐诗','tang','','[]','一陽纔動伏羣陰，萬物於今寓太音。',32,'全唐诗/poet.tang.26000.json','["一陽纔動伏羣陰，萬物於今寓太音。", "若喜長生添線日，微微消息識天心。"]'),
('ab287f91-8d9a-4355-8b08-513aa7b8a224','新昌井','殷堯藩','唐','唐诗','tang','','[]','轆轤千轉勞筋力，待得甘泉渴殺人。',32,'全唐诗/poet.tang.26000.json','["轆轤千轉勞筋力，待得甘泉渴殺人。", "且共山麋同飲澗，玉沙鋪底淺磷磷。"]'),
('3e59b6cc-23aa-42d8-9810-b1f74e1846c9','經靖安里','殷堯藩','唐','唐诗','tang','','[]','巷底蕭蕭絕市塵，供愁疎雨打黃昏。',32,'全唐诗/poet.tang.26000.json','["巷底蕭蕭絕市塵，供愁疎雨打黃昏。", "悠然一曲泉明調，淺立閑愁輕閉門。"]'),
('ba6f5f80-7fcd-4488-b72d-37569e593656','聞箏歌','殷堯藩','唐','唐诗','tang','','[]','淒淒切切斷腸聲，指滑音柔萬種情。',32,'全唐诗/poet.tang.26000.json','["淒淒切切斷腸聲，指滑音柔萬種情。", "花影深沈遮不住，度幃穿幕又殘更。"]'),
('1c2a94d9-f6a0-42c2-b6c7-62c04121ab64','吹笙歌','殷堯藩','唐','唐诗','tang','','[]','伶兒竹聲愁繞空，秦女淚濕燕支紅。',32,'全唐诗/poet.tang.26000.json','["伶兒竹聲愁繞空，秦女淚濕燕支紅。", "玉桃花片落不住，三十六簧能喚風。"]'),
('4ee121fc-5a0a-4690-9d6c-f6386c58d982','贈歌人郭婉二首 一','殷堯藩','唐','唐诗','tang','','[]','石家金谷舊歌人，起唱花筵淚滿巾。',32,'全唐诗/poet.tang.26000.json','["石家金谷舊歌人，起唱花筵淚滿巾。", "紅粉少年諸弟子，一時惆悵望梁塵。"]'),
('0a0ac822-812d-4ea3-9eb7-b0c1021ff1a3','贈歌人郭婉二首 二','殷堯藩','唐','唐诗','tang','','[]','雲滿衣裳月滿身，輕盈歸步過流塵。',32,'全唐诗/poet.tang.26000.json','["雲滿衣裳月滿身，輕盈歸步過流塵。", "五更無限留連意，常恐風花又一春。"]'),
('eead6632-0c59-47e5-b39a-47673ee0324a','潭州席上贈舞柘枝妓','殷堯藩','唐','唐诗','tang','','[]','姑蘇太守青娥女，流落長沙舞柘枝。',32,'全唐诗/poet.tang.26000.json','["姑蘇太守青娥女，流落長沙舞柘枝。", "坐滿繡衣皆不識，可憐紅臉淚雙垂。"]'),
('d3078d4c-c0da-4965-8905-ca0669c558ce','句','殷堯藩','唐','唐诗','tang','','[]','瘴雨出虹蝀，蠻煙渡江急。',24,'全唐诗/poet.tang.26000.json','["瘴雨出虹蝀，蠻煙渡江急。", "嘗聞島夷俗，犀象滿城邑。"]'),
('84a2014c-1579-4128-a861-1e9e1e71b22d','虎丘山真娘墓','沈亞之','唐','唐诗','tang','','[]','金釵淪劒壑，茲地似花臺。',48,'全唐诗/poet.tang.26000.json','["金釵淪劒壑，茲地似花臺。", "油壁何人值，錢塘度曲哀。", "翠餘長染柳，香重欲薰梅。", "但道行雲去，應隨魂夢來。"]'),
('e325f400-746a-4c84-9654-14b1bb2c290d','荅殷堯藩贈罷涇源記室','沈亞之','唐','唐诗','tang','','[]','勞君輟雅話，聽說事疆場。',48,'全唐诗/poet.tang.26000.json','["勞君輟雅話，聽說事疆場。", "提筆從征虜，飛書始伏羌。", "河流辭馬嶺，節臥聽龍驤。", "孤負平生劒，空憐射斗光。"]'),
('db4b846a-707e-4763-85f7-44a3381003f2','五月六日發石頭城步望前船示舍弟兼寄侯郎','沈亞之','唐','唐诗','tang','','[]','客子去淮陽，逶迤別夢長。',72,'全唐诗/poet.tang.26000.json','["客子去淮陽，逶迤別夢長。", "水關開夜鎖，霧櫂起晨涼。", "煙月期同賞，風波勿異行。", "隱山曾撼櫓，轉瀨指遙檣。", "蒲葉吳刀綠，筠筒楚粽香。", "因書報惠遠，爲我憶檀郎。"]'),
('fde43d6e-40e5-4cd0-93a5-950a9ca07500','別龐子肅','沈亞之','唐','唐诗','tang','','[]','自爲應仙才，丹砂鍊幾迴。',48,'全唐诗/poet.tang.26000.json','["自爲應仙才，丹砂鍊幾迴。", "山秋夢桂樹，月曉憶瑤臺。", "雨雪依巖避，煙雲逐步開。", "今朝龍杖去，早晚鶴書來。"]'),
('dfaf01bf-3c20-4c9a-94ca-574eeaac03c2','春色滿皇州','沈亞之','唐','唐诗','tang','','[]','何處春輝好，偏宜在雍州。',72,'全唐诗/poet.tang.26000.json','["何處春輝好，偏宜在雍州。", "花明夾城道，柳暗曲江頭。", "風軟遊絲重，光融瑞氣浮。", "鬬雞憐短草，乳燕傍高樓。", "繡轂盈香陌，新泉溢御溝。", "迴看日欲暮，還騎似川流。"]'),
('650d0c88-6efb-437f-ae8a-1760ce4e0f4e','宿白馬津寄寇立','沈亞之','唐','唐诗','tang','','[]','客思聽蛩嗟，秋懷似亂砂。',48,'全唐诗/poet.tang.26000.json','["客思聽蛩嗟，秋懷似亂砂。", "劒頭懸日影，蠅鼻落燈花。", "天外歸鴻斷，漳南別路賒。", "聞君同旅舍，幾得夢還家。"]'),
('05ca18f0-dded-445e-9f54-31fe745c75e3','汴州船行賦岸傍所見','沈亞之','唐','唐诗','tang','','[]','古木曉蒼蒼，秋林拂岸香。',72,'全唐诗/poet.tang.26000.json','["古木曉蒼蒼，秋林拂岸香。", "露珠蟲網細，金縷兔絲長。", "秋浪時迴沫，驚鱗乍觸航。", "蓬煙拈綠線，棘實綴紅囊。", "亂穗搖鼯尾，出根挂鳳腸。", "聊持一濯足，誰道比滄浪。"]'),
('49d072a1-20bb-4f77-9899-55d219490663','送文頴上人遊天台','沈亞之','唐','唐诗','tang','','[]','露花浮翠瓦，鮮思起芳叢。',48,'全唐诗/poet.tang.26000.json','["露花浮翠瓦，鮮思起芳叢。", "此際斷客夢，況復別志公。", "既歷天台去，言過赤城東。", "莫說人間事，崎嶇塵土中。"]'),
('9216bb62-c647-414c-bf80-eee0eea40f30','宿後自華陽行次昭應寄王直方','沈亞之','唐','唐诗','tang','','[]','重歸能幾日，物意早如春。',48,'全唐诗/poet.tang.26000.json','["重歸能幾日，物意早如春。", "暖色先驪岫，寒聲別鴈羣。", "川光如戲劒，帆態似翔雲。", "爲報東園蝶，南枝日已曛。"]'),
('cd21ad3c-e08e-4569-9978-078b6e38a4e4','題海榴樹呈八叔大人','沈亞之','唐','唐诗','tang','','[]','曾在蓬壺伴衆仙，文章枝葉五雲邊。',64,'全唐诗/poet.tang.26000.json','["曾在蓬壺伴衆仙，文章枝葉五雲邊。", "幾時奉宴瑤臺下，何日移榮玉砌前。", "染日裁霞深雨露，凌寒送暖占風煙。", "應笑強如河畔柳，逢波逐浪送張騫。"]'),
('dcdabc46-057b-4cd1-9af9-748ffa6901e3','西蕃請謁廟','沈亞之','唐','唐诗','tang','','[]','肅肅層城裏，巍巍祖廟清。',96,'全唐诗/poet.tang.26000.json','["肅肅層城裏，巍巍祖廟清。", "聖恩覃布濩，異域獻精誠。", "冠蓋分行列，戎夷辨姓名。", "禮終齊百拜，心潔表忠貞。", "瑞氣千重色，簫韶九奏聲。", "杖移迎日轉，旌動逐風輕。", "休運威儀正，年推俎豆盈。", "不才慙聖澤，空此望華纓。"]'),
('5c0a653f-3704-4ce0-a33f-1848559fe425','勸政樓下觀百官獻壽','沈亞之','唐','唐诗','tang','','[]','御氣黃花節，臨軒紫陌頭。',72,'全唐诗/poet.tang.26000.json','["御氣黃花節，臨軒紫陌頭。", "早陽生彩杖，霽色入仙樓。", "獻壽皆鴛鷺，瞻天在冕旒。", "菊尊開九日，鳳曆啓千秋。", "樂闋祥煙起，杯酣瑞影收。", "年年歌舞夕，此地慶皇休。"]'),
('87aac1f6-ef12-4e11-a777-2119b06112bb','山出雲','沈亞之','唐','唐诗','tang','','[]','片雲朝出岫，孤色逈難親。',72,'全唐诗/poet.tang.26000.json','["片雲朝出岫，孤色逈難親。", "蓋小辭山早，根輕觸石新。", "飄揚經綠野，明麗照青春。", "拂樹疑舒葉，臨江似結鱗。", "從龍方有感，捧日豈無因。", "看助爲霖去，恩沾雨露均。"]'),
('780b5267-9b33-47e2-8953-d4a07a4eac9d','曲江亭望慈恩杏花發','沈亞之','唐','唐诗','tang','','[]','曲臺晴好望，近接梵王家。',72,'全唐诗/poet.tang.26000.json','["曲臺晴好望，近接梵王家。", "十畝開金地，千株發杏花。", "帶雲猶誤雪，映日欲欺霞。", "紫陌傳香遠，紅泉落影斜。", "園中春尚早，亭上路非賒。", "芳景偏堪賞，其如積歲華。"]'),
('c63fe1ca-1982-47e2-881a-c9c5fb68ecfa','村居','沈亞之','唐','唐诗','tang','','[]','有樹巢宿鳥，無酒共客醉。',60,'全唐诗/poet.tang.26000.json','["有樹巢宿鳥，無酒共客醉。", "月上蟬韻殘，梧桐陰繞地。", "獨出村舍門，吟劇微風起。", "蕭蕭蘆荻叢，呌嘯如山鬼。", "應緣我憔悴，爲我哭秋思。"]'),
('32795c3d-dbfe-4b37-9a5d-327883b3eac7','春詞酬元微之','沈亞之','唐','唐诗','tang','','[]','黃鶯啼時春日高，紅芳發盡井邊桃。',32,'全唐诗/poet.tang.26000.json','["黃鶯啼時春日高，紅芳發盡井邊桃。", "美人手暖裁衣易，片片輕花落翦刀。"]'),
('516f9d8c-997b-403c-9281-092858b4c05e','題侯仙亭','沈亞之','唐','唐诗','tang','','[]','新創仙亭覆石壇，雕梁峻宇入雲端。',32,'全唐诗/poet.tang.26000.json','["新創仙亭覆石壇，雕梁峻宇入雲端。", "嶺北嘯猨高枕聽，湖南山色捲簾看。"]'),
('0224c269-eaff-42a2-8789-4152a70430ab','送龐子肅','沈亞之','唐','唐诗','tang','','[]','三年遊宦也迷津，馬困長安九陌塵。',32,'全唐诗/poet.tang.26000.json','["三年遊宦也迷津，馬困長安九陌塵。", "都作無成不歸去，古來妻嫂笑蘇秦。"]'),
('f3c21860-e614-4699-9549-69b46e8acb1d','夢輓秦弄玉','沈亞之','唐','唐诗','tang','','[]','泣葬一枝紅，生同死不同。',48,'全唐诗/poet.tang.26000.json','["泣葬一枝紅，生同死不同。", "金鈿墜芳草，香繡滿春風。", "舊日聞簫處，高樓當月中。", "梨花寒食夜，深閉翠微宮。"]'),
('d8dafcdd-c993-4203-8a5d-77e4941774a0','夢別秦穆公','沈亞之','唐','唐诗','tang','','[]','擊髆舞，恨滿煙光無處所。',56,'全唐诗/poet.tang.26000.json','["擊髆舞，恨滿煙光無處所。", "淚如雨，欲擬著辭不成語。", "金鳳銜紅舊繡衣，幾度宮中同看舞。", "人間春日正歡樂，日暮東風何處去。"]'),
('bb4b17bd-bee6-4503-989e-4a96f8c6260e','夢游秦宮','沈亞之','唐','唐诗','tang','','[]','君王多感放東歸，從此秦宮不復期。',32,'全唐诗/poet.tang.26000.json','["君王多感放東歸，從此秦宮不復期。", "春景似傷秦喪主，落花如雨淚臙脂。"]'),
('2bf57231-7c6d-4b4d-a256-a6cf28ce176e','湘中怨 一','沈亞之','唐','唐诗','tang','','[]','隆佳秀兮昭盛時，播薰綠兮淑華歸。',104,'全唐诗/poet.tang.26000.json','["隆佳秀兮昭盛時，播薰綠兮淑華歸。", "顧室荑與處蕚兮，潛重房以飾姿。", "見稚態之韶羞兮，蒙長靄以爲幃。", "醉融光兮渺渺瀰瀰，迷千里兮涵煙眉。", "晨陶陶兮暮熙熙，舞婑那之穠條兮。", "騁盈盈以披遲，酡遊顏兮倡蔓卉縠，流蒨霓兮石髮髓旎。"]'),
('8c413c74-6169-407f-b440-0854cd6890c5','湘中怨 二','沈亞之','唐','唐诗','tang','','[]','泝青山兮江之隅，拖湘波兮褭綠裾。',33,'全唐诗/poet.tang.26000.json','["泝青山兮江之隅，拖湘波兮褭綠裾。", "荷拳拳兮未舒，匪同歸兮將焉[如]。"]'),
('bbd2b95f-739c-4e2b-85f7-df48c2512abb','文祝延二闋 一','沈亞之','唐','唐诗','tang','','[]','閩山之杭杭兮水堋堋，吞荒抱大兮香疊層。',172,'全唐诗/poet.tang.26000.json','["閩山之杭杭兮水堋堋，吞荒抱大兮香疊層。", "騰氣清渾兮朝昏，神生其中兮宅幽凝。", "居如山兮惠如水，處端卓兮赴下而忘鄙。", "集人之祈兮從人之所市，攀清明兮叩髣髴。", "我民清兮期吉日，願聽誠兮陳所當。", "侯臨我兮恩如光，照導兮天覆。", "惠流吾兮樂且康，恭聞侯兮飲食失常。", "民縈憂兮心苦瘡，飽我之飢兮侯由有穀。", "神有澤兮宜蔭沃，脫侯之恙兮歸侯之多福。", "羣卑勤之恭潔兮，鑒貞盟乎山竹。"]'),
('9c898cc5-2525-44f3-85e5-e020c8a8d1d1','文祝延二闋 二','沈亞之','唐','唐诗','tang','','[]','兕載吹兮音咿咿，銅鐃呶兮睋呼𪾤睢。',182,'全唐诗/poet.tang.26000.json','["兕載吹兮音咿咿，銅鐃呶兮睋呼𪾤睢。", "樟之蓋兮麓下，雲垂幄兮爲帷。", "合吾民兮將安，維吾侯之康兮樂欣。", "肴盤列兮荅神，神擺漁篁兮降拂窣窣。", "右持妓兮左夫人，態修邃兮佻眇。", "調丹含瓊兮瑳佳笑，馨炮羶燔兮溢按豆。", "爵盎無虛兮菓摭雜佑，秋雲清醉兮流融光。", "巫裾旋兮覡袖翔，瞪虛凝兮覽迴楊。", "語神歡兮酒云央，望吾侯兮遵賞事。", "朝馬駕兮搦寶轡，千弭函弦兮森道騎。", "吾何樂兮神軒，維侯之康兮居遊自遂。"]'),
('a4d460d8-1940-4341-b6d1-940c237ced93','及第後過楊子江','施肩吾','唐','唐诗','tang','','[]','憶昔將貢年，抱愁此江邊。',48,'全唐诗/poet.tang.26000.json','["憶昔將貢年，抱愁此江邊。", "魚龍互閃爍，黑浪高於天。", "今日步春草，復來經此道。", "江神也世情，爲我風色好。"]'),
('03d691a1-9b4f-47c7-aa64-a077286be739','夜宴曲','施肩吾','唐','唐诗','tang','','[]','蘭缸如晝曉不眠，玉堂夜起沈香煙。',64,'全唐诗/poet.tang.26000.json','["蘭缸如晝曉不眠，玉堂夜起沈香煙。", "青娥一行十二仙，欲笑不笑桃花然。", "碧窗弄嬌梳洗晚，戶外不知銀漢轉。", "被郎嗔罰琉璃盞，酒入四肢紅玉軟。"]'),
('fa873d9a-0890-47da-a8a6-b6da4f0dbb77','効古興','施肩吾','唐','唐诗','tang','','[]','金雀無舊釵，緗綺無舊裾。',72,'全唐诗/poet.tang.26000.json','["金雀無舊釵，緗綺無舊裾。", "唯有一寸心，長貯萬里夫。", "南軒夜蟲織已促，北牖飛蛾遶殘燭。", "祗言衆口鑠千金，誰信獨愁銷片玉。", "不知歲晚歸不歸，又將啼眼縫征衣。"]'),
('50b73dfc-f141-4899-b752-46d1dde2536a','古別離二首 一','施肩吾','唐','唐诗','tang','','[]','古人謾歌西飛燕，十年不見狂夫面。',48,'全唐诗/poet.tang.26000.json','["古人謾歌西飛燕，十年不見狂夫面。", "三更風作切夢刀，萬轉愁成繫腸線。", "所嗟不及牛女星，一年一度得相見。"]'),
('10f9c5fb-c4fe-4af6-9023-bca86df5119f','古別離二首 二','施肩吾','唐','唐诗','tang','','[]','老母別愛子，少妻送征郎。',52,'全唐诗/poet.tang.26000.json','["老母別愛子，少妻送征郎。", "血流既四面，乃一斷二腸。", "不愁寒無衣，不怕飢無糧。", "惟恐征戰不還鄉，母化爲鬼妻爲孀。"]'),
('25c9d1df-051a-4878-9f6f-e77151950e68','壯士行','施肩吾','唐','唐诗','tang','','[]','一斗之膽撐臟腑，如磥之筋礙臂骨。',64,'全唐诗/poet.tang.26000.json','["一斗之膽撐臟腑，如磥之筋礙臂骨。", "有時悞入千人叢，自覺一身橫突兀。", "當今四海無煙塵，胸襟被壓不得伸。", "凍梟殘蠆我不取，汚我匣裏青蛇鱗。"]'),
('bb65e630-133d-478a-9ce0-c1cd1656d5b9','代征婦怨','施肩吾','唐','唐诗','tang','','[]','寒窗羞見影相隨，嫁得五陵輕薄兒。',64,'全唐诗/poet.tang.26000.json','["寒窗羞見影相隨，嫁得五陵輕薄兒。", "長短豔歌君自解，淺深更漏妾偏知。", "畫裙多淚鴛鴦濕，雲鬢慵梳玳瑁垂。", "何事不看霜雪裏，堅貞惟有古松枝。"]'),
('07fd45cc-d54e-4eb4-8b5d-1a43c306bcf0','送人南游','施肩吾','唐','唐诗','tang','','[]','見說南行偏不易，中途莫忘寄書頻。',64,'全唐诗/poet.tang.26000.json','["見說南行偏不易，中途莫忘寄書頻。", "凌空瘴氣墮飛鳥，解語山魈惱病人。", "閩縣綠娥能引客，泉州烏藥好防身。", "異花奇竹分明看，待汝歸來畫取真。"]'),
('2cda90ee-803a-48a2-adf8-4b826ff2f4c8','贈邊將','施肩吾','唐','唐诗','tang','','[]','輕生奉國不爲難，戰苦身多舊箭瘢。',64,'全唐诗/poet.tang.26000.json','["輕生奉國不爲難，戰苦身多舊箭瘢。", "玉匣鎖龍鱗甲冷，金鈴襯鶻羽毛寒。", "皂貂擁出花當背，白馬騎來月在鞍。", "猶恐犬戎臨虜塞，柳營時把陣圖看。"]'),
('43a3fdd9-6088-46cc-a9b2-d226237da33b','上禮部侍郎陳情','施肩吾','唐','唐诗','tang','','[]','九重城裏無親識，八百人中獨姓施。',64,'全唐诗/poet.tang.26000.json','["九重城裏無親識，八百人中獨姓施。", "弱羽飛時攢箭險，蹇驢行處薄冰危。", "晴天欲照盆難反，貧女如花鏡不知。", "却向從來受恩地，再求青律變寒枝。"]'),
('a18ef835-add7-499e-948a-25d274acfc09','早春殘雪','施肩吾','唐','唐诗','tang','','[]','春景照林巒，玲瓏雪影殘。',72,'全唐诗/poet.tang.26000.json','["春景照林巒，玲瓏雪影殘。", "井泉添碧甃，藥圃洗朱欄。", "雲路迷初醒，書堂映漸難。", "花分梅嶺色，塵減玉堦寒。", "遠稱棲松鶴，高宜點露盤。", "佇逢春律後，陰谷始堪看。"]'),
('6b7ea783-df07-4491-a048-cb315598a41e','送端上人遊天台','施肩吾','唐','唐诗','tang','','[]','師今欲向天台去，來說天台意最真。',64,'全唐诗/poet.tang.26000.json','["師今欲向天台去，來說天台意最真。", "溪過石橋爲險處，路逢毛褐是真人。", "雲邊望字鐘聲遠，雪裏尋僧脚跡新。", "只可且論經夏別，莫教琪樹兩迴春。"]'),
('bf6a4672-d840-468f-9a39-c6074c3094ce','惜花','施肩吾','唐','唐诗','tang','','[]','落盡萬株紅，無人解繫風。',24,'全唐诗/poet.tang.26000.json','["落盡萬株紅，無人解繫風。", "今朝芳徑裏，惆悵錦機空。"]'),
('b94cb12f-0b0d-4fc0-8fbe-1458502c32a0','衝夜行','施肩吾','唐','唐诗','tang','','[]','夜行無月時，古路多荒榛。',24,'全唐诗/poet.tang.26000.json','["夜行無月時，古路多荒榛。", "山鬼搖把火，自照不照人。"]'),
('06e97218-844f-4719-907e-57e2a55d5aa6','夜愁曲','施肩吾','唐','唐诗','tang','','[]','歌者歌未絕，愁人愁轉增。',24,'全唐诗/poet.tang.26000.json','["歌者歌未絕，愁人愁轉增。", "空把琅玕枝，強挑無心燈。"]'),
('7c1915c7-8b5b-46f5-8710-ee7a6da1c1b7','雜古詞五首 一','施肩吾','唐','唐诗','tang','','[]','可憐江北女，慣唱江南曲。',24,'全唐诗/poet.tang.26000.json','["可憐江北女，慣唱江南曲。", "搖蕩木蘭舟，雙鳧不成浴。"]'),
('574da8ad-4a82-4a46-979c-849faf124cbb','雜古詞五首 二','施肩吾','唐','唐诗','tang','','[]','郎爲七上香，妾作籠下灰。',24,'全唐诗/poet.tang.26000.json','["郎爲七上香，妾作籠下灰。", "歸時即暖熱，去罷生塵埃。"]'),
('b5efef32-c2b2-4e04-a413-95485b6c431b','雜古詞五首 三','施肩吾','唐','唐诗','tang','','[]','夜裁鴛鴦綺，朝織蒲桃綾。',24,'全唐诗/poet.tang.26000.json','["夜裁鴛鴦綺，朝織蒲桃綾。", "欲試一寸心，待縫三尺冰。"]'),
('93ab529b-04dc-4bde-8594-e3b05c8e16c1','雜古詞五首 四','施肩吾','唐','唐诗','tang','','[]','憐時魚得水，怨罷商與參。',24,'全唐诗/poet.tang.26000.json','["憐時魚得水，怨罷商與參。", "不如山梔子，却能結同心。"]'),
('3e73002f-e2fe-4790-b453-106b76df2c44','雜古詞五首 五','施肩吾','唐','唐诗','tang','','[]','紅顏感暮花，白日同流水。',24,'全唐诗/poet.tang.26000.json','["紅顏感暮花，白日同流水。", "思君若孤燈，一夜一心死。"]'),
('0b81abc2-fe08-4d17-818a-8ff93547eb9a','幼女詞','施肩吾','唐','唐诗','tang','','["\u513f\u7ae5"]','幼女纔六歲，未知巧與拙。',24,'全唐诗/poet.tang.26000.json','["幼女纔六歲，未知巧與拙。", "向夜在堂前，學人拜新月。"]'),
('82e9313e-2ceb-49ae-8a95-e73b15b55cb8','買地詞','施肩吾','唐','唐诗','tang','','[]','買地不惜錢，爲多芳桂叢。',24,'全唐诗/poet.tang.26000.json','["買地不惜錢，爲多芳桂叢。", "所期在清涼，坐起聞香風。"]'),
('a32175d3-ae78-4240-bf42-94a9eb6f194c','弋陽訪古','施肩吾','唐','唐诗','tang','','[]','行逢葛溪水，不見葛仙人。',24,'全唐诗/poet.tang.26000.json','["行逢葛溪水，不見葛仙人。", "空拋青竹杖，呪作葛陂神。"]'),
('ca607987-8ab9-464f-8802-c5e45bb12ca6','幽居樂','施肩吾','唐','唐诗','tang','','[]','萬籟不在耳，寂寥心境清。',24,'全唐诗/poet.tang.26000.json','["萬籟不在耳，寂寥心境清。", "無妨數莖竹，時有蕭蕭聲。"]'),
('b27b92fa-23c2-4095-80a3-c43fd4e1ac26','湘川懷古','施肩吾','唐','唐诗','tang','','[]','湘水終日流，湘妃昔時哭。',24,'全唐诗/poet.tang.26000.json','["湘水終日流，湘妃昔時哭。", "美色已成塵，淚痕猶在竹。"]'),
('f72daa63-bddf-4ceb-9823-8e472db73c97','秋山吟','施肩吾','唐','唐诗','tang','','[]','夜吟秋山上，褭褭秋風歸。',26,'全唐诗/poet.tang.26000.json','["夜吟秋山上，褭褭秋風歸。", "月色清且[冷]，桂香落人衣。"]'),
('69f9b53d-4092-409e-955c-63bd684463a3','寒夜','施肩吾','唐','唐诗','tang','','[]','三復招隱吟，不知寒夜深。',24,'全唐诗/poet.tang.26000.json','["三復招隱吟，不知寒夜深。", "看看西來月，移到青天心。"]'),
('d650b17b-c1ad-47f9-a8f6-f6cfea468dc9','湘竹詞','施肩吾','唐','唐诗','tang','','[]','萬古湘江竹，無窮奈怨何。',24,'全唐诗/poet.tang.26000.json','["萬古湘江竹，無窮奈怨何。", "年年長春筍，只是淚痕多。"]'),
('8769cb35-f928-49b7-a338-1d2d4e8af7b7','觀花後遊慈恩寺','施肩吾','唐','唐诗','tang','','[]','世事知難了，應須問苦空。',24,'全唐诗/poet.tang.26000.json','["世事知難了，應須問苦空。", "羞將看花眼，來入梵王宮。"]'),
('fb027138-9930-4848-a754-5ed841537d32','乞巧詞','施肩吾','唐','唐诗','tang','','[]','乞巧望星河，雙雙並綺羅。',24,'全唐诗/poet.tang.26000.json','["乞巧望星河，雙雙並綺羅。", "不嫌針眼小，只道月明多。"]'),
('9cb6b7e3-eb7f-4d48-8022-3d0eb6798383','不見來詞','施肩吾','唐','唐诗','tang','','[]','烏鵲語千回，黃昏不見來。',24,'全唐诗/poet.tang.26000.json','["烏鵲語千回，黃昏不見來。", "漫教脂粉匣，閉了又重開。"]'),
('411635e8-0f39-4272-a8ba-a50845cc7b97','夜起來','施肩吾','唐','唐诗','tang','','[]','香銷連理帶，塵覆合歡桮。',24,'全唐诗/poet.tang.26000.json','["香銷連理帶，塵覆合歡桮。", "嬾臥相思枕，愁吟夜起來。"]'),
('a6ff59ae-f01a-4eaa-851a-f73d69decb54','笑卿卿詞','施肩吾','唐','唐诗','tang','','[]','笑向卿卿道，躭書夜夜多。',24,'全唐诗/poet.tang.26000.json','["笑向卿卿道，躭書夜夜多。", "出來看玉兔，又欲過銀河。"]'),
('9b2fe41e-b5a8-4f28-80e9-83d78ca8d522','感遇詞','施肩吾','唐','唐诗','tang','','[]','一種貌如仙，人情要自偏。',24,'全唐诗/poet.tang.26000.json','["一種貌如仙，人情要自偏。", "羅敷有底好，最得使君憐。"]'),
('b3474f68-a050-48cf-8d0d-a4f73309ec2c','及第後夜訪月仙子','施肩吾','唐','唐诗','tang','','[]','自喜尋幽夜，新當及第年。',24,'全唐诗/poet.tang.26000.json','["自喜尋幽夜，新當及第年。", "還將天上桂，來訪月中仙。"]'),
('b430204b-04b7-4d63-90ac-898f9fefa341','定情樂 一','施肩吾','唐','唐诗','tang','','[]','敢嗟君不憐，自是命不諧。',24,'全唐诗/poet.tang.26000.json','["敢嗟君不憐，自是命不諧。", "著破三條裙，却還雙股釵。"]'),
('2f797cbc-2c50-4692-a513-57ce7fadb055','定情樂 二','施肩吾','唐','唐诗','tang','','[]','感郎雙條脫，新破八幅綃。',24,'全唐诗/poet.tang.26000.json','["感郎雙條脫，新破八幅綃。", "不惜榆莢錢，買人金步搖。"]'),
('ad4e116d-c270-4860-ba40-36c7a5573226','宿南一上人山房','施肩吾','唐','唐诗','tang','','[]','窗牖月色多，坐臥禪心靜。',24,'全唐诗/poet.tang.26000.json','["窗牖月色多，坐臥禪心靜。", "青鬼來試人，夜深弄燈影。"]'),
('f231ad07-e888-454a-bfa1-6544d95f1696','蘭渚泊','施肩吾','唐','唐诗','tang','','[]','家在洞水西，身作蘭渚客。',24,'全唐诗/poet.tang.26000.json','["家在洞水西，身作蘭渚客。", "天晝無纖雲，獨坐空江碧。"]'),
('eeec8ef4-a521-4479-a72d-79ed17129f7f','經吳真君舊宅','施肩吾','唐','唐诗','tang','','[]','古仙煉丹處，不測何歲年。',24,'全唐诗/poet.tang.26000.json','["古仙煉丹處，不測何歲年。", "至今空宅基，時有五色煙。"]'),
('ff655a33-2f9f-4d3e-b04f-6dc0e85e315f','古相思','施肩吾','唐','唐诗','tang','','[]','十訪九不見，甚於菖蒲花。',24,'全唐诗/poet.tang.26000.json','["十訪九不見，甚於菖蒲花。", "可憐雲中月，今夜墮我家。"]'),
('4f743153-575a-413e-b217-b10d18c723e9','瀑布','施肩吾','唐','唐诗','tang','','[]','豁開青冥顛，寫出萬丈泉。',24,'全唐诗/poet.tang.26000.json','["豁開青冥顛，寫出萬丈泉。", "如裁一條素，白日懸秋天。"]'),
('5a6c15c8-80b1-46d9-a0a5-93b3566c89d2','金尺石','施肩吾','唐','唐诗','tang','','[]','丹砂畫頑石，黃金橫一尺。',24,'全唐诗/poet.tang.26000.json','["丹砂畫頑石，黃金橫一尺。", "人世較短長，仙家愛平直。"]'),
('083c5d84-4001-4404-9f54-e7a12a526435','秋洞宿','施肩吾','唐','唐诗','tang','','[]','夜深秋洞裏，風雨報龍歸。',24,'全唐诗/poet.tang.26000.json','["夜深秋洞裏，風雨報龍歸。", "何事觸人睡，不教胡蝶飛。"]'),
('75c289e7-b9af-4ed5-b2b7-289d82f8710e','效古詞','施肩吾','唐','唐诗','tang','','[]','姊妹無多兄弟少，舉家鍾愛年最小。',32,'全唐诗/poet.tang.26000.json','["姊妹無多兄弟少，舉家鍾愛年最小。", "有時繞樹山鵲飛，貪看不待畫眉了。"]'),
('9c577244-da4d-49de-8ebd-2f567888e89f','山中得劉秀才京書','施肩吾','唐','唐诗','tang','','[]','自笑家貧客到疎，滿庭煙草不能鋤。',32,'全唐诗/poet.tang.26000.json','["自笑家貧客到疎，滿庭煙草不能鋤。", "今朝誰料三千里，忽得劉京一紙書。"]'),
('02be2b59-bf17-4d89-82a6-08a0f4d99d3c','望夫詞','施肩吾','唐','唐诗','tang','','[]','手爇寒燈向影頻，回文機上暗生塵。',32,'全唐诗/poet.tang.26000.json','["手爇寒燈向影頻，回文機上暗生塵。", "自家夫壻無消息，却恨橋頭賣卜人。"]'),
('705098b0-0d29-4eb9-9d3e-417bb6dfc858','憶四明山泉','施肩吾','唐','唐诗','tang','','[]','愛彼山中石泉水，幽深夜夜落空裏。',32,'全唐诗/poet.tang.26000.json','["愛彼山中石泉水，幽深夜夜落空裏。", "至今憶得臥雲時，猶自涓涓在人耳。"]'),
('429449c0-e850-42b6-8d84-b80d39bf0712','西山靜中吟','施肩吾','唐','唐诗','tang','','[]','重重道氣結成神，玉闕金堂逐日新。',32,'全唐诗/poet.tang.26000.json','["重重道氣結成神，玉闕金堂逐日新。", "若數西山得道者，連予便是十三人。"]'),
('6f04e60d-2bb3-4169-82d0-b0271855767b','天柱山贈峨嵋田道士','施肩吾','唐','唐诗','tang','','[]','古稱天柱連九天，峨嵋道士棲其巔。',32,'全唐诗/poet.tang.26000.json','["古稱天柱連九天，峨嵋道士棲其巔。", "近聞教得玄鶴舞，試憑驅出青芝田。"]'),
('8a9144aa-377f-46a0-b043-dc1565181b06','夜巖謠','施肩吾','唐','唐诗','tang','','[]','夜上幽巖踏靈草，松枝已疎桂枝老。',32,'全唐诗/poet.tang.26000.json','["夜上幽巖踏靈草，松枝已疎桂枝老。", "新詩幾度惜不吟，此處一聲風月好。"]'),
('33c3d8b6-ed09-4eef-a00a-3ef6869892aa','島夷行','施肩吾','唐','唐诗','tang','','[]','腥臊海邊多鬼市，島夷居處無鄉里。',32,'全唐诗/poet.tang.26000.json','["腥臊海邊多鬼市，島夷居處無鄉里。", "黑皮少年學採珠，手把生犀照鹹水。"]'),
