('5038998f-20a6-492c-b247-d698042a13dd','少女詞二首 二','施肩吾','唐','唐诗','tang','','[]','同心帶裏脫金錢，買取頭花翠羽連。',32,'全唐诗/poet.tang.26000.json','["同心帶裏脫金錢，買取頭花翠羽連。", "手執木蘭猶未慣，今朝初上采菱船。"]'),
('d961175d-4727-494a-9643-c2d1a73aa061','冬詞','施肩吾','唐','唐诗','tang','','[]','錦繡堆中臥初起，芙蓉面上粉猶殘。',32,'全唐诗/poet.tang.26000.json','["錦繡堆中臥初起，芙蓉面上粉猶殘。", "臺前也欲梳雲髻，只怕盤龍手捻難。"]'),
('aca8ff15-1361-4c3c-8910-74efd08ba13c','昭君怨','施肩吾','唐','唐诗','tang','','[]','馬上徒勞別恨深，總緣如玉不輸金。',32,'全唐诗/poet.tang.26000.json','["馬上徒勞別恨深，總緣如玉不輸金。", "已知賤妾無歸日，空荷君王有悔心。"]'),
('c9da098c-d1b5-4288-9f2d-82334cad5bc0','贈仙子','施肩吾','唐','唐诗','tang','','[]','欲令雪貌帶紅芳，更取金瓶瀉玉漿。',32,'全唐诗/poet.tang.26000.json','["欲令雪貌帶紅芳，更取金瓶瀉玉漿。", "鳳管鶴聲來未足，嬾眠秋月憶蕭郎。"]'),
('3fc9e291-65f6-4824-b7ad-444a85bb77da','越溪懷古','施肩吾','唐','唐诗','tang','','[]','憶昔西施人未求，浣紗曾向此溪頭。',32,'全唐诗/poet.tang.26000.json','["憶昔西施人未求，浣紗曾向此溪頭。", "一朝得侍君王側，不見玉顏空水流。"]'),
('d970bea0-3ed7-4783-b803-6a8d0b6b87bf','秋夜山中贈別友人','施肩吾','唐','唐诗','tang','','[]','何處邀君話別情，寒山木落月華清。',32,'全唐诗/poet.tang.26000.json','["何處邀君話別情，寒山木落月華清。", "莫愁今夜無詩思，已聽秋猨第一聲。"]'),
('170155ec-15c9-4b3f-aca1-6ff99583e834','大堤新詠','施肩吾','唐','唐诗','tang','','[]','行路少年知不知，襄陽全欠舊來時。',32,'全唐诗/poet.tang.26000.json','["行路少年知不知，襄陽全欠舊來時。", "宜城賈客載錢出，始覺大堤無女兒。"]'),
('528c3fdb-defd-4d3a-81b6-696363540070','宿四明山','施肩吾','唐','唐诗','tang','','[]','黎洲老人命余宿，杳然高頂浮雲平。',32,'全唐诗/poet.tang.26000.json','["黎洲老人命余宿，杳然高頂浮雲平。", "下視不知幾千仞，欲曉不曉天雞聲。"]'),
('e4bc73b6-b5fa-4f69-8f8c-1a6d8a178f5a','禁中新柳','施肩吾','唐','唐诗','tang','','[]','萬條金線帶春煙，深染青絲不直錢。',32,'全唐诗/poet.tang.26000.json','["萬條金線帶春煙，深染青絲不直錢。", "又免生當離別地，宮鵶啼處禁門前。"]'),
('9c99efe9-888e-4f12-b844-db59ddcd50f0','酬張明府','施肩吾','唐','唐诗','tang','','[]','潘令新詩忽寄來，分明繡段對花開。',32,'全唐诗/poet.tang.26000.json','["潘令新詩忽寄來，分明繡段對花開。", "此時欲醉紅樓裏，正被歌人勸一桮。"]'),
('b394869d-687a-40f0-9eef-964a5221dbe7','安吉天寧寺聞磬','施肩吾','唐','唐诗','tang','','[]','玉磬敲時清夜分，老龍吟斷碧天雲。',32,'全唐诗/poet.tang.26000.json','["玉磬敲時清夜分，老龍吟斷碧天雲。", "隣房逢見廣州客，曾向羅浮山裏聞。"]'),
('c59ca08f-e45e-4c38-995b-fba791b01312','句','施肩吾','唐','唐诗','tang','','[]','年來如拋梭，不老應不得。',216,'全唐诗/poet.tang.26000.json','["年來如拋梭，不老應不得。", "花眼綻紅斟酒看，藥心抽綠帶煙鋤。", "顛狂楚客歌成雪，媚賴吳娘笑是鹽。", "荷翻紫蓋搖波面，蒲瑩青刀插水湄。", "煙黏薜荔龍鬚軟，雨壓芭蕉鳳翅垂。", "茶爲滌煩子，酒爲忘憂君。", "鋤藥顧老叟，焚香呼小青。", "遺却白雞呼喌喌。", "五通本是佛家奴，身著青衣一足無。", "天邊有仙藥，爲我補三關。", "世人誰不愛年長，所欲皆非保命方。", "但看日及花，惟是朝可憐。", "池塘已長雞頭葉，籬落初開狗脊花。", "出路船爲脚，供官本是奴。", "一言感著熱鐵心，爲人劍下偷青娥。", "青鬢丈人不識愁。"]'),
('072525b3-078b-4130-a052-96279a833ea1','不赴拾遺召','費冠卿','唐','唐诗','tang','','[]','君親同是先王道，何如骨肉一處老。',32,'全唐诗/poet.tang.26000.json','["君親同是先王道，何如骨肉一處老。", "也知臣子合佐時，自古榮華誰可保。"]'),
('fd5b322e-0862-4df0-917f-2338630940ed','閑居即事','費冠卿','唐','唐诗','tang','','[]','生計唯將三尺僮，學他賢者隱牆東。',64,'全唐诗/poet.tang.26000.json','["生計唯將三尺僮，學他賢者隱牆東。", "照眠夜後多因月，掃地春來祗藉風。", "幾處紅旗驅戰士，一園青草伴衰翁。", "子房仙去孔明死，更有何人解指蹤。"]'),
('740c8682-56d1-4316-a930-cfed57db0c2f','酬范中丞見','費冠卿','唐','唐诗','tang','','[]','花宮柳陌正從行，紫袂金鞍問姓名。',64,'全唐诗/poet.tang.26000.json','["花宮柳陌正從行，紫袂金鞍問姓名。", "戰國方須禮干木，康時何必重侯嬴。", "捧將束帛山僮喜，傳示銀鉤邑客驚。", "直爲雲泥相去遠，一言知己殺身輕。"]'),
('ab0b4b03-0a08-4d00-8ec6-52b229ad53c9','秋日與冷然上人寺莊觀稼','費冠卿','唐','唐诗','tang','','[]','世人從擾擾，獨自愛身閑。',48,'全唐诗/poet.tang.26000.json','["世人從擾擾，獨自愛身閑。", "美景當新霽，隨僧過遠山。", "村橋出秋稼，空翠落澄灣。", "唯有中林犬，猶應望我還。"]'),
('ac105775-7e0e-4308-9c2c-a1115f2256ec','題中峰','費冠卿','唐','唐诗','tang','','[]','中峰高拄泬寥天，上有茅菴與石泉。',32,'全唐诗/poet.tang.26000.json','["中峰高拄泬寥天，上有茅菴與石泉。", "晴景獵人曾望見，青藍色裏一僧禪。"]'),
('20f4beda-32b6-4e80-b424-433438bb873a','蒙召拜拾遺書情二首 一','費冠卿','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','拾遺帝側知難得，官緊才微恐不勝。',32,'全唐诗/poet.tang.26000.json','["拾遺帝側知難得，官緊才微恐不勝。", "好是中朝絕親友，九華山下詔來徵。"]'),
('a558a4ff-f55e-43e5-b6f8-6459949ffa3b','蒙召拜拾遺書情二首 二','費冠卿','唐','唐诗','tang','','[]','三千里外一微臣，二十年來任運身。',32,'全唐诗/poet.tang.26000.json','["三千里外一微臣，二十年來任運身。", "今日忽蒙天子召，自慙驚動國中人。"]'),
('332986d1-e891-4350-a3a3-428b2bf18b96','挂樹藤','費冠卿','唐','唐诗','tang','','[]','本爲獨立難，寄彼高樹枝。',48,'全唐诗/poet.tang.26000.json','["本爲獨立難，寄彼高樹枝。", "蔓衍數條遠，溟濛千朵垂。", "向日助成陰，當風藉持危。", "誰言柔可屈，坐見蟠蛟螭。"]'),
('73f3a526-ece7-4204-afe2-2694108b2e0b','枕流石','費冠卿','唐','唐诗','tang','','[]','不爲幽岸隱，古色涵空出。',48,'全唐诗/poet.tang.26000.json','["不爲幽岸隱，古色涵空出。", "願以清泚流，鑒此堅貞質。", "傍臨玉光潤，時瀉苔花密。", "往往驚遊鱗，尚疑垂釣日。"]'),
('7ede654b-58f4-4437-849c-ac703f5f0c8b','久居京師感懷詩','費冠卿','唐','唐诗','tang','','[]','煢獨不爲苦，求名始辛酸。',84,'全唐诗/poet.tang.26000.json','["煢獨不爲苦，求名始辛酸。", "上國無交親，請謁多少難。", "九月風到面，羞汗成冰片。", "求名俟公道，名與公道遠。", "力盡得一名，他喜我且輕。", "家書十年絕，歸去知誰榮。", "馬嘶渭橋柳，特地起秋聲。"]'),
('66d92651-3b95-418b-8620-bb1287b79979','答蕭建','費冠卿','唐','唐诗','tang','','[]','自地上青峰，懸崖一萬重。',218,'全唐诗/poet.tang.26000.json','["自地上青峰，懸崖一萬重。", "踐危頻側足，登塹半齊胸。", "飛狖啼攀桂，遊人喘倚松。", "入林寒㾕㾕，近瀑雨濛濛。", "徑滑石稜上，寺開山掌中。", "幡花撲淨地，臺殿印晴空。", "勝境層層別，高僧院院逢。", "泉魚候洗鉢，老玃戲撞鐘。", "外戶憑雲掩，中廚課水舂。", "搜泥時和麪，拾橡半添穜。", "渡壑緣槎險，持燈入洞窮。", "夾天開壁峭，透石蹙波雄。", "澗藹清無土，潭深碧有龍。", "畬田一片淨，谷樹萬株濃。", "野客登臨慣，山房幽寂同。", "寒爐樹根火，夏牖竹稍風。", "邊鄙籌賢相，黔黎託聖躬。", "君能棄名利，歲[晏]一相從。"]'),
('a3b93ba7-05fa-4a4a-9278-c79e37862a30','代書問費徵君九華亭','蕭建','唐','唐诗','tang','','[]','見說九華峰上寺，日宮猶在下方開。',32,'全唐诗/poet.tang.26000.json','["見說九華峰上寺，日宮猶在下方開。", "其中幽境客難到，請爲詩中圖畫來。"]'),
('04c7dcf9-9275-47ba-a1ed-0c1f572bc0a1','獻主文','劉虛白','唐','唐诗','tang','','[]','二十年前此夜中，一般燈燭一般風。',32,'全唐诗/poet.tang.26000.json','["二十年前此夜中，一般燈燭一般風。", "不知歲月能多少，猶著麻衣待至公。"]'),
('b09e2c02-ef4a-4631-b3c8-584000604f66','句','劉虛白','唐','唐诗','tang','','[]','知道醉鄉無戶稅，任他荒却下丹田。',16,'全唐诗/poet.tang.26000.json','["知道醉鄉無戶稅，任他荒却下丹田。"]'),
('81d71b3a-71d5-4af2-b5b8-e067652a59dd','山出雲','張復','唐','唐诗','tang','','[]','山靜雲初吐，霏微觸石新。',72,'全唐诗/poet.tang.26000.json','["山靜雲初吐，霏微觸石新。", "無心離碧岫，有葉占青春。", "散類如虹氣，輕同不讓塵。", "凌空還似翼，映澗欲成鱗。", "異起臨汾鼎，疑隨出峽神。", "爲霖終濟旱，非獨降賢人。"]'),
('67d498e6-639f-4e00-868a-7a6f43fdad85','山出雲','張勝之','唐','唐诗','tang','','[]','片雲初出岫，孤迥色難親。',72,'全唐诗/poet.tang.26000.json','["片雲初出岫，孤迥色難親。", "蓋小辭山近，根輕觸石新。", "飄颻經綠野，明麗照晴春。", "拂樹疑舒葉，臨流似結鱗。", "從龍方有感，捧日豈無因。", "看取爲霖去，恩霑雨露均。"]'),
('7f943c62-ed92-4b71-b9ed-f44df9c36af6','送狄尚書鎮太原','姚合','唐','唐诗','tang','','[]','授鉞儒生貴，傾朝赴餞筵。',96,'全唐诗/poet.tang.26000.json','["授鉞儒生貴，傾朝赴餞筵。", "麾幢官在省，禮樂將臨邊。", "代馬龍相雜，汾河海暗連。", "遠戎移帳幕，高鳥避旌旃。", "天下屯兵處，皇威破虜年。", "防秋嫌壘近，入塞必身先。", "中外恩重疊，科名歲接連。", "散材無所用，老向瑣闈眠。"]'),
('4d4a2fb3-c151-4a4d-b48b-90d3f71d96a0','送楊尚書祭西嶽','姚合','唐','唐诗','tang','','["\u534e\u5c71"]','報功嚴祀典，寵詔下明庭。',60,'全唐诗/poet.tang.26000.json','["報功嚴祀典，寵詔下明庭。", "酒氣飄林嶺，香煙入杳冥。", "樂清三奏備，詞直百神聽。", "衣拂雲霞濕，詩通水石靈。", "何因逐騶騎，暫得到巖扃。"]'),
('2c1b750c-2593-4ea2-b828-967fe2287005','送李侍御過夏州','姚合','唐','唐诗','tang','','[]','酬恩不顧名，走馬覺身輕。',48,'全唐诗/poet.tang.26000.json','["酬恩不顧名，走馬覺身輕。", "迢遞河邊路，蒼茫塞上城。", "沙寒無宿雁，虜近少閑兵。", "飲罷揮鞭去，旁人意氣生。"]'),
('9eadc1fc-bb77-4b1e-aa9c-01ee8779a597','送李起居赴池州','姚合','唐','唐诗','tang','','[]','天子念疲民，分憂輟侍臣。',48,'全唐诗/poet.tang.26000.json','["天子念疲民，分憂輟侍臣。", "紅旗高起焰，綠野靜無塵。", "闕下親知別，江南惠化新。", "朝昏即千里，且願話逡巡。"]'),
('8f1f4d8c-b39f-48a0-897f-417f4e4f54f8','送劉詹事赴壽州','姚合','唐','唐诗','tang','','[]','慇懃莫遽起，四坐悉同袍。',48,'全唐诗/poet.tang.26000.json','["慇懃莫遽起，四坐悉同袍。", "世上詩難得，林中酒更高。", "隋隄傍楊柳，楚驛在波濤。", "別後書頻寄，無辭費筆毫。"]'),
('0270ef40-78a6-488d-8472-ed61bd046165','送裴大夫赴亳州','姚合','唐','唐诗','tang','','[]','杭人遮道路，垂泣浙江前。',72,'全唐诗/poet.tang.26000.json','["杭人遮道路，垂泣浙江前。", "譙國迎舟艦，行歌汴水邊。", "周旋君量遠，交代我才偏。", "寒日嚴旌戟，晴風出管弦。", "一桮誠淡薄，四坐願留連。", "異政承殊澤，應爲天下先。"]'),
('084db12d-6e02-4e11-a918-1ea08048a907','送徐州韋僅行軍','姚合','唐','唐诗','tang','','[]','餞幕儼征軒，行軍歸大藩。',48,'全唐诗/poet.tang.26000.json','["餞幕儼征軒，行軍歸大藩。", "山程度函谷，水驛到夷門。", "曉日詩情遠，春風酒色渾。", "逡巡何足貴，所貴盡殘罇。"]'),
('53a1e44b-511b-4586-9414-3c73b86f7c54','送劉禹錫郎中赴蘇州 一','姚合','唐','唐诗','tang','','[]','三十年來天下名，銜恩東守闔閭城。',64,'全唐诗/poet.tang.26000.json','["三十年來天下名，銜恩東守闔閭城。", "初經咸谷眠山驛，漸入梁園問水程。", "霽日滿江寒浪靜，春風遶郭白蘋生。", "虎丘野寺吳中少，誰伴吟詩月裏行。"]'),
('a66b4af3-fcac-4dad-99c8-89f99b4ad6e1','送劉禹錫郎中赴蘇州 二','姚合','唐','唐诗','tang','','[]','州城全是故吳宮，香徑難尋古蘚中。',64,'全唐诗/poet.tang.26000.json','["州城全是故吳宮，香徑難尋古蘚中。", "雲水計程千里遠，軒車送別九衢空。", "鶴聲高下聽無盡，潮色朝昏望不同。", "太守吟詩人自理，小齋閑臥白蘋風。"]'),
('4a217e35-590a-49b8-8539-f57a0d5e9d8d','送賈謩赴共城營田','姚合','唐','唐诗','tang','','[]','上國羞長選，戎裝貴所從。',48,'全唐诗/poet.tang.26000.json','["上國羞長選，戎裝貴所從。", "山田依法種，兵食及時供。", "水氣詩書軟，嵐煙筆硯濃。", "幾時無事擾，相見得從容。"]'),
('b8aa0d7a-53af-4104-a016-e1de7d5157c2','送裴宰君','姚合','唐','唐诗','tang','','[]','見說爲官處，煙霞思不窮。',48,'全唐诗/poet.tang.26000.json','["見說爲官處，煙霞思不窮。", "夜猿啼戶外，瀑水落廚中。", "名藥人難識，仙山路易通。", "還應施靜化，誰復與君同。"]'),
('130cda42-0082-4d5c-b4cf-c78afa4f44f7','送顧非熊下第歸越','姚合','唐','唐诗','tang','','[]','失意尋歸路，親知不復過。',48,'全唐诗/poet.tang.26000.json','["失意尋歸路，親知不復過。", "家山去城遠，日月在船多。", "楚塞數逢雁，浙江長有波。", "秋風別鄉老，還聽鹿鳴歌。"]'),
('2e52da8d-17fb-4679-ba2b-487ccb2ef9ff','送雍陶遊蜀','姚合','唐','唐诗','tang','','[]','春色三千里，愁人意未開。',48,'全唐诗/poet.tang.26000.json','["春色三千里，愁人意未開。", "木梢穿棧出，雨勢隔江來。", "荒館因花宿，深山羨客迴。", "相如何物在，應只有琴臺。"]'),
('884eca24-432e-472e-9965-3bf570707876','送崔約下第歸揚州','姚合','唐','唐诗','tang','','[]','滿座詩人吟送酒，離城此會亦應稀。',64,'全唐诗/poet.tang.26000.json','["滿座詩人吟送酒，離城此會亦應稀。", "春風下第時稱屈，秋卷呈親自束歸。", "日晚山花當馬落，天陰水鳥傍船飛。", "江邊道路多苔蘚，塵土無由得上衣。"]'),
('abfd7f47-7486-4431-a34f-b7fe350303a9','送李廓侍御赴西川行營','姚合','唐','唐诗','tang','','[]','不道弓箭字，罷官唯醉眠。',48,'全唐诗/poet.tang.26000.json','["不道弓箭字，罷官唯醉眠。", "何人薦籌策，走馬逐旌旃。", "陣變孤虛外，功成語笑前。", "從今巂州路，無復有烽煙。"]'),
('d124cb30-bab0-4125-a214-cff3258bde3f','送楊尚書赴東川','姚合','唐','唐诗','tang','','[]','郤縠詩書將，銜恩赴梓州。',48,'全唐诗/poet.tang.26000.json','["郤縠詩書將，銜恩赴梓州。", "遶身垂印綬，護馬執戈矛。", "劒閣和銘峭，巴江帶字流。", "從來皆惜別，此別復何愁。"]'),
('af5b3568-96cf-4ad0-b46f-3be08ff7a8e4','送邢郎中赴太原','姚合','唐','唐诗','tang','','[]','上將得良策，恩威作長城。',48,'全唐诗/poet.tang.26000.json','["上將得良策，恩威作長城。", "如今幷州北，不見有胡兵。", "晉野雨初足，汾河波亦清。", "所從古無比，意氣送君行。"]'),
('14c2166b-9642-4b81-9979-666ab5244f8f','送裴中丞赴華州','姚合','唐','唐诗','tang','','[]','我夢何曾應，看君渡滻川。',48,'全唐诗/poet.tang.26000.json','["我夢何曾應，看君渡滻川。", "自無仙掌分，非是聖心偏。", "徑草多生藥，庭花半落泉。", "人間有此郡，況在鳳城邊。"]'),
('3279e9a5-f576-4eb3-af6a-fbc82b62f646','送徐員外赴河中從事','姚合','唐','唐诗','tang','','[]','赤府從軍美，儒衣結束輕。',48,'全唐诗/poet.tang.26000.json','["赤府從軍美，儒衣結束輕。", "涼飆下山寺，曉浪滿關城。", "閑坐饒詩景，高眠長道情。", "將軍不戰術，計日立功名。"]'),
('f3c6041f-01da-4470-9ca0-fe8d63fb8bad','送殷堯藩侍御赴同州','姚合','唐','唐诗','tang','','[]','吟詩擲酒船，仙掌白樓前。',48,'全唐诗/poet.tang.26000.json','["吟詩擲酒船，仙掌白樓前。", "從事關中貴，主人天下賢。", "此生無了日，終歲踏離筵。", "何計因歸去，深山恣意眠。"]'),
('746aaef3-99cd-45ad-9aa4-5990f683e51d','送崔中丞赴鄭州','姚合','唐','唐诗','tang','','[]','僕射陂前郡，清高越四隣。',48,'全唐诗/poet.tang.26000.json','["僕射陂前郡，清高越四隣。", "丹霄鳳詔下，太守虎符新。", "霧濕關城月，花香驛路塵。", "連枝相庭樹，歲歲一家春。"]'),
('c78fc8ce-5f24-4c0d-91df-3f826be14993','送丁端公赴河陰','姚合','唐','唐诗','tang','','[]','炎天木葉焦，曉夕絕涼飆。',48,'全唐诗/poet.tang.26000.json','["炎天木葉焦，曉夕絕涼飆。", "念子獨歸縣，何人不在朝。", "市連風浪動，帆徹海門遙。", "飲盡樽中酒，同年同寂寥。"]'),
('ad1a4a4b-a38f-4925-859f-dfd40a1aea39','送鄭尚書赴興元','姚合','唐','唐诗','tang','','[]','儒有登壇貴，何人得此功。',48,'全唐诗/poet.tang.26000.json','["儒有登壇貴，何人得此功。", "紅旗燒密雪，白馬踏長風。", "斧鉞來天上，詩書理漢中。", "方知百勝略，應不在彎弓。"]'),
('e4cf1af0-99f2-4c89-ba02-e444ebd31dc3','送田使君赴蔡州','姚合','唐','唐诗','tang','','[]','長年離別情，百盞酒須傾。',48,'全唐诗/poet.tang.26000.json','["長年離別情，百盞酒須傾。", "詩外應無思，人間半是行。", "路遙嘶白馬，林斷出紅旌。", "功業今應立，淮西有勁兵。"]'),
('bd7e27c0-8910-470e-9d10-c3345cd7929e','送無可上人遊邊','姚合','唐','唐诗','tang','','[]','一鉢與三衣，經行遠近隨。',48,'全唐诗/poet.tang.26000.json','["一鉢與三衣，經行遠近隨。", "出家還養母，持律復能詩。", "春雪離京厚，晨鐘近塞遲。", "亦知蓮府客，夜坐喜同師。"]'),
('675559ad-67b1-4fc0-baed-fbd73db63374','送僧 一','姚合','唐','唐诗','tang','','[]','人間擾擾唯閑事，自見高人只有詩。',32,'全唐诗/poet.tang.26000.json','["人間擾擾唯閑事，自見高人只有詩。", "寂寞嵩峰雲外寺，常多夢裏過齋時。"]'),
('1540cd22-62d8-41ba-a7b2-d7a583b31970','送僧 二','姚合','唐','唐诗','tang','','[]','城中聽得新經論，却過關東說向人。',32,'全唐诗/poet.tang.26000.json','["城中聽得新經論，却過關東說向人。", "舊國門徒終日望，見時應是見真身。"]'),
('033a5f97-4dc2-4770-a1c8-1602c6269d47','送宋慎言','姚合','唐','唐诗','tang','','[]','童穉便知聞，如今祗有君。',48,'全唐诗/poet.tang.26000.json','["童穉便知聞，如今祗有君。", "百篇詩盡和，一盞酒須分。", "驛路多連水，州城半在雲。", "離情同落葉，向晚更紛紛。"]'),
('521ad0fe-dc2f-45fa-aa12-e09016c15f9b','送家兄赴任昭義','姚合','唐','唐诗','tang','','[]','早得白眉名，之官濠上城。',72,'全唐诗/poet.tang.26000.json','["早得白眉名，之官濠上城。", "別離浮世事，迢遰長年情。", "廣陌垂花影，遙林起雨聲。", "出關春草長，過汴夏雲生。", "黠吏先潛去，疲人相次迎。", "宴餘和酒拜，魂夢共東行。"]'),
('7b2a13e1-a963-4c76-8676-cf9353746fe5','送崔玄亮赴果州冬夜宴韓卿宅','姚合','唐','唐诗','tang','','[]','蘭燭照重茵，飛盃復幾分。',72,'全唐诗/poet.tang.26000.json','["蘭燭照重茵，飛盃復幾分。", "主人寒不寐，上客曉離羣。", "騎吏緣青壁，旌旗度白雲。", "劒銘生蘚色，巴字疊冰文。", "華省思僊侶，疲民愛使君。", "泠泠唯自適，郡邸有誰聞。"]'),
('242fe55a-82fe-4dfe-9afb-ed25fef3780c','送喻鳧校書歸毘陵','姚合','唐','唐诗','tang','','[]','主人庭葉黑，詩稿更誰書。',48,'全唐诗/poet.tang.26000.json','["主人庭葉黑，詩稿更誰書。", "闕下科名出，鄉中賦籍除。", "山春煙樹衆，江遠晚帆疎。", "吾亦家吳者，無因到弊廬。"]'),
('03092e20-d4a2-40a3-8ade-843c75171902','送董正字武歸常州覲親','姚合','唐','唐诗','tang','','[]','路岐知不盡，離別自無窮。',48,'全唐诗/poet.tang.26000.json','["路岐知不盡，離別自無窮。", "行客心方切，主人罇未空。", "楚檣收月下，江樹在潮中。", "人各還家去，還家慶不同。"]'),
('8fc946ff-341a-4f70-8f1f-74159a4bf21e','送蕭正字往蔡州賀裴相淮西平','姚合','唐','唐诗','tang','','[]','相府旌旄重，還邀上客行。',48,'全唐诗/poet.tang.26000.json','["相府旌旄重，還邀上客行。", "今朝郭門路，初徹蔡州城。", "從馬唯提酒，防身不要兵。", "從來皆作使，君去是時平。"]'),
('e7050a04-a24c-4499-b74b-be84da3c0932','送進士田卓入華山','姚合','唐','唐诗','tang','','[]','何物隨身去，六經與一琴。',48,'全唐诗/poet.tang.26000.json','["何物隨身去，六經與一琴。", "辭家計已久，入谷住應深。", "偶坐僧同石，閑書葉滿林。", "業成須謁帝，無貯白雲心。"]'),
('7569d663-805a-47fc-97ed-72d88c179880','送右司薛員外赴處州','姚合','唐','唐诗','tang','','[]','懷中天子書，腰下使君魚。',48,'全唐诗/poet.tang.26000.json','["懷中天子書，腰下使君魚。", "瀑布和雲落，仙都與世疎。", "遠程兼水陸，半歲在舟車。", "相送難相別，南風入夏初。"]'),
('5a11df95-1dc6-4732-80e5-9ae3e4b7ecb8','送王建秘書往渭南莊','姚合','唐','唐诗','tang','','[]','白鬚芸閣吏，羸馬月中行。',48,'全唐诗/poet.tang.26000.json','["白鬚芸閣吏，羸馬月中行。", "莊僻難尋路，官閑易出城。", "看山多失飯，過寺故題名。", "秋日田家作，唯添集卷成。"]'),
('73249ea6-6c5d-43d3-a032-4c7ee2a89166','送殷堯藩侍御遊山南','姚合','唐','唐诗','tang','','[]','詩境西南好，秋深晝夜蛩。',48,'全唐诗/poet.tang.26000.json','["詩境西南好，秋深晝夜蛩。", "人家連水影，驛路在山峰。", "谷靜雲生石，天寒雪覆松。", "我爲公府繫，不得此相從。"]'),
('aa7af578-c93a-4e28-ae4d-b3e8f5b36a8b','送李植侍御','姚合','唐','唐诗','tang','','[]','聖代無邪觸，空林獬豸歸。',48,'全唐诗/poet.tang.26000.json','["聖代無邪觸，空林獬豸歸。", "誰知隴山鳥，長繞玉樓飛。", "風雨依山急，雲泉入郭微。", "無同昔年別，別後寄書稀。"]'),
('f718214a-3a80-4eab-a145-e140588bb217','送王澹','姚合','唐','唐诗','tang','','[]','常省爲官處，門前數樹松。',48,'全唐诗/poet.tang.26000.json','["常省爲官處，門前數樹松。", "尋山屐費齒，書石筆無鋒。", "果熟猿偷亂，花繁鳥語重。", "今來爲客去，惜取最高峰。"]'),
('6a895d01-2e34-4729-ae87-709945f997cd','送崔之仁','姚合','唐','唐诗','tang','','[]','欲出還成住，前程甚謫遷。',48,'全唐诗/poet.tang.26000.json','["欲出還成住，前程甚謫遷。", "佯眠隨客醉，愁坐似僧禪。", "舊國歸何處，春山買欠錢。", "幾時無一事，長在故人邊。"]'),
('64a7639b-7ab0-4db1-8b41-b11498712044','送孫山人','姚合','唐','唐诗','tang','','[]','山翁來帝里，不肯住多時。',48,'全唐诗/poet.tang.26000.json','["山翁來帝里，不肯住多時。", "塵土衣裳重，腥羶僕隸飢。", "林中愁不到，城外老應遲。", "喧寂一爲別，相逢未有期。"]'),
('7fa39bab-0056-44b9-b7c3-f4d318fa0131','送費驤','姚合','唐','唐诗','tang','','[]','兄寒弟亦飢，力學少閑時。',48,'全唐诗/poet.tang.26000.json','["兄寒弟亦飢，力學少閑時。", "何路免爲客，無門賣得詩。", "幾人攜酒送，獨我入山遲。", "少小同居止，今朝始別離。"]'),
('02188682-4b6c-4a6a-816d-da27ed66b8df','送河中楊少府宴崔駙馬宅','姚合','唐','唐诗','tang','','[]','鳳凰樓下醉醺醺，晚出東門蟬漸聞。',64,'全唐诗/poet.tang.26000.json','["鳳凰樓下醉醺醺，晚出東門蟬漸聞。", "不使鄉人治驛路，却將家累宿山雲。", "閑時採藥隨僧去，每月請錢共客分。", "縣吏若非三載滿，自知無計更尋君。"]'),
('2da4dcfb-c085-4638-b980-af8257874eea','送文著上人遊越','姚合','唐','唐诗','tang','','[]','水石隨緣豈計程，東吳相遇別西京。',64,'全唐诗/poet.tang.26000.json','["水石隨緣豈計程，東吳相遇別西京。", "夜禪月下袈裟濕，曉上山巔錫杖鳴。", "念我爲官應易老，羨師依佛學無生。", "越中多有前朝寺，處處鐵鐘石磬聲。"]'),
('2e9f7f05-df4e-49b5-a947-20705290e186','送無可上人遊越','姚合','唐','唐诗','tang','','[]','清晨相訪立門前，麻履方袍一少年。',64,'全唐诗/poet.tang.26000.json','["清晨相訪立門前，麻履方袍一少年。", "嬾讀經文求作佛，願攻詩句覓昇仙。", "芳春山影花連寺，獨夜潮聲月滿船。", "今日送行偏惜別，共師文字有因緣。"]'),
('4fb139bc-44b8-4e72-aa7f-94b0af0ee056','送洛陽張員外','姚合','唐','唐诗','tang','','[]','餞客未歸城，東來騶騎迎。',48,'全唐诗/poet.tang.26000.json','["餞客未歸城，東來騶騎迎。", "千山嵩岳峭，百縣洛陽清。", "朔雁和雲度，川風吹雨晴。", "蘚庭公事暇，應祗獨吟行。"]'),
('58c273ac-aa5c-41c3-817d-401e32ca2011','送少府田中丞入西藩','姚合','唐','唐诗','tang','','[]','蕭關路絕久，石堠亦爲塵。',48,'全唐诗/poet.tang.26000.json','["蕭關路絕久，石堠亦爲塵。", "護塞空兵帳，和戎在使臣。", "風沙去國遠，雨雪換衣頻。", "若問涼州事，涼州多漢人。"]'),
('49f76693-b178-4934-9c9f-874e3b92d712','送王龜處士','姚合','唐','唐诗','tang','','[]','送客客爲誰，朱門處士稀。',48,'全唐诗/poet.tang.26000.json','["送客客爲誰，朱門處士稀。", "唯修曾子行，不著老萊衣。", "古寺隨僧飯，空林共鳥歸。", "壺中駐年藥，燒得獻庭闈。"]'),
('7527d9c0-b0d4-4e50-a6f0-4ad0b043a09d','送崔郎中赴常州','姚合','唐','唐诗','tang','','[]','貴是鴒原在紫微，榮逢知己領黃扉。',64,'全唐诗/poet.tang.26000.json','["貴是鴒原在紫微，榮逢知己領黃扉。", "人間盛事今全得，江上政聲復欲歸。", "風起滿城山果落，雨餘穿宅水禽飛。", "昔年嘗作毘陵客，石峭泉清天下稀。"]'),
('33e3e495-f88f-49d8-b576-99b43f64645c','送林使君赴邵州','姚合','唐','唐诗','tang','','[]','詔書飛下五雲間，才子分符不等閑。',64,'全唐诗/poet.tang.26000.json','["詔書飛下五雲間，才子分符不等閑。", "驛路算程多是水，州圖管地少於山。", "江頭斑竹尋應遍，洞裏丹砂自採還。", "清淨化人人自理，終朝無事更相關。"]'),
('c2a77bf9-2c23-453c-897e-f078195c170d','送別友人','姚合','唐','唐诗','tang','','[]','獨向山中覓紫芝，山人勾引住多時。',64,'全唐诗/poet.tang.26000.json','["獨向山中覓紫芝，山人勾引住多時。", "摘花浸酒春愁盡，燒竹煎茶夜臥遲。", "泉落林梢多碎滴，松生石底足旁枝。", "明朝却欲歸城市，問我來期總不知。"]'),
('f5681052-e641-4a42-876b-897f0e4c8c25','送李琮歸靈州覲省','姚合','唐','唐诗','tang','','[]','餞席離人起，貪程醉不眠。',48,'全唐诗/poet.tang.26000.json','["餞席離人起，貪程醉不眠。", "風沙移道路，僕馬識山川。", "塞樹花開小，關城雪下偏。", "胡塵今已盡，應便促朝天。"]'),
('00167d6c-319b-4e46-80f8-78cad2b7e5fa','送任畹評事赴沂海','姚合','唐','唐诗','tang','','[]','擲筆不作尉，戎衣從嫖姚。',120,'全唐诗/poet.tang.26000.json','["擲筆不作尉，戎衣從嫖姚。", "嚴冬入都門，僕馬氣益豪。", "沂州右鎮雄，士勇旌旗高。", "洛東無憂虞，半夜開虎牢。", "丈夫貴功勳，不貴爵祿饒。", "仰眠作書生，衣食何由銷。", "任生非常才，臨事膽不搖。", "必當展長畫，逆波斬鯨鼇。", "九陌塵土黑，話別立遠郊。", "孟堅勒燕然，豈獨在漢朝。"]'),
('d7ba5684-17a2-4741-9b5d-fd0770ca9781','送李餘及第歸蜀','姚合','唐','唐诗','tang','','[]','蜀山高岧嶤，蜀客無平才。',192,'全唐诗/poet.tang.26000.json','["蜀山高岧嶤，蜀客無平才。", "日飲錦江水，文章盈其懷。", "十年作貢賓，九年多邅迴。", "春來登高科，升天得梯階。", "手持冬集書，還家獻庭闈。", "人生此爲榮，得如君者稀。", "李白蜀道難，羞爲無成歸。", "子今稱意行，所歷安覺危。", "與子久相從，今朝忽乖離。", "風飄海中船，會合難自期。", "長安米價高，伊我常渴飢。", "臨岐歌送子，無聲但陳詞。", "義交外不親，利交內相違。", "勉子慎其道，急若食與衣。", "苦爇道路赤，行人念前馳。", "一杯不可輕，遠別方自茲。"]'),
('b7a7bf7c-634b-4422-ba98-d732edb3f952','送饒州張使君','姚合','唐','唐诗','tang','','[]','鄱陽勝事聞難比，千里連連是稻畦。',64,'全唐诗/poet.tang.26000.json','["鄱陽勝事聞難比，千里連連是稻畦。", "山寺去時通水路，郡圖開處是詩題。", "化行應免農人困，庭靜惟多野鶴棲。", "飲罷春明門外別，蕭條驛路夕陽低。"]'),
('bbf8e824-0384-42fa-9ff1-502f687fd1d7','送張宗原','姚合','唐','唐诗','tang','','[]','東門送客道，春色如死灰。',144,'全唐诗/poet.tang.26000.json','["東門送客道，春色如死灰。", "一客失意行，十客顏色低。", "住者既無家，去者又非歸。", "窮愁一成疾，百藥不可治。", "子賢我且愚，命分不合齊。", "誰開蹇躓門，日日同遊棲。", "子行何所之，切切食與衣。", "誰能買仁義，令子無寒飢。", "野田不生草，四向生路岐。", "士人甚商賈，終日須東西。", "鴻雁春北去，秋風復南飛。", "勉君向前路，無失相見期。"]'),
('c73738b8-20ae-4bde-8301-6382bbe03f6c','送王求','姚合','唐','唐诗','tang','','[]','士有經世籌，自無活身策。',120,'全唐诗/poet.tang.26000.json','["士有經世籌，自無活身策。", "求食道路間，勞困甚徒役。", "我身與子同，日被飢寒迫。", "側望卿相門，難入堅如石。", "爲農昧耕耘，作商迷貿易。", "空把書卷行，投人買罪責。", "六月南風多，苦旱土色赤。", "坐家心尚焦，況乃遠作客。", "羸馬出郭門，餞飲曉連夕。", "願君似醉腸，莫謾生憂慼。"]'),
('7646ef91-0e26-4b1e-99e2-6dcbed97aff0','送朱慶餘及第後歸越','姚合','唐','唐诗','tang','','[]','勸君緩上車，鄉里有吾廬。',48,'全唐诗/poet.tang.26000.json','["勸君緩上車，鄉里有吾廬。", "未得同歸去，空令相見疎。", "山晴棲鶴起，天曉落潮初。", "此慶將誰比，獻親冬集書。"]'),
('6197db38-f2f1-43f2-888d-9cf6ad51f61d','送朱慶餘越州歸覲','姚合','唐','唐诗','tang','','[]','鄉書落姓名，太守拜親榮。',48,'全唐诗/poet.tang.26000.json','["鄉書落姓名，太守拜親榮。", "訪我波濤郡，還家霧雨城。", "海山窗外近，鏡水世間清。", "何計隨君去，鄰牆過此生。"]'),
('a9a5b081-345a-45d3-a1ed-34933b19dd4b','送任尊師歸蜀覲親','姚合','唐','唐诗','tang','','[]','白雲修道者，歸去春風前。',48,'全唐诗/poet.tang.26000.json','["白雲修道者，歸去春風前。", "玉簡通仙籍，金丹駐母年。", "錦文江一色，酒氣雨相連。", "衆說君平死，真師易義全。"]'),
('842122de-1894-429c-b409-7ff84813c11f','送友人遊蜀','姚合','唐','唐诗','tang','','[]','送君一壺酒，相別野庭邊。',48,'全唐诗/poet.tang.26000.json','["送君一壺酒，相別野庭邊。", "馬上過秋色，舟中到錦川。", "峽猿啼夜雨，蜀鳥噪晨煙。", "莫便不迴首，風光促幾年。"]'),
('fc4de02a-4571-4e2e-928f-3a7c46b1f339','送杜立歸蜀','姚合','唐','唐诗','tang','','[]','迢遞三千里，西南是去程。',72,'全唐诗/poet.tang.26000.json','["迢遞三千里，西南是去程。", "杜陵家已盡，蜀國客重行。", "雪照巴江色，風吹棧閣聲。", "馬嘶山稍煖，人語店初明。", "旅夢心多感，孤吟氣不平。", "誰爲李白後，爲訪錦官城。"]'),
('e9731824-a335-4f7b-a859-2ea027a0a7c1','送韓湘赴江西從事','姚合','唐','唐诗','tang','','[]','年少登科客，從軍詔命新。',72,'全唐诗/poet.tang.26000.json','["年少登科客，從軍詔命新。", "行裝有兵器，祖席盡詩人。", "細雨湘城暮，微風楚水春。", "潯陽應足雁，夢澤豈無塵。", "猿叫來山頂，潮痕在樹身。", "從容多暇日，佳句寄須頻。"]'),
('120ee7ce-e340-4a96-a8a0-bc2875b9903e','送潘傳秀才歸宣州','姚合','唐','唐诗','tang','','[]','李白墳三尺，嵯峨萬古名。',48,'全唐诗/poet.tang.26000.json','["李白墳三尺，嵯峨萬古名。", "因君還故里，爲我弔先生。", "晴日移虹影，空山出鶴聲。", "老郎閑未得，無計此中行。"]'),
('2610dfcf-d37d-4fe0-9d5e-01a93044caf6','送僧默然','姚合','唐','唐诗','tang','','[]','出家侍母前，至孝自通禪。',48,'全唐诗/poet.tang.26000.json','["出家侍母前，至孝自通禪。", "伏日江頭別，秋風檣下眠。", "鳥聲猿更促，石色樹相連。", "此路多如此，師行亦有緣。"]'),
('812de94c-728a-442a-9d9d-d4205fafc5f5','送陟遐上人遊天台','姚合','唐','唐诗','tang','','[]','萬疊赤城路，終年遊客稀。',48,'全唐诗/poet.tang.26000.json','["萬疊赤城路，終年遊客稀。", "朝來送師去，自覺有家非。", "石淨山光遠，雲深海色微。", "此詩成亦鄙，爲我寫巖扉。"]'),
('9c5b8bfe-a6cb-4439-b1e5-4d9ce437e7be','送盛秀才赴舉','姚合','唐','唐诗','tang','','[]','重重吳越浙江潮，刺史何門始得消。',64,'全唐诗/poet.tang.26000.json','["重重吳越浙江潮，刺史何門始得消。", "五字州人唯有此，四鄰風景合相饒。", "橘村籬落香潛度，竹寺虛空翠自飄。", "君去九衢須說我，病成疎嬾嬾趨朝。"]'),
('0a92cdec-66d7-4f87-b93f-2ec17fc1cb02','送僧貞實歸杭州天竺','姚合','唐','唐诗','tang','','[]','石橋寺裏最清涼，聞說茆庵寄上方。',64,'全唐诗/poet.tang.26000.json','["石橋寺裏最清涼，聞說茆庵寄上方。", "林外猿聲連院磬，月中潮色到禪牀。", "他生念我身何在，此世唯師性亦忘。", "九陌相逢千里別，青山重疊樹蒼蒼。"]'),
('766ab7bc-0163-490c-82c6-fbcf0d4e9c0e','送盧二弟茂才罷舉遊洛謁新相','姚合','唐','唐诗','tang','','[]','踏碎作賦筆，驅車出上京。',48,'全唐诗/poet.tang.26000.json','["踏碎作賦筆，驅車出上京。", "離筵俯岐路，四坐半公卿。", "守命貧難擲，憂身夢數驚。", "今朝赴知己，休詠苦辛行。"]'),
('77810dc3-68de-4a90-8928-7cd0c4728cea','送任畹及第歸蜀中覲親','姚合','唐','唐诗','tang','','[]','子規啼欲死，君聽固無愁。',48,'全唐诗/poet.tang.26000.json','["子規啼欲死，君聽固無愁。", "闕下聲名出，鄉中意氣遊。", "東川橫劒閣，南斗近刀州。", "神聖題前字，千人看不休。"]'),
('da961f32-7e62-429b-83f9-744b2be9958f','送杜觀罷舉東遊','姚合','唐','唐诗','tang','','[]','秋風離九陌，心事豈云安。',48,'全唐诗/poet.tang.26000.json','["秋風離九陌，心事豈云安。", "曾是求名苦，當知此去難。", "辛勤程自遠，寂寞夜多寒。", "詩句無人識，應須把劒看。"]'),
('1596fb29-0e7f-474c-a5ee-29a2953dbfa2','送狄兼謩下第歸故山','姚合','唐','唐诗','tang','','[]','慈恩塔上名，昨日敗垂成。',72,'全唐诗/poet.tang.26000.json','["慈恩塔上名，昨日敗垂成。", "賃舍應無直，居山豈釣聲。", "半年猶小隱，數日得閑行。", "映竹窺猿劇，尋雲探鶴情。", "愛花高酒戶，煮藥汙茶鐺。", "莫便多時住，煙霄路在城。"]'),
('fd3e8eee-4529-4977-bd6f-57ebca9e5201','送源中丞赴新羅','姚合','唐','唐诗','tang','','[]','赤墀賜對使殊方，官重霜臺紫綬光。',64,'全唐诗/poet.tang.26000.json','["赤墀賜對使殊方，官重霜臺紫綬光。", "玉節在船清海怪，金函開詔拜夷王。", "雲晴漸覺山川異，風便那知道路長。", "誰得似君將雨露，海東萬里灑扶桑。"]'),
('45679c83-391a-4108-b387-4eac529d0610','送陳倜赴江陵從事','姚合','唐','唐诗','tang','','[]','荆州勝事衆皆聞，幕下今朝又得君。',64,'全唐诗/poet.tang.26000.json','["荆州勝事衆皆聞，幕下今朝又得君。", "才子何須藉科第，男兒終久要功勳。", "江村竹樹多於草，山路塵埃半是雲。", "新什定知饒景思，不應一向賦從軍。"]'),
('0f4436ec-fc8a-4adf-b3af-b28356163427','送張郎中副使赴澤潞','姚合','唐','唐诗','tang','','[]','曉陌事戎裝，風流粉署郎。',48,'全唐诗/poet.tang.26000.json','["曉陌事戎裝，風流粉署郎。", "機籌通變化，除拜出尋常。", "地冷饒霜氣，山高礙雁行。", "應無離別恨，車馬自生光。"]'),
('7613cffa-2c90-4f04-b3d4-70fa58e72414','送陸暢侍御歸揚州','姚合','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','故園偏接近，霅水洞庭邊。',60,'全唐诗/poet.tang.26000.json','["故園偏接近，霅水洞庭邊。", "歸去知何日，相逢各長年。", "山川南北路，風雪別離天。", "楚色窮冬燒，淮聲獨夜船。", "從軍丞相府，談笑酒杯前。"]'),
('5cc8a024-5f9c-4d24-a31a-ed7d3b3e2ad9','送韋瑤校書赴越','姚合','唐','唐诗','tang','','[]','寄家臨禹穴，乘傳出秦關。',48,'全唐诗/poet.tang.26000.json','["寄家臨禹穴，乘傳出秦關。", "霜落橘滿地，潮來帆近山。", "相門賓益貴，水國事多閑。", "晨省高堂後，餘歡杯酒間。"]'),
('8d1ab97e-d59f-4592-a06f-590ede1f5bd4','送雍陶及第歸覲','姚合','唐','唐诗','tang','','[]','獻親冬集書，比橘復何如。',48,'全唐诗/poet.tang.26000.json','["獻親冬集書，比橘復何如。", "此去關山遠，相思笑語疎。", "路尋丹壑斷，人近白雲居。", "幽石題名處，憑君亦記余。"]'),
('4c1b6c9c-c6b1-4745-bd3f-baf885fac446','送李秀才赴舉','姚合','唐','唐诗','tang','','[]','羅剎樓頭醉，送君西入京。',48,'全唐诗/poet.tang.26000.json','["羅剎樓頭醉，送君西入京。", "秦吳無限地，山水半分程。", "海上煙霞濕，關中日月明。", "登科舊鄉里，當爲改嘉名。"]'),
('72447425-18ce-41cc-94a7-02d590d06aef','送李傳秀才歸宣州','姚合','唐','唐诗','tang','','[]','謝守青山宅，山孤宅亦平。',48,'全唐诗/poet.tang.26000.json','["謝守青山宅，山孤宅亦平。", "池塘無復見，春草野中生。", "常日登樓望，今朝送客行。", "慇懃拂石壁，爲我一書名。"]'),
('3cec999d-6330-4601-98ed-d6884ea49ef6','送元緒上人遊商山','姚合','唐','唐诗','tang','','[]','萬法空門裏，師修歷幾生。',48,'全唐诗/poet.tang.26000.json','["萬法空門裏，師修歷幾生。", "過來心已悟，未到行彌精。", "溪寂鐘還度，林昏錫獨鳴。", "朝簪抽未得，此別豈忘情。"]'),
('b5280da7-28c8-48db-a2b6-d6e95017bb25','送僧棲真歸杭州天竺寺','姚合','唐','唐诗','tang','','[]','吏事日紛然，無因到佛前。',48,'全唐诗/poet.tang.26000.json','["吏事日紛然，無因到佛前。", "勞師相借問，知我亦通禪。", "古寺杉松出，殘陽鐘磬連。", "草菴盤石上，歸此是因緣。"]'),
('db310434-bb20-4800-8dac-9fe91f641ecc','送敬法師歸福州','姚合','唐','唐诗','tang','','[]','結得隨緣伴，蟬鳴方出關。',36,'全唐诗/poet.tang.26000.json','["結得隨緣伴，蟬鳴方出關。", "新經譯舊寺，故國與誰還。", "齋爲無鐘早，心因罷講閑。"]'),
('8be2c09a-af09-4650-bffe-bb420bf74555','送清敬闍黎歸浙西','姚合','唐','唐诗','tang','','[]','大地無生理，吳中豈是歸。',48,'全唐诗/poet.tang.26000.json','["大地無生理，吳中豈是歸。", "自翻貝葉偈，人施福田衣。", "夏盡灘聲出，潮來日色微。", "郡齋師去後，寂寞夜吟稀。"]'),
('8d8b40a6-db13-4b12-a86c-27784d219d19','送賈島及鍾渾','姚合','唐','唐诗','tang','','[]','日日攻詩亦自彊，年年供應在名場。',32,'全唐诗/poet.tang.26000.json','["日日攻詩亦自彊，年年供應在名場。", "春風驛路歸何處，紫閣山邊是草堂。"]'),
('fe77cb4f-f22f-47b9-96a9-95be4d55f7b8','送僧遊邊','姚合','唐','唐诗','tang','','[]','師向邊頭去，邊人業障輕。',48,'全唐诗/poet.tang.26000.json','["師向邊頭去，邊人業障輕。", "腥羶齋自潔，部落講還成。", "傳教多離寺，隨緣不計程。", "三千世界內，何處是無生。"]'),
('96ab7efe-75a6-4d9e-a169-5f3756fb57f9','送澄江上人赴興元鄭尚書招','姚合','唐','唐诗','tang','','[]','師經非紙上，師佛在心中。',48,'全唐诗/poet.tang.26000.json','["師經非紙上，師佛在心中。", "覺路何曾異，行人自不同。", "水雲晴亦雨，山木夜多風。", "聞結西方社，尚書待遠公。"]'),
('8b17bc13-2a9a-4121-a4eb-fe88568b1d71','送馬戴下第客遊','姚合','唐','唐诗','tang','','[]','昨來送君處，亦是九衢中。',48,'全唐诗/poet.tang.26000.json','["昨來送君處，亦是九衢中。", "此日慇懃別，前時寂寞同。", "鳥啼寒食雨，花落暮春風。", "向晚離人起，筵收罇未空。"]'),
('f2505f10-aa9a-48dd-8eff-c397df6924cb','送薛二十三郎中赴婺州','姚合','唐','唐诗','tang','','[]','我住浙江西，君去浙江東。',24,'全唐诗/poet.tang.26000.json','["我住浙江西，君去浙江東。", "日日心來往，不畏浙江風。"]'),
('03756be7-c822-4907-b370-de11dc31f4ee','送獨孤煥評事赴豐州','姚合','唐','唐诗','tang','','["\u9ec4\u6cb3"]','東門攜酒送廷評，結束從軍塞上行。',64,'全唐诗/poet.tang.26000.json','["東門攜酒送廷評，結束從軍塞上行。", "深磧路移唯馬覺，斷蓬風起與鵰平。", "煙生遠戍侵雲色，冰疊黃河長雪聲。", "須鑿燕然山上石，登科記裏是閑名。"]'),
('3cc4c872-f2d4-41e4-be99-64b57db40c53','送張齊物主簿赴內鄉','姚合','唐','唐诗','tang','','[]','幾年山下事仙翁，名在長生籙籍中。',32,'全唐诗/poet.tang.26000.json','["幾年山下事仙翁，名在長生籙籍中。", "燒得藥成須寄我，曾爲主簿與君同。"]'),
('6c05ab76-ecd1-4b7e-a7df-7de3ce7498f6','送王嗣之典儀城','姚合','唐','唐诗','tang','','[]','日日思朝位，偷閑城外行。',48,'全唐诗/poet.tang.26000.json','["日日思朝位，偷閑城外行。", "唯求採藥者，不道在官名。", "好異嫌山淺，尋幽喜逕生。", "病來文字拙，不要把歸城。"]'),
('19a70179-39ee-4e60-9642-72c0cccafc07','別賈島','姚合','唐','唐诗','tang','','[]','嬾作住山人，貧家日賃身。',48,'全唐诗/poet.tang.26000.json','["嬾作住山人，貧家日賃身。", "書多筆漸重，睡少枕長新。", "野客狂無過，詩仙瘦始真。", "秋風千里去，誰與我相親。"]'),
('8aa6ba2b-7354-4d02-b0e2-44c384a2eb02','別李餘','姚合','唐','唐诗','tang','','[]','病童隨瘦馬，難算往來程。',48,'全唐诗/poet.tang.26000.json','["病童隨瘦馬，難算往來程。", "野寺僧相送，河橋酒滯行。", "足愁無道性，久客會人情。", "何計羈窮盡，同居不出城。"]'),
('2b68b954-1ec8-4912-99a0-42a2aaf4006d','別胡逸','姚合','唐','唐诗','tang','','[]','記得春闈同席試，逡巡何啻十年餘。',32,'全唐诗/poet.tang.26000.json','["記得春闈同席試，逡巡何啻十年餘。", "今日相逢又相送，予乘五馬子單車。"]'),
('eac51509-f644-4b77-b297-ac4efa638e9e','惜別','姚合','唐','唐诗','tang','','[]','酒闌歌罷更遲留，攜手思量凭翠樓。',64,'全唐诗/poet.tang.26000.json','["酒闌歌罷更遲留，攜手思量凭翠樓。", "桃李容華猶歎月，風流才器亦悲秋。", "光陰不覺朝昏過，岐路無窮早晚休。", "似把剪刀裁別恨，兩人分得一般愁。"]'),
('8206a417-7b86-4017-9668-02c3e88ce20a','欲別','姚合','唐','唐诗','tang','','[]','山川重疊遠茫茫，欲別先憂別恨長。',64,'全唐诗/poet.tang.26000.json','["山川重疊遠茫茫，欲別先憂別恨長。", "紅芍藥花雖共醉，綠蘼蕪影又分將。", "鴛鴦有路高低去，鴻雁南飛一兩行。", "惆悵與君煙景迥，不知何日到瀟湘。"]'),
('f6321999-bd88-4d39-afc4-6b8a973aa111','別杭州','姚合','唐','唐诗','tang','','[]','醉與江濤別，江濤惜我遊。',24,'全唐诗/poet.tang.26000.json','["醉與江濤別，江濤惜我遊。", "他年婚嫁了，終老此江頭。"]'),
('0e08ce19-341f-4210-a001-502ef3df6335','寄賈島','姚合','唐','唐诗','tang','','[]','漫向城中住，兒童不識錢。',48,'全唐诗/poet.tang.26000.json','["漫向城中住，兒童不識錢。", "甕頭寒絕酒，竈額曉無煙。", "狂發吟如哭，愁來坐似禪。", "新詩有幾首，旋被世人傳。"]'),
('51504f86-cf82-4bfe-b15b-b0590a5e921f','寄王度居士','姚合','唐','唐诗','tang','','[]','顦顇王居士，顛狂不稱時。',96,'全唐诗/poet.tang.26000.json','["顦顇王居士，顛狂不稱時。", "天公與貧病，時輩復輕欺。", "茅屋隨年借，盤飡逐日移。", "棄嫌官似夢，珍重酒如師。", "無竹栽蘆看，思山疊石爲。", "靜窗留客話，古寺覓僧棊。", "瘦馬寒來死，羸童餓得癡。", "唯應尋阮籍，心事遠相知。"]'),
('1364baba-e887-479b-b919-a7df80f08ae5','寄楊茂卿校書','姚合','唐','唐诗','tang','','["\u9ec4\u6cb3"]','去年別君時，同宿黎陽城。',168,'全唐诗/poet.tang.26000.json','["去年別君時，同宿黎陽城。", "黃河凍欲合，船入冰罅行。", "君爲使滑州，我來西入京。", "丈夫不泣別，旁人歎無情。", "到京就省試，落籍先有名。", "慙辱鄉薦書，忽欲自受刑。", "還家豈無路，羞爲路人輕。", "決心住城中，百敗望一成。", "腐草衆所棄，猶能化爲螢。", "豈我愚暗身，終久不發明。", "所悲道路長，親愛難合幷。", "還如舟與車，奔走各異程。", "耳目甚短狹，背面若聾盲。", "安得學白日，遠見君儀形。"]'),
('82ae8487-6295-4752-8e55-faf91b40cd92','寄杜師義','姚合','唐','唐诗','tang','','[]','出處難相見，同城似異鄉。',48,'全唐诗/poet.tang.26000.json','["出處難相見，同城似異鄉。", "點兵尋戶籍，燒藥試仙方。", "事校千般別，心還一種忙。", "黃金如化得，相寄亦何妨。"]'),
('c8244509-2da4-486d-a2b7-c7dbcdf7f302','寄陸渾縣尉李景先','姚合','唐','唐诗','tang','','[]','微俸還同請，唯君獨自閑。',48,'全唐诗/poet.tang.26000.json','["微俸還同請，唯君獨自閑。", "地偏無驛路，藥賤管仙山。", "月色生松裏，泉聲在石間。", "吟詩復飲酒，何事更相關。"]'),
('d3cb012d-7f91-426a-a9cd-b7a49a565f2d','寄酬盧侍御','姚合','唐','唐诗','tang','','[]','詩新得意恣狂疎，揮手終朝力有餘。',32,'全唐诗/poet.tang.26000.json','["詩新得意恣狂疎，揮手終朝力有餘。", "今到詩家渾手戰，欲題名字倩人書。"]'),
('bb3cc6b8-1812-4da2-884c-3ecc3a614c37','寄主客張郎中','姚合','唐','唐诗','tang','','[]','年長方慕道，金丹事參差。',96,'全唐诗/poet.tang.26000.json','["年長方慕道，金丹事參差。", "故園歸未得，秋風思難持。", "蹇拙公府棄，朴靜高人知。", "以我齊杖屨，昏旭詎相離。", "吟詩紅葉寺，對酒黃菊籬。", "所賞未及畢，後遊良有期。", "粲粲華省步，屑屑旅客姿。", "未同山中去，固當殊路岐。"]'),
('e8e3f1da-9e79-49cf-bb6d-177427f3da94','寄鄠縣尉李廓少府','姚合','唐','唐诗','tang','','[]','歲滿休爲吏，吟詩著白衣。',48,'全唐诗/poet.tang.26000.json','["歲滿休爲吏，吟詩著白衣。", "愛山閑臥久，在世此心稀。", "聽鶴向風立，捕魚乘月歸。", "比君才不及，謬得侍彤闈。"]'),
('206d18c4-7da5-4c09-9654-85bd70be90da','寄紫閣隱者','姚合','唐','唐诗','tang','','[]','自聞憔客說，無計得相尋。',48,'全唐诗/poet.tang.26000.json','["自聞憔客說，無計得相尋。", "幾世傳高臥，全家在一林。", "養情書覽苦，採藥路多深。", "願得爲鄰里，誰能說此心。"]'),
('b7df71ab-49b9-42c2-bf42-26d303dba339','寄國子楊巨源祭酒','姚合','唐','唐诗','tang','','[]','日日新詩出，城中寫不禁。',48,'全唐诗/poet.tang.26000.json','["日日新詩出，城中寫不禁。", "清高疑對竹，閑雅勝聞琴。", "門戶饒秋景，兒童解冷吟。", "雲山今作主，還借外人尋。"]'),
('182d305a-5d79-48bb-905d-ea5f13c4e0b0','寄永樂長官殷堯藩','姚合','唐','唐诗','tang','','[]','故人爲吏隱，高臥簿書間。',48,'全唐诗/poet.tang.26000.json','["故人爲吏隱，高臥簿書間。", "遶院唯栽藥，逢僧只說山。", "此宵歡不接，窮歲信空還。", "何計相尋去，嚴風雪滿關。"]'),
('4bda0066-2ee8-495b-ba9d-a19d76c7c7f2','冬夜書事寄兩省閣老','姚合','唐','唐诗','tang','','[]','天寒漸覺雁聲疎，新月微微玉漏初。',64,'全唐诗/poet.tang.26000.json','["天寒漸覺雁聲疎，新月微微玉漏初。", "海嶠只宜今日去，故鄉已過十年餘。", "髮稀豈易勝玄冕，眼暗應難寫諫書。", "閣下羣公盡高思，誰能攜酒訪貧居。"]'),
('805a0fa8-63a4-4dc7-add4-86cc015b0ce4','寄靈一律師','姚合','唐','唐诗','tang','','[]','梵書鈔律千餘紙，淨院焚香獨受持。',32,'全唐诗/poet.tang.26000.json','["梵書鈔律千餘紙，淨院焚香獨受持。", "童子病來煙火絕，清泉漱口過齋時。"]'),
('dba42230-764f-4b2b-b3bb-7992f1ec6bf7','郡中書事寄默然上人','姚合','唐','唐诗','tang','','[]','郡中饒野興，過客亦淹留。',48,'全唐诗/poet.tang.26000.json','["郡中饒野興，過客亦淹留。", "看月江樓曉，尋山石徑秋。", "意歸何處老，誰免此生愁。", "長愛東林子，安禪百事休。"]'),
('1c318cad-b468-4f49-bd1e-b6a866694863','寄張徯','姚合','唐','唐诗','tang','','[]','幽處尋書坐，朝朝閉竹扉。',48,'全唐诗/poet.tang.26000.json','["幽處尋書坐，朝朝閉竹扉。", "山僧封茗寄，野客乞詩歸。", "秋卷多唯好，時名屈更肥。", "明年取前字，杯酒賽春輝。"]'),
('6425ac6e-95fe-4741-ab8f-1b722310d980','寄李頻','姚合','唐','唐诗','tang','','[]','閉門常不出，惟覺長庭莎。',48,'全唐诗/poet.tang.26000.json','["閉門常不出，惟覺長庭莎。", "朋友來看少，詩書臥讀多。", "命隨才共薄，愁與醉相和。", "珍重君名字，新登甲乙科。"]'),
('038c4215-406a-4ab0-86e0-7ab65ff9a2a3','寄李羣玉','姚合','唐','唐诗','tang','','[]','九衢名與利，無計擾閑人。',72,'全唐诗/poet.tang.26000.json','["九衢名與利，無計擾閑人。", "道遠期輕世，才高貴重身。", "石脂稀勝乳，玉粉細於塵。", "骨換肌膚膩，心靈氣色真。", "嵩山高到日，洛水煖如春。", "居住應安穩，黃金幾竈新。"]'),
('f4cd7026-0071-4b41-b1ea-84cfaa539275','病中書事寄友人','姚合','唐','唐诗','tang','','[]','終日自纏繞，此身無適緣。',72,'全唐诗/poet.tang.26000.json','["終日自纏繞，此身無適緣。", "萬愁生雨夜，百病凑衰年。", "多睡憎明屋，慵行待暖天。", "瘡頭梳有蝨，風耳亂無蟬。", "換白方多錯，迴金法不全。", "家貧何所怨，將在老僧邊。"]'),
('dc485459-58ab-4fb2-9bf9-72da65e1a128','九日寄錢可復','姚合','唐','唐诗','tang','','[]','數盃黃菊酒，千里白雲天。',48,'全唐诗/poet.tang.26000.json','["數盃黃菊酒，千里白雲天。", "上國名方振，戎州病未痊。", "靜愁惟憶醉，閑走不勝眠。", "惆悵東門別，相逢知幾年。"]'),
('58bb88d7-ce0e-47b8-9be7-407d950fef0e','春日早朝寄劉起居','姚合','唐','唐诗','tang','','[]','九衢寒霧歛，雙闕曙光分。',48,'全唐诗/poet.tang.26000.json','["九衢寒霧歛，雙闕曙光分。", "綵杖迎春日，香煙接瑞雲。", "珮聲清漏間，天語侍臣聞。", "莫笑馮唐老，還來謁聖君。"]'),
('8bf872f0-27fb-4770-8c31-60953b3dc8fe','秋日寄李支使','姚合','唐','唐诗','tang','','[]','秋思朝來起，侵人暑稍微。',48,'全唐诗/poet.tang.26000.json','["秋思朝來起，侵人暑稍微。", "曉眠離北戶，午飯尚生衣。", "山靜雲初白，枝高果漸稀。", "聞君家海上，莫與燕同歸。"]'),
('72d8bf4c-1fc9-46d3-aae2-4ccbf522ba7e','寄汴州令狐楚相公','姚合','唐','唐诗','tang','','[]','汴水從今不復渾，秋風鼙鼓動城根。',64,'全唐诗/poet.tang.26000.json','["汴水從今不復渾，秋風鼙鼓動城根。", "梁園臺館關東少，相府旌旗天下尊。", "詩好四方誰敢和，政成三郡自無冤。", "幾時詔下歸丹闕，還領千官入閤門。"]'),
('76638c65-4efd-41bf-a2b2-aa3dbb7953aa','寄東都分司白賓客','姚合','唐','唐诗','tang','','[]','闕下高眠過十旬，南宮印綬乞離身。',64,'全唐诗/poet.tang.26000.json','["闕下高眠過十旬，南宮印綬乞離身。", "詩中得意應千首，海內嫌官只一人。", "賓客分司真是隱，山泉遶宅豈辭貧。", "竹齋晚起多無事，唯到龍門寺裏頻。"]'),
('260f2655-f59b-4456-b12d-6bff439e5acc','寄裴起居','姚合','唐','唐诗','tang','','[]','千官曉立鑪煙裏，立近丹墀是起居。',32,'全唐诗/poet.tang.26000.json','["千官曉立鑪煙裏，立近丹墀是起居。", "彩筆專書皇帝語，書成幾卷太平書。"]'),
('2c1cd3bb-1cbf-42dc-84c8-e561f63ee132','寄狄拾遺時爲魏州從事','姚合','唐','唐诗','tang','','[]','少在兵馬間，長還繫戎職。',144,'全唐诗/poet.tang.26000.json','["少在兵馬間，長還繫戎職。", "雞飛不得遠，豈要生羽翼。", "三年城中遊，與君最相識。", "應知我中腸，不苟念衣食。", "主人樹勳名，欲滅天下賊。", "愚雖乏智謀，願陳一夫力。", "人生須氣健，飢凍縛不得。", "睡當一席寬，覺乃千里窄。", "古人不懼死，所懼死無益。", "至交不可合，一合難離坼。", "君嘗相勸勉，苦語毒胸臆。", "百年心知同，誰限河南北。"]'),
('48046781-6ad6-407d-9f39-b4d6d3d0c21c','金州書事寄山中舊友','姚合','唐','唐诗','tang','','[]','安康雖好郡，刺史是憨翁。',120,'全唐诗/poet.tang.26000.json','["安康雖好郡，刺史是憨翁。", "買酒終朝飲，吟詩一室空。", "自知爲政拙，衆亦覺心公。", "親事星河在，憂人骨肉同。", "簿書嵐色裡，鼓角水聲中。", "井邑神州接，帆檣海路通。", "野亭晴帶霧，竹寺夏多風。", "溉稻長洲白，燒林遠岫紅。", "舊山期已失，芳草思何窮。", "林下無相笑，男兒五馬雄。"]'),
('c4ff255a-e82f-4474-8742-043ef63928a8','寄紫閣無名頭陀','姚合','唐','唐诗','tang','','[]','峭行得如如，誰分聖與愚。',48,'全唐诗/poet.tang.26000.json','["峭行得如如，誰分聖與愚。", "不眠知夢妄，無號免人呼。", "山海禪皆遍，華夷佛豈殊。", "何因接師話，清淨在斯須。"]'),
('18535822-283e-4e41-b6b1-890b90bec410','寄郁上人','姚合','唐','唐诗','tang','','[]','此生修道淺，愁見未來身。',48,'全唐诗/poet.tang.26000.json','["此生修道淺，愁見未來身。", "誰爲傳真諦，唯應是上人。", "自悲年已長，漸覺事難親。", "不向禪門去，他門無了因。"]'),
('bec98897-2a6e-4043-9412-5310716c1192','寄孫路秀才','姚合','唐','唐诗','tang','','[]','幽居鄰里少，江際復山阿。',48,'全唐诗/poet.tang.26000.json','["幽居鄰里少，江際復山阿。", "潮去蟬聲出，天晴鶴語多。", "老人能步蹇，才子奈貧何。", "曾見春官語，年來虛甲科。"]'),
('9eb374c0-5e1d-48a3-8a93-71054e927b42','寄安陸友人','姚合','唐','唐诗','tang','','[]','別路在春色，故人雲夢中。',48,'全唐诗/poet.tang.26000.json','["別路在春色，故人雲夢中。", "鳥啼三月雨，蝶舞百花風。", "煙束遠山碧，霞欹落照紅。", "想君登此興，迴首念飄蓬。"]'),
('e1eb8cf0-d0b4-4a15-b39b-0d26f74ad791','寄馬戴','姚合','唐','唐诗','tang','','[]','天府鹿鳴客，幽山秋未歸。',48,'全唐诗/poet.tang.26000.json','["天府鹿鳴客，幽山秋未歸。", "我知方甚愛，衆說以爲非。", "隔屋聞泉細，和雲見鶴微。", "新詩此處得，清峭比應稀。"]'),
('420a1dad-65ea-418e-ae2b-2302ba655b15','寄賈島時任普州司倉','姚合','唐','唐诗','tang','','[]','長沙事可悲，普掾罪誰知。',48,'全唐诗/poet.tang.26000.json','["長沙事可悲，普掾罪誰知。", "千載人空盡，一家冤不移。", "吟寒應齒落，才峭自名垂。", "地遠山重疊，難傳相憶詞。"]'),
('7ec47936-39eb-4d96-903c-963aa7a62854','寄楊工部聞毘陵舍弟自罨溪入茶山','姚合','唐','唐诗','tang','','[]','採茶溪路好，花影半浮沈。',72,'全唐诗/poet.tang.26000.json','["採茶溪路好，花影半浮沈。", "畫舸僧同上，春山客共尋。", "芳新生石際，幽嫩在山陰。", "色是春光染，香驚日氣侵。", "試嘗應酒醒，封進定恩深。", "芳貽千里外，怡怡太府吟。"]'),
('edd28ed2-fdff-4314-afca-96d3c04b56dc','寄陝州王司馬','姚合','唐','唐诗','tang','','[]','家寄秦城非本心，偶然頭上有朝簪。',64,'全唐诗/poet.tang.26000.json','["家寄秦城非本心，偶然頭上有朝簪。", "自當臺直無因醉，一別詩宗更嬾吟。", "世事每將愁見擾，年光唯與老相侵。", "欲知居處堪長久，須向山中學煮金。"]'),
('06721120-774c-453c-935a-376e2f62cbff','寄賈島','姚合','唐','唐诗','tang','','[]','寂寞荒原下，南山祗隔籬。',48,'全唐诗/poet.tang.26000.json','["寂寞荒原下，南山祗隔籬。", "家貧唯我並，詩好復誰知。", "草色無窮處，蟲聲少盡時。", "朝昏鼓不到，閑臥益相宜。"]'),
('11108560-73be-4dc3-aabb-d4011ffdd69d','寄崔之仁山人','姚合','唐','唐诗','tang','','[]','百門坡上住，石屋兩三間。',48,'全唐诗/poet.tang.26000.json','["百門坡上住，石屋兩三間。", "日月難教老，妻兒乞與閑。", "仙經揀客問，藥債煮金還。", "何計能相訪，終身得在山。"]'),
('4529393b-d298-48ac-9d81-0539fd356008','寄嵩嶽程光範','姚合','唐','唐诗','tang','','[]','相別何容易，相逢便歲年。',48,'全唐诗/poet.tang.26000.json','["相別何容易，相逢便歲年。", "客來嫌路遠，誰得到君邊。", "岳色鳥啼裏，鐘聲竹影前。", "只應訪支遁，時得話詩篇。"]'),
('2024f7ba-c7d3-4a57-abe4-4d64ca219ad6','洛下夜會寄賈島','姚合','唐','唐诗','tang','','[]','洛下攻詩客，相逢祗是吟。',48,'全唐诗/poet.tang.26000.json','["洛下攻詩客，相逢祗是吟。", "夜觴歡稍靜，寒屋坐多深。", "烏府偶爲吏，滄江長在心。", "憶君難就寢，燭滅復星沈。"]'),
('9f21d32f-408c-4a18-89d8-ef40ed7cdab6','寄華州李中丞','姚合','唐','唐诗','tang','','[]','毛女峰前郡，煙霞氣轉清。',96,'全唐诗/poet.tang.26000.json','["毛女峰前郡，煙霞氣轉清。", "庭分靈掌影，窗度瀑泉聲。", "蘚逕人稀到，松齋藥自生。", "常飡亦芝朮，閑客是公卿。", "看水逢仙鶴，登樓見帝城。", "養生非酒病，難隱是詩名。", "省署嘗連步，江臯欲獨耕。", "偶題無六義，聊以達微誠。"]'),
('ea783731-e342-41f5-b894-a2a72a5dad63','病中辱諫議惠甘菊藥苗因以詩贈','姚合','唐','唐诗','tang','','[]','蕭蕭一畝宮，種菊十餘叢。',48,'全唐诗/poet.tang.26000.json','["蕭蕭一畝宮，種菊十餘叢。", "採摘和芳露，封題寄病翁。", "熟宜茶鼎裏，飡稱石甌中。", "香潔將何比，從來味不同。"]'),
('8cd6f19f-b61a-43e6-8d8b-85e5f12c15e0','舟行書事寄杭州崔員外','姚合','唐','唐诗','tang','','[]','張頤任酒澆，開眼信花燒。',48,'全唐诗/poet.tang.26000.json','["張頤任酒澆，開眼信花燒。", "舊國歸何滯，新知別又遙。", "夜行篙觸石，晚泊纜依橋。", "若未重相見，無門解寂寥。"]'),
('d68728fb-baa6-43be-a895-c5addefc7126','寄元緒上人','姚合','唐','唐诗','tang','','[]','石窗紫蘚牆，此世此清涼。',48,'全唐诗/poet.tang.26000.json','["石窗紫蘚牆，此世此清涼。", "研露題詩潔，消冰煮茗香。", "閑雲春影薄，孤磬夜聲長。", "何計休爲吏，從師老草堂。"]'),
('ce4a1be1-8a2b-4564-bb6d-0419d638298f','寄白閣默然','姚合','唐','唐诗','tang','','[]','白閣峰頭雪，城中望亦寒。',48,'全唐诗/poet.tang.26000.json','["白閣峰頭雪，城中望亦寒。", "高僧多默坐，清夜到明看。", "世上無諸苦，林間只一飡。", "嘗聞南北教，所得比師難。"]'),
('638069e4-36ef-4406-91a2-b4c33a983ca0','夏日書事寄丘亢處士','姚合','唐','唐诗','tang','','[]','暑天難可度，豈復更持觴。',48,'全唐诗/poet.tang.26000.json','["暑天難可度，豈復更持觴。", "樹裏鳴蟬咽，宮中午漏長。", "病夫心益躁，靜者室應涼。", "幾欲相尋去，紅塵滿路旁。"]'),
('08873d76-93f7-4c46-945f-8b65939c9ba9','秋中寄崔道士','姚合','唐','唐诗','tang','','[]','貧居雀喧噪，況乃靜巷陌。',120,'全唐诗/poet.tang.26000.json','["貧居雀喧噪，況乃靜巷陌。", "夜眠睡不成，空庭聞露滴。", "旁有一桮酒，歡然如對客。", "月光久逾明，照得筆墨白。", "平生志舒豁，難可似茲夕。", "四肢得自便，雖勞不爲役。", "故人山中住，善治活身策。", "五穀口不嘗，比僧更閑寂。", "我今暫得安，自謂脫幽戚。", "君身長逍遙，日月爭老得。"]'),
('9f180d24-de06-4b4b-b98f-67aca6d65beb','寄華州崔中丞','姚合','唐','唐诗','tang','','[]','蓮華峰下郡，僊洞亦難勝。',48,'全唐诗/poet.tang.26000.json','["蓮華峰下郡，僊洞亦難勝。", "閭里蒼苔水，虛空瀑布冰。", "酒香和藥熟，山峭過雲登。", "清淨黎人泰，唯憂急詔徵。"]'),
('6a021036-cb53-42be-a11e-e5b8548a1d8a','秋日書事寄祕書竇少監','姚合','唐','唐诗','tang','','[]','秋氣日騷騷，星星雙鬢毛。',48,'全唐诗/poet.tang.26000.json','["秋氣日騷騷，星星雙鬢毛。", "涼天吟自遠，清夜夢還高。", "林下期同去，人間共是勞。", "頭巾何所直，且漉甕頭糟。"]'),
('43270fbe-9d0d-4f6b-9205-7f8563a0bd81','友人南遊不回因寄','姚合','唐','唐诗','tang','','[]','相思春樹綠，千里亦依依。',48,'全唐诗/poet.tang.26000.json','["相思春樹綠，千里亦依依。", "鄠杜月頻滿，瀟湘人不歸。", "桂花風畔落，煙草蝶雙飛。", "一別無消息，水南車跡稀。"]'),
('931a6272-dd3b-4923-8a21-97f6237fde87','早春山居寄城中知己','姚合','唐','唐诗','tang','','[]','陽和潛發蕩寒陰，便使川原景象深。',64,'全唐诗/poet.tang.26000.json','["陽和潛發蕩寒陰，便使川原景象深。", "入戶風泉聲瀝瀝，當軒雲岫影沈沈。", "殘雲帶雨輕飄雪，嫩柳含煙小綻金。", "雖有眼前詩酒興，邀遊爭得稱閑心。"]'),
('abd9d4c1-1561-41fb-bdd6-34fb4e7d58a0','辭白賓客歸後寄','姚合','唐','唐诗','tang','','[]','千騎紅旗不可攀，水頭獨立暮方還。',32,'全唐诗/poet.tang.26000.json','["千騎紅旗不可攀，水頭獨立暮方還。", "家人怪我渾如病，尊酒休傾筆硯間。"]'),
('9afcdc93-1771-450f-8d8c-087a7d52eee1','寄右史李定言','姚合','唐','唐诗','tang','','[]','纔歸龍尾含雞舌，更立螭頭運兔毫。',32,'全唐诗/poet.tang.26000.json','["纔歸龍尾含雞舌，更立螭頭運兔毫。", "閶闔欲開金漏盡，冕旒初坐御香高。"]'),
('d210bc9b-2d9b-4f61-b9b4-3b96eefbb9aa','寄絳州李使君','姚合','唐','唐诗','tang','','[]','獨施清靜化，千里管橫汾。',72,'全唐诗/poet.tang.26000.json','["獨施清靜化，千里管橫汾。", "黎庶應深感，朝庭亦細聞。", "心期在黃老，家事是功勳。", "物外須仙侶，人間要使君。", "花多勻地落，山近滿廳雲。", "戎客無因去，西看白日曛。"]'),
('8a2b62c2-e2e3-494a-a833-f7a1a99acfcc','寄送盧拱秘書遊魏州','姚合','唐','唐诗','tang','','[]','太行山下路，荆棘昨來平。',96,'全唐诗/poet.tang.26000.json','["太行山下路，荆棘昨來平。", "一自開元後，今逢上客行。", "地形吞北虜，人事接東京。", "埽灑氛埃靜，遊從氣概生。", "薊門春不豔，淇水煖還清。", "看野風情遠，尋花酒病成。", "官閑身自在，詩逸語縱橫。", "車馬迴應晚，煙光滿去程。"]'),
('e014b570-1a3e-4ebd-b5f0-e1b05a702e5b','秋晚夜坐寄院中諸曹長','姚合','唐','唐诗','tang','','[]','腰間垂印囊，白髮未歸鄉。',48,'全唐诗/poet.tang.26000.json','["腰間垂印囊，白髮未歸鄉。", "還往應相責，朝昏亦自傷。", "窮愁山影峭，獨夜漏聲長。", "寂寞難成寐，寒燈侵曉光。"]'),
('665bec6a-03ae-4da9-b0dc-51ea016cbb77','書懷寄友人','姚合','唐','唐诗','tang','','[]','精心奉北宗，微宦在南宮。',72,'全唐诗/poet.tang.26000.json','["精心奉北宗，微宦在南宮。", "舉世勞爲適，開門事不窮。", "年來復幾日，蟬去又鳴鴻。", "衰疾誰人問，閑情與酒通。", "四鄰寒稍靜，九陌夜方空。", "知老何山是，思歸愚谷中。"]'),
('d8de8ee4-24a1-4e0f-a028-5823c02cd009','寄無可上人','姚合','唐','唐诗','tang','','[]','十二門中寺，詩僧寺獨幽。',48,'全唐诗/poet.tang.26000.json','["十二門中寺，詩僧寺獨幽。", "多年松色別，後夜磬聲秋。", "見世慮皆盡，來生事更修。", "終須執瓶鉢，相逐入牛頭。"]'),
('4b2ad007-739b-4f49-82ea-3041d230f520','寄暉上人','姚合','唐','唐诗','tang','','[]','日出月復沒，悠悠昏與明。',48,'全唐诗/poet.tang.26000.json','["日出月復沒，悠悠昏與明。", "修持經幾劫，清淨到今生。", "林下知無相，人間苦是情。", "終期逐師去，不擬老塵纓。"]'),
('cd099b26-a618-4b54-9fa1-aa0b07e42410','寄李干','姚合','唐','唐诗','tang','','[]','尋常自怪詩無味，雖被人吟不喜聞。',32,'全唐诗/poet.tang.26000.json','["尋常自怪詩無味，雖被人吟不喜聞。", "見說與君同一格，數篇到火却休焚。"]'),
('c7767dc8-6d15-41ee-83d5-6cd92ba52954','寄賈島浪仙','姚合','唐','唐诗','tang','','[]','悄悄掩門扉，窮窘自維縶。',144,'全唐诗/poet.tang.26000.json','["悄悄掩門扉，窮窘自維縶。", "世途已昧履，生計復乖緝。", "疎我非常性，端峭爾孤立。", "往還縱云久，貧蹇豈自習。", "所居率荒野，寧似在京邑。", "院落夕彌空，蟲聲雁相及。", "衣巾半僧施，蔬藥常自拾。", "凜凜寢席單，翳翳竈煙濕。", "頹籬里人度，敗壁鄰燈入。", "曉思已暫舒，暮愁還更集。", "風淒林葉萎，苔糝行徑澀。", "海嶠誓同歸，橡栗充朝給。"]'),
('4fec0dc6-d776-4771-be95-86674aaaa645','寄九華費冠卿','姚合','唐','唐诗','tang','','[]','逍遙[罾]繳外，高鳥與潛魚。',62,'全唐诗/poet.tang.26000.json','["逍遙[罾]繳外，高鳥與潛魚。", "闕下無朝籍，林間有詔書。", "夜眠青玉洞，曉飯白雲蔬。", "四海人空老，九華君獨居。", "此心誰復識，日與世情疎。"]'),
('305580ee-d8de-4c2a-8dbd-8dece64a6ddc','寄不疑上人','姚合','唐','唐诗','tang','','[]','是法修行遍，方棲不二門。',48,'全唐诗/poet.tang.26000.json','["是法修行遍，方棲不二門。", "隨緣嫌寺著，見性覺經繁。", "所歎身將老，始聞師一言。", "塵沙千萬劫，劫盡佛長存。"]'),
('b9845ba4-5fb1-4245-a952-e73bc9e18a60','寄主客劉郎中','姚合','唐','唐诗','tang','','[]','漢朝共許賈生賢，遷謫還應是宿緣。',64,'全唐诗/poet.tang.26000.json','["漢朝共許賈生賢，遷謫還應是宿緣。", "仰德多時方會面，拜兄何暇更論年。", "嵩山晴色來城裏，洛水寒光出岸邊。", "清景早朝吟麗思，題詩應費益州牋。"]'),
('276b2bc3-6f3b-417c-8afc-e6ae993922e2','寄周十七起居','姚合','唐','唐诗','tang','','[]','鼕鼕九陌鼓聲齊，百辟朝天馬亂嘶。',64,'全唐诗/poet.tang.26000.json','["鼕鼕九陌鼓聲齊，百辟朝天馬亂嘶。", "月照濃霜寒更遠，風吹紅燭舉還低。", "官清立在金鑪北，仗下歸眠玉殿西。", "莫笑老人多獨出，晴山荒景覓詩題。"]'),
('4c4bbf1a-a0e4-4ea9-9c25-1dc3571b8f14','秋夜寄默然上人','姚合','唐','唐诗','tang','','[]','霜月靜幽居，閑吟夢覺初。',48,'全唐诗/poet.tang.26000.json','["霜月靜幽居，閑吟夢覺初。", "秋深夜迢遰，年長意蕭疎。", "海上歸難遂，人間事盡虛。", "賴師方便語，漸得識真如。"]'),
('ba14b348-f052-4198-9d3d-d5fcb223b5d9','寄王玄伯','姚合','唐','唐诗','tang','','[]','夜歸曉出滿衣塵，轉覺才名帶累身。',32,'全唐诗/poet.tang.26000.json','["夜歸曉出滿衣塵，轉覺才名帶累身。", "莫覓舊來終日醉，世間盃酒屬閑人。"]'),
('043b07d3-0e5b-4663-a0b0-d8202700c504','寄山中友人','姚合','唐','唐诗','tang','','[]','昨秋今復春，役役是非身。',48,'全唐诗/poet.tang.26000.json','["昨秋今復春，役役是非身。", "海上無歸路，城中作老人。", "流年何處在，白日每朝新。", "聞有長生術，將求未有因。"]'),
('903ca896-71a8-494d-865e-e9ea39a912f5','寄陝府內兄郭冏端公','姚合','唐','唐诗','tang','','[]','蹇鈍無大計，酷嗜進士名。',240,'全唐诗/poet.tang.26000.json','["蹇鈍無大計，酷嗜進士名。", "爲文性不高，三年住西京。", "相府執文柄，念其心專精。", "薄藝不退辱，特列爲門生。", "事出自非意，喜常少於驚。", "春牓四散飛，數日徧八紘。", "眼始見花發，耳得聞鳥鳴。", "免同去年春，兀兀聾與盲。", "家寄河朔間，道路出陝城。", "暌違逾十年，一會豁素誠。", "同游山水窮，狂飲飛大觥。", "起坐不相離，有若親弟兄。", "中外無親疎，所算在其情。", "久客貴優饒，一醉舊疾平。", "家遠歸思切，風雨甚亦行。", "到茲戀仁賢，淹滯一月程。", "新詩忽見示，氣逸言縱橫。", "纏緜意千里，騷雅文發明。", "永晝吟不休，咽喉乾無聲。", "羈貧重金玉，今日金玉輕。"]'),
('26d9b08b-8f42-47b1-89fa-884390d01ad1','寄題蔡州蔣亭兼簡田使君','姚合','唐','唐诗','tang','','[]','幾歲亂軍裏，蔣亭名不銷。',48,'全唐诗/poet.tang.26000.json','["幾歲亂軍裏，蔣亭名不銷。", "無人知舊徑，有藥長新苗。", "樹宿山禽靜，池通野水遙。", "何因同此醉，永望思蕭條。"]'),
('58017abf-5aae-407c-84ef-14b2a12c2c77','山居寄友人','姚合','唐','唐诗','tang','','[]','獨在山阿裏，朝朝遂性情。',48,'全唐诗/poet.tang.26000.json','["獨在山阿裏，朝朝遂性情。", "曉泉和雨落，秋草上堦生。", "因客始沽酒，借書方到城。", "詩情聊自遣，不是趁聲名。"]'),
('020e8b00-6b2c-4e0d-995a-197c7d7bcb01','寄崔之仁山人','姚合','唐','唐诗','tang','','[]','不得之仁消息久，秋來體色復何如。',64,'全唐诗/poet.tang.26000.json','["不得之仁消息久，秋來體色復何如。", "苦將杯酒判身病，狂作文章信手書。", "官職卑微從客笑，性靈閑野向錢疎。", "幾時身計渾無事，揀取深山一處居。"]'),
('eebb7886-2e91-4e2d-88e0-43821d2d4d20','寄主客劉員外','姚合','唐','唐诗','tang','','[]','蟬稀蟲唧唧，露重思悠悠。',48,'全唐诗/poet.tang.26000.json','["蟬稀蟲唧唧，露重思悠悠。", "靜者多便夜，豪家不見秋。", "同歸方欲就，微恙幾時瘳。", "今日滄江上，何人理釣舟。"]'),
('d091fa9b-f194-4096-ae49-8c159c9724bd','山中寄友人','姚合','唐','唐诗','tang','','[]','路岐何渺邈，在客易蹉跎。',48,'全唐诗/poet.tang.26000.json','["路岐何渺邈，在客易蹉跎。", "却是去家遠，因循住日多。", "幾看春草綠，又見塞鴻過。", "未有進身處，忍教拋薜蘿。"]'),
('b88960bb-299e-4e47-a043-2cbdc654b528','寄友人','姚合','唐','唐诗','tang','','[]','日暮掩重扉，抽簪復解衣。',48,'全唐诗/poet.tang.26000.json','["日暮掩重扉，抽簪復解衣。", "漏聲林下靜，螢色月中微。", "秋霽露華結，夜深人語稀。", "慇懃故山路，誰與我同歸。"]'),
('3f0928b7-9b6b-4cae-ac15-001ec1b2cd1f','寄李餘臥疾','姚合','唐','唐诗','tang','','[]','窮節彌慘慄，我詎自云樂。',72,'全唐诗/poet.tang.26000.json','["窮節彌慘慄，我詎自云樂。", "伊人嬰疾恙，所對唯苦藥。", "寂寞行稍稀，清羸飡自薄。", "幽齋外浮事，夢寐亦簡略。", "雪戶掩復明，風簾卷還落。", "方持數桮酒，勉子同斟酌。"]'),
('eedaf711-5cf8-4bda-aa6a-c66492d6b89e','寄白石師','姚合','唐','唐诗','tang','','[]','白石師何在，師禪白石中。',48,'全唐诗/poet.tang.26000.json','["白石師何在，師禪白石中。", "無情雲可比，不食鳥難同。", "屨下蒼苔雪，龕前瀑布風。", "相尋未有計，只是禮虛空。"]'),
('c0cac011-4262-4af5-aa17-bb9e5c237f7e','寄賈島','姚合','唐','唐诗','tang','','[]','疎拙祗如此，此身誰與同。',48,'全唐诗/poet.tang.26000.json','["疎拙祗如此，此身誰與同。", "高情向酒上，無事在山中。", "漸老病難理，久貧吟益空。", "賴君時訪宿，不避北齋風。"]'),
('26b125e2-18f6-4400-bb11-d680c48a1193','寄默然上人','姚合','唐','唐诗','tang','','[]','晨飡夜復眠，日與月相連。',48,'全唐诗/poet.tang.26000.json','["晨飡夜復眠，日與月相連。", "天下誰無病，人間樂是禪。", "幾生通佛性，一室但香煙。", "結得無爲社，還應有宿緣。"]'),
('609da49d-27ba-4a48-b00a-2ab30953838d','寄不出院僧','姚合','唐','唐诗','tang','','[]','不行門外地，齋戒得清真。',48,'全唐诗/poet.tang.26000.json','["不行門外地，齋戒得清真。", "長食施來飯，深居鎖定身。", "朝昏常傍佛，起坐省逢人。", "非獨心常淨，衣無一點塵。"]'),
('f6c186d2-a1fa-43fa-93af-83db5544eaae','萬年縣中雨夜會宿寄皇甫甸','姚合','唐','唐诗','tang','','[]','縣齋還寂寞，夕雨洗蒼苔。',48,'全唐诗/poet.tang.26000.json','["縣齋還寂寞，夕雨洗蒼苔。", "清氣燈微潤，寒聲竹共來。", "蟲移上階近，客起到門迴。", "想得吟詩處，唯應對酒杯。"]'),
('12fb0ad1-ffeb-4872-a26c-6bd68946192d','寄舊山隱者','姚合','唐','唐诗','tang','','[]','別君須臾間，曆日兩度新。',168,'全唐诗/poet.tang.26000.json','["別君須臾間，曆日兩度新。", "念彼白日長，復值人事并。", "未改當時居，心事如野雲。", "朝朝恣行坐，百事都不聞。", "奈何道未盡，出山最艱辛。", "奔走衢路間，四枝不屬身。", "名在進士場，筆毫爭等倫。", "我性本朴直，詞理安得文。", "縱然自稱心，又不合衆人。", "以此名字低，不如風中塵。", "昨逢賣藥客，云是居山鄰。", "說君憶我心，顦顇其形神。", "昔是同枝鳥，今作萬里分。", "萬里亦未遙，喧靜終難羣。"]'),
('157ac10c-9fe3-46d9-aec2-681255c88a39','新居秋夕寄李廓','姚合','唐','唐诗','tang','','[]','羈滯多共趣，屢屢同室眠。',120,'全唐诗/poet.tang.26000.json','["羈滯多共趣，屢屢同室眠。", "稍暇更訪詣，寧唯候招延。", "媿君備蔬藥，識我性所便。", "罷吏童僕去，灑掃或自專。", "古巷人易息，疎迥自江邊。", "幸當中秋夕，復此無雲天。", "月華更漏清，露葉光彩鮮。", "四鄰亦悄悄，中懷益纏綿。", "茲境罕能致，居閑得彌偏。", "數杯罷復飲，共想山中年。"]'),
('cc4f6ab9-d6dd-497c-b8fc-9acbc1672c04','贈盧大夫將軍','姚合','唐','唐诗','tang','','[]','將軍身在城，詎得虜塵清。',72,'全唐诗/poet.tang.26000.json','["將軍身在城，詎得虜塵清。", "釀酒邀閑客，吟詩直禁營。", "蒼鷹春不下，戰馬夜空鳴。", "碣石應無業，皇州獨有名。", "上山嫌䯗重，拔劒歎衣生。", "公議今如此，登壇到即行。"]'),
('dc381daa-6cbf-47be-a5aa-6a6cf77f493c','贈供奉僧次融','姚合','唐','唐诗','tang','','[]','會解如來意，僧家獨有君。',48,'全唐诗/poet.tang.26000.json','["會解如來意，僧家獨有君。", "開經對天子，騎馬過聲聞。", "本寺遠於日，新詩高似雲。", "熱時吟一句，涼冷勝秋分。"]'),
('e51d0724-a849-469b-8558-e869a3ce35a6','贈王尊師','姚合','唐','唐诗','tang','','[]','先生自說瀛洲路，多在青松白石間。',64,'全唐诗/poet.tang.26000.json','["先生自說瀛洲路，多在青松白石間。", "海岸夜中常見日，仙宮深處却無山。", "犬隨鶴去遊諸洞，龍作人來問大還。", "今日偶聞塵外事，朝簪未擲復何顏。"]'),
('1bb16200-bbfa-4b67-a093-dc9d59ff0e7b','贈常州院僧','姚合','唐','唐诗','tang','','[]','一住毘陵寺，師應祗信緣。',48,'全唐诗/poet.tang.26000.json','["一住毘陵寺，師應祗信緣。", "院貧人施食，窗靜鳥窺禪。", "古磬聲難盡，秋燈色更鮮。", "仍聞開講日，湖上少魚船。"]'),
('a0d76d64-03bf-45c9-83b5-1bd82b93b684','贈盧沙彌小師','姚合','唐','唐诗','tang','','[]','怕見世間事，削頭披佛衣。',120,'全唐诗/poet.tang.26000.json','["怕見世間事，削頭披佛衣。", "年小未受戒，會解如老師。", "天與出家腸，一食齋不飢。", "麻履踏雪路，與馬不肯騎。", "嫌我身腥羶，似我見戎夷。", "彼此見會異，對面成別離。", "我師文宣王，立教垂書詩。", "但全仁義心，自然便慈悲。", "兩教大體同，無處辨是非。", "莫以衣服別，到頭不相知。"]'),
('2c03c521-514b-4ed5-ade4-b57f322116e1','贈張籍太祝','姚合','唐','唐诗','tang','','[]','絕妙江南曲，淒涼怨女詩。',120,'全唐诗/poet.tang.26000.json','["絕妙江南曲，淒涼怨女詩。", "古風無手敵，新語是人知。", "飛動應由格，功夫過却奇。", "麟臺添集卷，樂府換歌詞。", "李白應先拜，劉禎必自疑。", "貧須君子救，病合國家醫。", "野客開山借，鄰僧與米炊。", "甘貧辭聘幣，依選受官資。", "多見愁連曉，稀聞債盡時。", "聖朝文物盛，太祝獨低眉。"]'),
('de87b80e-0013-4620-86a1-cf63b2f72a40','贈丘郎中','姚合','唐','唐诗','tang','','[]','繞籬栽杏種黃精，曉侍罏煙暮出城。',32,'全唐诗/poet.tang.26000.json','["繞籬栽杏種黃精，曉侍罏煙暮出城。", "萬事將身求總易，學君難得是長生。"]'),
('1dfe241a-82f4-4923-b31b-67d5be063240','贈王建司馬','姚合','唐','唐诗','tang','','[]','久向空門隱，交親亦不知。',48,'全唐诗/poet.tang.26000.json','["久向空門隱，交親亦不知。", "文高輕古意，官冷似前資。", "老覺僧齋健，貧還酒債遲。", "仙方小字寫，行坐把相隨。"]'),
('aa938026-f70d-446e-a604-a3861206d377','贈任士曹','姚合','唐','唐诗','tang','','[]','憲皇十一祀，共得春闈書。',48,'全唐诗/poet.tang.26000.json','["憲皇十一祀，共得春闈書。", "道直淹曹掾，命通侍玉除。", "浮生年月促，九陌笑言疎。", "何計同歸去，滄江有弊廬。"]'),
('74b99c4c-b943-4e6e-9246-6cf53654ad94','贈劉[叉]','姚合','唐','唐诗','tang','','[]','自君離海上，垂釣更何人。',48,'全唐诗/poet.tang.26000.json','["自君離海上，垂釣更何人。", "獨宿空堂雨，閑行九陌塵。", "避時曾變姓，救難似嫌身。", "何處相期宿，咸陽酒市春。"]'),
('efe59883-f5c0-42e0-8b53-79b93ca97eac','贈僧紹明','姚合','唐','唐诗','tang','','[]','西方清淨路，此路出何門。',48,'全唐诗/poet.tang.26000.json','["西方清淨路，此路出何門。", "見說師知處，從來佛不言。", "今生多病惱，自曉至黃昏。", "唯寐方無事，那堪夢亦喧。"]'),
('e222b9c5-02f4-46cf-92d2-4e0727067cae','贈張質山人','姚合','唐','唐诗','tang','','[]','先生居處僻，荆棘與牆齊。',48,'全唐诗/poet.tang.26000.json','["先生居處僻，荆棘與牆齊。", "酒好寧論價，詩狂不著題。", "燒成度世藥，踏盡上山梯。", "嬾聽閑人語，爭如谷鳥啼。"]'),
('9f1d4b8f-ccab-43d9-9b70-491956c6b5c8','贈少室山麻襦僧','姚合','唐','唐诗','tang','','[]','秖辮麻爲衲，此中經幾春。',48,'全唐诗/poet.tang.26000.json','["秖辮麻爲衲，此中經幾春。", "菴前多猛獸，徑小絕行人。", "泉近濆瓶履，山深少垢塵。", "想師正法指，喻我獨迷津。"]'),
('fa3ae6e7-69b8-4033-babc-78175bb58233','贈王山人','姚合','唐','唐诗','tang','','[]','賢哲論獨誕，吾宗次定今。',48,'全唐诗/poet.tang.26000.json','["賢哲論獨誕，吾宗次定今。", "詩吟天地廣，覺印果因深。", "教演歸恭敬，名標中外欽。", "既能施六度，了悟達雙林。"]'),
('4ff27137-bd97-4748-a262-1d8272fdcff7','贈終南山傅山人','姚合','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','七十未成事，終南蒼鬢翁。',96,'全唐诗/poet.tang.26000.json','["七十未成事，終南蒼鬢翁。", "老來詩興苦，貧去酒腸空。", "蟠蟄身仍病，鵬摶力未通。", "已無燒藥本，唯有著書功。", "白馬時何晚，青龍歲欲終。", "生涯枯葉下，家口亂雲中。", "潭靜魚驚水，天晴鶴唳風。", "悲君還姓傅，獨不夢高宗。"]'),
('9fe41b72-30c1-43cf-8158-21c78cae1f8d','使兩浙贈羅隱','姚合','唐','唐诗','tang','','[]','平日時風好涕流，讒書雖盛一名休。',64,'全唐诗/poet.tang.26000.json','["平日時風好涕流，讒書雖盛一名休。", "寰區歎屈瞻天問，夷貊聞詩過海求。", "向夕便思青瑣拜，近年尋伴赤松遊。", "何當世祖從人望，早以公台命卓侯。"]'),
('a8aad9d5-e7e7-4a68-9b5e-2f12210e75f6','閑居遣懷十首 一','姚合','唐','唐诗','tang','','[]','身外無徭役，開門百事閑。',48,'全唐诗/poet.tang.26000.json','["身外無徭役，開門百事閑。", "倚松聽唳鶴，策杖望秋山。", "萍任連池綠，苔從匝地斑。", "料無車馬客，何必掃柴關。"]'),
('eef80cd9-9d08-4e94-b4a9-2ba1330843b0','閑居遣懷十首 二','姚合','唐','唐诗','tang','','[]','閑臥銷長日，親朋笑我疎。',48,'全唐诗/poet.tang.26000.json','["閑臥銷長日，親朋笑我疎。", "詩篇隨分有，人事度年無。", "情性僻難改，愁懷酒爲除。", "誰能思此計，空備滿牀書。"]'),
('b549457b-ddd0-4ee8-a61d-930ba15da82f','閑居遣懷十首 三','姚合','唐','唐诗','tang','','[]','白日逍遙過，看山復遶池。',48,'全唐诗/poet.tang.26000.json','["白日逍遙過，看山復遶池。", "展書尋古事，翻卷改新詩。", "賒酒風前酌，留僧竹裏棊。", "同人笑相問，羨我足閑時。"]'),
('39f286ec-dfce-4ab9-87d0-8cef09ff4ad5','閑居遣懷十首 四','姚合','唐','唐诗','tang','','[]','好景時牽目，茅齋興有餘。',48,'全唐诗/poet.tang.26000.json','["好景時牽目，茅齋興有餘。", "遠山經雨後，庭樹得秋初。", "道侶憐栽藥，高人笑養魚。", "優游隨本性，甘被棄慵疎。"]'),
('e6757612-397f-4fd8-bb63-980f9a72ad41','閑居遣懷十首 五','姚合','唐','唐诗','tang','','[]','永日廚煙絕，何曾暫廢吟。',48,'全唐诗/poet.tang.26000.json','["永日廚煙絕，何曾暫廢吟。", "閑時隨思緝，小酒恣情斟。", "看月嫌松密，垂綸愛水深。", "世間多少事，無事可關心。"]'),
('a0ff0aed-dbbf-4b35-b768-ec8eb563fe86','閑居遣懷十首 六','姚合','唐','唐诗','tang','','[]','一生能幾日，愁恨也無端。',48,'全唐诗/poet.tang.26000.json','["一生能幾日，愁恨也無端。", "遇酒酕醄飲，逢花爛熳看。", "青雲非失路，白髮未相干。", "以此多攜解，將心但自寬。"]'),
('4d189158-a8eb-4655-a2fe-59927177bf78','閑居遣懷十首 七','姚合','唐','唐诗','tang','','[]','萬事徒紛擾，難關枕上身。',48,'全唐诗/poet.tang.26000.json','["萬事徒紛擾，難關枕上身。", "朗吟銷白日，沈醉度青春。", "演步憐山近，閑眠厭客頻。", "市朝曾不到，長免滿衣塵。"]'),
('049d4910-8f4d-4a21-803f-f2690ba6df06','閑居遣懷十首 八','姚合','唐','唐诗','tang','','[]','野性多疎惰，幽棲更稱情。',48,'全唐诗/poet.tang.26000.json','["野性多疎惰，幽棲更稱情。", "獨行看影笑，閑坐弄琴聲。", "嬾拜腰肢硬，慵趨禮樂生。", "業文隨日遣，不是爲求名。"]'),
('8934a6c4-4d68-4223-b35e-881c6812c187','閑居遣懷十首 九','姚合','唐','唐诗','tang','','[]','生計甘寥落，高名愧自由。',48,'全唐诗/poet.tang.26000.json','["生計甘寥落，高名愧自由。", "慣無身外事，不信世間愁。", "好酒盈桮酌，閑詩任筆酬。", "涼風從入戶，雲水更宜秋。"]'),
('3bde6535-14ef-49f1-a1c2-701911881930','閑居遣懷十首 十','姚合','唐','唐诗','tang','','[]','拙直難和洽，從人笑掩關。',48,'全唐诗/poet.tang.26000.json','["拙直難和洽，從人笑掩關。", "不能行戶外，寧解走塵間。", "被酒長酣思，無愁可上顏。", "何言歸去事，著處是青山。"]'),
('f32809ee-c967-4d39-844b-20fe2e76ab31','武功縣中作三十首 一','姚合','唐','唐诗','tang','','[]','縣去帝城遠，爲官與隱齊。',48,'全唐诗/poet.tang.26000.json','["縣去帝城遠，爲官與隱齊。", "馬隨山鹿放，雞雜野禽棲。", "遶舍惟藤架，侵堦是藥畦。", "更師嵇叔夜，不擬作書題。"]'),
('3daf629e-a7a5-49a0-80a8-10c88a2e83f9','武功縣中作三十首 二','姚合','唐','唐诗','tang','','[]','方拙天然性，爲官是事疎。',48,'全唐诗/poet.tang.26000.json','["方拙天然性，爲官是事疎。", "惟尋向山路，不寄入城書。", "因病多收藥，緣飡學釣魚。", "養身成好事，此外更空虛。"]'),
('e33579c8-c35a-4a17-a56d-8b4cb5556a76','武功縣中作三十首 三','姚合','唐','唐诗','tang','','[]','微官如馬足，祗是在泥塵。',48,'全唐诗/poet.tang.26000.json','["微官如馬足，祗是在泥塵。", "到處貧隨我，終年老趁人。", "簿書銷眼力，桮酒耗心神。", "早作歸休計，深居養此身。"]'),
('724567ce-d327-4eb1-9c02-c13b56304b35','武功縣中作三十首 四','姚合','唐','唐诗','tang','','[]','簿書多不會，薄俸亦難銷。',48,'全唐诗/poet.tang.26000.json','["簿書多不會，薄俸亦難銷。", "醉臥慵開眼，閑行嬾繫腰。", "移花兼蝶至，買石得雲饒。", "且自心中樂，從他笑寂寥。"]'),
('2f25299c-e19e-4409-a27e-290e4aef43bb','武功縣中作三十首 五','姚合','唐','唐诗','tang','','[]','曉鐘驚睡覺，事事便相關。',48,'全唐诗/poet.tang.26000.json','["曉鐘驚睡覺，事事便相關。", "小市柴薪貴，貧家砧杵閑。", "讀書多旋忘，賒酒數空還。", "長羨劉伶輩，高眠出世間。"]'),
('53c954d0-e805-4ea3-b4a6-4d0bfb1507f4','武功縣中作三十首 六','姚合','唐','唐诗','tang','','[]','性疎常愛臥，親故笑悠悠。',48,'全唐诗/poet.tang.26000.json','["性疎常愛臥，親故笑悠悠。", "縱出多攜枕，因衙始裹頭。", "上山方覺老，過寺暫忘愁。", "三考千餘日，低腰不擬休。"]'),
('1b150d02-1fdf-4b49-8605-2fb3de508e70','武功縣中作三十首 七','姚合','唐','唐诗','tang','','[]','客至皆相笑，詩書滿臥牀。',48,'全唐诗/poet.tang.26000.json','["客至皆相笑，詩書滿臥牀。", "愛閑求病假，因醉棄官方。", "鬢髮寒唯短，衣衫瘦漸長。", "自嫌多檢束，不似舊來狂。"]'),
('4db16628-99cb-4bb9-bfa7-445415f7dd86','武功縣中作三十首 八','姚合','唐','唐诗','tang','','[]','一日看除目，終年損道心。',48,'全唐诗/poet.tang.26000.json','["一日看除目，終年損道心。", "山亦衝雪上，詩好帶風吟。", "野客嫌知印，家人笑買琴。", "只應隨分過，已是錯彌深。"]'),
('f528eb9a-65e7-4355-a633-93974fa82a59','武功縣中作三十首 九','姚合','唐','唐诗','tang','','[]','鄰里皆相愛，門開數見過。',48,'全唐诗/poet.tang.26000.json','["鄰里皆相愛，門開數見過。", "秋涼送客遠，夜靜詠詩多。", "就架題書目，尋欄記藥窠。", "到官無別事，種得滿庭莎。"]'),
('4997a55a-783e-4ba4-bb90-c06dc69e27ce','武功縣中作三十首 十','姚合','唐','唐诗','tang','','[]','窮達天應與，人間事莫論。',48,'全唐诗/poet.tang.26000.json','["窮達天應與，人間事莫論。", "微官長似客，遠縣豈勝村。", "竟日多無食，連宵不閉門。", "齋心調筆硯，唯寫五千言。"]'),
('82b7bf34-f3d2-4fa9-be92-54621dd07153','武功縣中作三十首 十一','姚合','唐','唐诗','tang','','[]','縣僻仍牢落，遊人到便迴。',48,'全唐诗/poet.tang.26000.json','["縣僻仍牢落，遊人到便迴。", "路當邊地去，村入郭門來。", "酒戶愁偏長，詩情病不開。", "可曾衙小吏，恐謂踏青苔。"]'),
('3f5c647e-f304-49c3-9bc8-710974a6fc22','武功縣中作三十首 十二','姚合','唐','唐诗','tang','','[]','自下青山路，三年著綠衣。',48,'全唐诗/poet.tang.26000.json','["自下青山路，三年著綠衣。", "官卑食肉僭，才短事人非。", "野客教長醉，高僧勸早歸。", "不知何計是，免與本心違。"]'),
('3c08f293-4f17-4f5b-bbe6-931893186181','武功縣中作三十首 十三','姚合','唐','唐诗','tang','','[]','日出方能起，庭前看種莎。',50,'全唐诗/poet.tang.26000.json','["日出方能起，庭前看種莎。", "吏來山鳥散，酒熟野人過。", "岐路荒城少，煙霞遠岫多。", "同官數相引，下馬上西[坡]。"]'),
('6e12e1a1-f9f2-4be4-8481-ff03bd51da73','武功縣中作三十首 十四','姚合','唐','唐诗','tang','','[]','作吏荒城裏，窮愁欲不勝。',48,'全唐诗/poet.tang.26000.json','["作吏荒城裏，窮愁欲不勝。", "病多唯識藥，年老漸親僧。", "夢覺空堂月，詩成滿硯冰。", "故人多得路，寂寞不相稱。"]'),
('054a6402-670b-4133-9514-298cc1ac656d','武功縣中作三十首 十五','姚合','唐','唐诗','tang','','[]','誰念東山客，棲棲守印牀。',48,'全唐诗/poet.tang.26000.json','["誰念東山客，棲棲守印牀。", "何年得事盡，終日逐人忙。", "醉臥誰知呌，閑書不著行。", "人間長檢束，與此豈相當。"]'),
('35114297-2f49-4893-9ae9-3e3735825643','武功縣中作三十首 十六','姚合','唐','唐诗','tang','','[]','朝朝眉不展，多病怕逢迎。',48,'全唐诗/poet.tang.26000.json','["朝朝眉不展，多病怕逢迎。", "引水遠通澗，壘山高過城。", "秋燈照樹色，寒雨落池聲。", "好是吟詩夜，披衣坐到明。"]'),
('a134c0cf-6992-4f91-8f8e-4b690525327e','武功縣中作三十首 十七','姚合','唐','唐诗','tang','','[]','簿籍誰能問，風寒趁早眠。',48,'全唐诗/poet.tang.26000.json','["簿籍誰能問，風寒趁早眠。", "每旬常乞假，隔月探支錢。", "還往嫌詩僻，親情怪酒顛。", "謀身須上計，終久是歸田。"]'),
('4d554bdc-1d9b-432b-b59c-0e2b25b98d4d','武功縣中作三十首 十八','姚合','唐','唐诗','tang','','[]','閉門風雨裏，落葉與堦齊。',48,'全唐诗/poet.tang.26000.json','["閉門風雨裏，落葉與堦齊。", "野客嫌桮小，山翁喜枕低。", "聽琴知道性，尋藥得詩題。", "誰更能騎馬，閑行祗杖藜。"]'),
('62de7e73-92a5-4c2d-90cc-7caaf2f45037','武功縣中作三十首 十九','姚合','唐','唐诗','tang','','[]','腥羶都不食，稍稍覺神清。',48,'全唐诗/poet.tang.26000.json','["腥羶都不食，稍稍覺神清。", "夜犬因風吠，鄰雞帶雨鳴。", "守官常臥病，學道別稱名。", "小有洞中路，誰能引我行。"]'),
('9efe4657-6cce-45e7-bc8d-2e04e26c6709','武功縣中作三十首 二十','姚合','唐','唐诗','tang','','[]','宦名渾不計，酒熟且開封。',48,'全唐诗/poet.tang.26000.json','["宦名渾不計，酒熟且開封。", "晴月銷燈色，寒天挫筆鋒。", "驚禽時並起，閑客數相逢。", "舊國蕭條思，青山隔幾重。"]'),
('4d519d79-53d0-484a-aea3-15feb2056a0a','武功縣中作三十首 二十一','姚合','唐','唐诗','tang','','[]','假日多無事，誰知我獨忙。',48,'全唐诗/poet.tang.26000.json','["假日多無事，誰知我獨忙。", "移山入縣宅，種竹上城牆。", "驚蝶遺花蘂，遊蜂帶蜜香。", "唯愁明早出，端坐吏人旁。"]'),
('7ca1b788-18c1-4bb2-990f-2b928cefe3f1','武功縣中作三十首 二十二','姚合','唐','唐诗','tang','','[]','門外青山路，因循自不歸。',48,'全唐诗/poet.tang.26000.json','["門外青山路，因循自不歸。", "養生宜縣僻，說品喜官微。", "淨愛山僧飯，閑披野客衣。", "誰憐幽谷鳥，不解入城飛。"]'),
('afb371ff-eb47-4a8a-b213-b5534444c706','武功縣中作三十首 二十三','姚合','唐','唐诗','tang','','[]','一官無限日，愁悶欲何如。',48,'全唐诗/poet.tang.26000.json','["一官無限日，愁悶欲何如。", "掃舍驚巢燕，尋方落壁魚。", "從僧乞淨水，憑客報閑書。", "白髮誰能鑷，年來四十餘。"]'),
('31f8a3b1-f884-44a8-96a3-c2f5590a4fee','武功縣中作三十首 二十四','姚合','唐','唐诗','tang','','[]','朝朝門不閉，長似在山時。',48,'全唐诗/poet.tang.26000.json','["朝朝門不閉，長似在山時。", "賓客抽書讀，兒童斫竹騎。", "久貧還易老，多病嬾能醫。", "道友應相怪，休官日已遲。"]'),
('c2d6e090-3115-414a-b6f9-b431a8010807','武功縣中作三十首 二十五','姚合','唐','唐诗','tang','','[]','戚戚常無思，循資格上官。',48,'全唐诗/poet.tang.26000.json','["戚戚常無思，循資格上官。", "閑人得事晚，常骨覓仙難。", "醉臥疑身病，貧居覺道寬。", "新詩久不寫，自算少人看。"]'),
('221f76d4-58dd-40a2-a47b-02e254b29d41','武功縣中作三十首 二十六','姚合','唐','唐诗','tang','','[]','漫作容身計，今知拙有餘。',48,'全唐诗/poet.tang.26000.json','["漫作容身計，今知拙有餘。", "青衫迎驛使，白髮憶山居。", "道友憐蔬食，吏人嫌草書。", "須爲長久事，歸去自耕鋤。"]'),
('97dff714-c0e6-4e5d-8ba0-fa97d2d70fd1','武功縣中作三十首 二十七','姚合','唐','唐诗','tang','','[]','主印三年坐，山居百事休。',48,'全唐诗/poet.tang.26000.json','["主印三年坐，山居百事休。", "焚香開敕庫，踏月上城樓。", "飲酒多成病，吟詩易長愁。", "慇懃問漁者，暫借手中鉤。"]'),
('b90d6572-7281-451e-ba7a-1dc8d80f7c63','武功縣中作三十首 二十八','姚合','唐','唐诗','tang','','[]','長憶青山下，深居遂性情。',48,'全唐诗/poet.tang.26000.json','["長憶青山下，深居遂性情。", "壘堦溪石淨，燒竹竈煙輕。", "點筆圖雲勢，彈琴學鳥聲。", "今朝知縣印，夢裏百憂生。"]'),
('bd1ba69b-8cae-46e7-9a04-ea15876b2423','武功縣中作三十首 二十九','姚合','唐','唐诗','tang','','[]','自知狂僻性，吏事固相疎。',48,'全唐诗/poet.tang.26000.json','["自知狂僻性，吏事固相疎。", "祗是看山立，無嫌出縣居。", "印朱霑墨硯，戶籍雜經書。", "月俸尋常請，無妨乏斗儲。"]'),
('1825b558-ae53-4a49-a611-359592280833','武功縣中作三十首 三十','姚合','唐','唐诗','tang','','[]','作吏無能事，爲文舊致功。',48,'全唐诗/poet.tang.26000.json','["作吏無能事，爲文舊致功。", "詩標八病外，心落百憂中。", "拜別登朝客，歸依鍊藥翁。", "不知還往內，誰與此心同。"]'),
('a0e1cf33-21a8-4c25-82c2-5fc7d8511d87','罷武功縣將入城 一','姚合','唐','唐诗','tang','','[]','乍拋衫笏覺身輕，依舊還稱學道名。',64,'全唐诗/poet.tang.26000.json','["乍拋衫笏覺身輕，依舊還稱學道名。", "欲泥山僧分屋住，羞從野老借牛耕。", "妻兒盡怕爲逋客，親故相邀遣到城。", "無奈同官珍重意，幾迴臨路却休行。"]'),
('b7393b62-ec95-468a-9327-1a38ffad55ca','罷武功縣將入城 二','姚合','唐','唐诗','tang','','[]','青衫脫下便狂歌，種薤栽莎斸古坡。',64,'全唐诗/poet.tang.26000.json','["青衫脫下便狂歌，種薤栽莎斸古坡。", "野客相逢添酒病，春山暫上著詩魔。", "亦知官罷貧還甚，且喜閑來睡得多。", "欲與九衢親故別，明朝拄杖始經過。"]'),
('3eec77ea-2e2f-4e0e-acc2-33945543a903','秋日閑居二首 一','姚合','唐','唐诗','tang','','[]','九陌宅重重，何門憐此翁。',48,'全唐诗/poet.tang.26000.json','["九陌宅重重，何門憐此翁。", "荒庭唯菊茂，幽徑與山通。", "落葉帶衣上，閑雲來酒中。", "此心誰得見，林下鹿應同。"]'),
('3a60b5d6-a07f-4827-84fe-a8afab5fff65','秋日閑居二首 二','姚合','唐','唐诗','tang','','[]','先憶花時節，家山聽更歸。',48,'全唐诗/poet.tang.26000.json','["先憶花時節，家山聽更歸。", "愛詩看古集，憶酒典寒衣。", "睡少身還健，愁多食不肥。", "自憐疎嬾性，無事出門稀。"]'),
('6e129b82-8127-4efa-a701-f6d8e95071c3','閑居晚夏','姚合','唐','唐诗','tang','','[]','閑居無事擾，舊病亦多痊。',48,'全唐诗/poet.tang.26000.json','["閑居無事擾，舊病亦多痊。", "選字詩中老，看山屋外眠。", "片霞侵落日，繁葉咽鳴蟬。", "對此心還樂，誰知乏酒錢。"]'),
('a0f8e495-6176-4dc8-b686-2f565c2d3a72','閑居','姚合','唐','唐诗','tang','','[]','不自識疎鄙，終年住在城。',48,'全唐诗/poet.tang.26000.json','["不自識疎鄙，終年住在城。", "過門無馬跡，滿宅是蟬聲。", "帶病吟雖苦，休官夢已清。", "何當學禪觀，依止古先生。"]'),
('1463253c-20b4-40c9-812f-e1f24a7df344','街西居三首 一','姚合','唐','唐诗','tang','','[]','受得山野性，住城多事違。',72,'全唐诗/poet.tang.26000.json','["受得山野性，住城多事違。", "青山在宅南，迴首東西稀。", "淺淺一井泉，數家同汲之。", "獨我惡水濁，鑿井庭之陲。", "自鑿還自飲，亦爲衆所非。", "吁嗟世間事，潔身誠難爲。"]'),
('0e2c86a8-ceaa-433e-846a-57c4dbfbc758','街西居三首 二','姚合','唐','唐诗','tang','','[]','日出窮巷喜，溫然勝重衣。',36,'全唐诗/poet.tang.26000.json','["日出窮巷喜，溫然勝重衣。", "重衣豈不煖，所煖人不齊。", "兀兀復行行，不離階與墀。"]'),
('a8363aee-f771-4d54-9eb8-402f2330aca3','街西居三首 三','姚合','唐','唐诗','tang','','[]','丈夫非馬蹄，安得知路岐。',36,'全唐诗/poet.tang.26000.json','["丈夫非馬蹄，安得知路岐。", "窮賤飱茹薄，興與養性宜。", "乃知長生術，豪貴難得之。"]'),
('75896b6e-2de4-493c-b741-b91e35725243','閑居遣興','姚合','唐','唐诗','tang','','[]','終年城裏住，門戶似山林。',48,'全唐诗/poet.tang.26000.json','["終年城裏住，門戶似山林。", "客怪身名晚，妻嫌酒病深。", "寫方多識藥，失譜廢彈琴。", "文字非經濟，空虛用破心。"]'),
('cbea30b5-8e8c-452a-9209-cebf8ded2f4a','莊居即事','姚合','唐','唐诗','tang','','[]','休看小字大書名，向日持經眼却明。',64,'全唐诗/poet.tang.26000.json','["休看小字大書名，向日持經眼却明。", "時過無心求富貴，身閑不夢見公卿。", "因尋岳寺葷辛斷，自到王城禮數生。", "斜月照牀新睡覺，西風半夜鶴來聲。"]'),
('4579c7a8-dcae-497a-abc4-4c19651c1494','親仁里居','姚合','唐','唐诗','tang','','[]','三年賃舍親仁里，寂寞何曾似在城。',64,'全唐诗/poet.tang.26000.json','["三年賃舍親仁里，寂寞何曾似在城。", "飲酒自緣防冷病，尋人多是爲閑行。", "軒車無路通門巷，親友因詩道姓名。", "自別青山歸未得，羨君長聽石泉聲。"]'),
('78edb327-b375-4dda-8ede-071486af5ec0','莊居野行','姚合','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u540c\u60c5", "\u519c\u6c11"]','客行野田間，此屋皆閉戶。',120,'全唐诗/poet.tang.26000.json','["客行野田間，此屋皆閉戶。", "借問屋中人，盡去作商賈。", "官家不稅商，稅農服作苦。", "居人盡東西，道路侵壠畝。", "採玉上山顛，探珠入水府。", "邊兵索衣食，此物同泥土。", "古來一人耕，三人食猶飢。", "如今千萬家，無一把鋤犂。", "我倉常空虛，我田生蒺藜。", "上天不雨粟，何由活烝黎。"]'),
('6563d3fe-2b18-455b-a2a7-9e295926dc58','春日閑居','姚合','唐','唐诗','tang','','[]','居止日蕭條，庭前唯藥苗。',48,'全唐诗/poet.tang.26000.json','["居止日蕭條，庭前唯藥苗。", "身閑眠自久，眼荖視還遙。", "簷燕酬鶯語，鄰花雜絮飄。", "客來無酒飲，搔首擲空瓢。"]'),
('ebac63ea-29fc-4e6a-84e4-cb4291fd2031','獨居','姚合','唐','唐诗','tang','','[]','深閉柴門長不出，功夫自課少閑時。',64,'全唐诗/poet.tang.26000.json','["深閉柴門長不出，功夫自課少閑時。", "翻音免問他人字，覆局何勞對手棊。", "生計如雲無定所，窮愁似影每相隨。", "到頭歸向青山是，塵路茫茫欲告誰。"]'),
('c2e17874-14ab-45bd-88c1-f06a74eb9b59','早春閑居','姚合','唐','唐诗','tang','','[]','寂寞日何爲，閑居春色遲。',48,'全唐诗/poet.tang.26000.json','["寂寞日何爲，閑居春色遲。", "驚風起庭雪，寒雨長簷澌。", "強飲樽中酒，嘲山世外詩。", "此生仍且在，難與老相離。"]'),
('e580517c-479a-45dd-a898-554815b0e82e','原上新居','姚合','唐','唐诗','tang','','[]','秋來梨果熟，行哭小兒飢。',48,'全唐诗/poet.tang.26000.json','["秋來梨果熟，行哭小兒飢。", "鄰富雞長往，莊貧客漸稀。", "借牛耕地晚，賣樹納錢遲。", "牆下當官道，依前夾竹籬。"]'),
('3abea4a2-82e9-46bf-8d32-8d6466dfc256','將歸山','姚合','唐','唐诗','tang','','[]','野人慣去山中住，自到城來悶不勝。',64,'全唐诗/poet.tang.26000.json','["野人慣去山中住，自到城來悶不勝。", "宮樹蟬聲多却樂，侯門月色少於燈。", "飢來唯擬重餐藥，歸去還應只別僧。", "聞道舊溪茆屋畔，春風新上數枝藤。"]'),
('26b2e549-ffd0-473d-afe8-01aab3de950e','山中述懷','姚合','唐','唐诗','tang','','[]','爲客久未歸，寒山獨掩扉。',48,'全唐诗/poet.tang.26000.json','["爲客久未歸，寒山獨掩扉。", "曉來山鳥散，雨過杏花稀。", "天遠雲空積，溪深水自微。", "此情對春色，盡醉欲忘機。"]'),
('f6118331-0103-4cde-80ef-7d5409fc5994','偶然書懷','姚合','唐','唐诗','tang','','[]','十年通籍入金門，自媿名微枉搢紳。',64,'全唐诗/poet.tang.26000.json','["十年通籍入金門，自媿名微枉搢紳。", "鍊得丹砂疑不食，從茲白髮日相親。", "家山迢遰歸無路，桮酒稀疎病到身。", "漢有馮唐唐有我，老爲郎吏更何人。"]'),
('fb9d2e33-7cf4-4f08-a22f-0c1bd8975109','客舍有懷','姚合','唐','唐诗','tang','','[]','旅人無事喜，終日思悠悠。',48,'全唐诗/poet.tang.26000.json','["旅人無事喜，終日思悠悠。", "逢酒嫌桮淺，尋書怕字稠。", "貧來許錢聖，夢覺見身愁。", "寂寞中林下，飢鷹望到秋。"]'),
('17df8354-71b5-471d-a2b0-daad31f67827','及第後夜中書事','姚合','唐','唐诗','tang','','[]','夜睡常驚起，春光屬野夫。',72,'全唐诗/poet.tang.26000.json','["夜睡常驚起，春光屬野夫。", "新銜添一字，舊友遜前途。", "喜過還疑夢，狂來不似儒。", "愛花持燭看，憶酒犯街沽。", "天上名應定，人間盛更無。", "報恩丞相閤，何啻殺微軀。"]'),
('113eb3c3-8bba-4cd0-b01b-5b326e72ca78','偶題','姚合','唐','唐诗','tang','','[]','年年九陌看春還，舊隱空勞夢寐間。',64,'全唐诗/poet.tang.26000.json','["年年九陌看春還，舊隱空勞夢寐間。", "遲日逍遙芸草長，聖朝清淨諫臣閑。", "偶逢遊客同傾酒，自有前騶恥見山。", "道侶書來相責誚，朝朝欲報作何顏。"]'),
('b21d59e1-ba45-46c0-a0fc-6cb2058f2a8b','感時','姚合','唐','唐诗','tang','','[]','憶昔未出身，索寞無精神。',72,'全唐诗/poet.tang.26000.json','["憶昔未出身，索寞無精神。", "逢人話天命，自賤如埃塵。", "君今纔出身，颯爽鞍馬春。", "逢人話天命，自重如千鈞。", "信涉名利道，舉動皆喪真。", "君今自世情，何況天下人。"]'),
('7a965764-42dc-4c62-bb34-cf363044610c','憶山','姚合','唐','唐诗','tang','','[]','閑處無人到，乖疎稱野情。',48,'全唐诗/poet.tang.26000.json','["閑處無人到，乖疎稱野情。", "日高搔首起，林下散衣行。", "泉引窗前過，雲看石罅生。", "別來愁欲老，虛負出山名。"]'),
('83290594-cd48-47f1-9326-3253bef72aaf','客遊旅懷','姚合','唐','唐诗','tang','','[]','客行無定止，終日路岐間。',48,'全唐诗/poet.tang.26000.json','["客行無定止，終日路岐間。", "馬爲賒來貴，僮緣借得頑。", "詩書愁觸雨，店舍喜逢山。", "舊業嵩陽下，三年未得還。"]'),
('733d55ae-562b-4cfd-be0e-903eb86c258a','迎春','姚合','唐','唐诗','tang','','[]','半年留醉待花開，曉去迎春夜始迴。',64,'全唐诗/poet.tang.26000.json','["半年留醉待花開，曉去迎春夜始迴。", "風煖慢行尋曲水，天晴遠望立高臺。", "亦知無處將詩請，唯得終朝把酒催。", "今日柳條全弄色，遊人相伴看春來。"]'),
('1ef429d5-f656-412a-b651-920636c45daa','遊春十二首 一','姚合','唐','唐诗','tang','','[]','正月一日後，尋春更不眠。',48,'全唐诗/poet.tang.26000.json','["正月一日後，尋春更不眠。", "自知還近僻，衆說過於顛。", "看水寧依路，登山欲到天。", "悠悠芳思起，多是晚風前。"]'),
('8a041708-e49b-4452-8dbb-e52c7b5399b0','遊春十二首 二','姚合','唐','唐诗','tang','','[]','官卑長少事，縣僻又無城。',48,'全唐诗/poet.tang.26000.json','["官卑長少事，縣僻又無城。", "未曉衝寒起，迎春忍病行。", "樹枝風掉軟，菜甲土浮輕。", "好箇林間鵲，今朝足喜聲。"]'),
('afa75ea5-54a0-481a-a2e9-0d3c5dd365f1','遊春十二首 三','姚合','唐','唐诗','tang','','[]','詩酒相牽引，朝朝思不窮。',48,'全唐诗/poet.tang.26000.json','["詩酒相牽引，朝朝思不窮。", "苔痕雪水裏，春色竹煙中。", "迎雨緣池草，摧花倚樹風。", "書非名利事，愛此少人同。"]'),
('63385b23-3104-4f1b-9d3e-97393c432971','遊春十二首 四','姚合','唐','唐诗','tang','','[]','塵中主印吏，誰遣有高情。',48,'全唐诗/poet.tang.26000.json','["塵中主印吏，誰遣有高情。", "趁煖簷前坐，尋芳樹底行。", "土融凝墅色，冰敗滿池聲。", "漸覺春相泥，朝來睡不輕。"]'),
('a650e50f-4efe-4ce0-84d5-25e908ce9eb9','遊春十二首 五','姚合','唐','唐诗','tang','','[]','疎頑無異事，隨例但添年。',48,'全唐诗/poet.tang.26000.json','["疎頑無異事，隨例但添年。", "舊曆藏深篋，新衣薄絮綿。", "暖風渾酒色，晴日暢琴弦。", "同伴無辭困，遊春貴在先。"]'),
('f6020926-c0b1-4b0b-ab7e-24017c54b9c9','遊春十二首 六','姚合','唐','唐诗','tang','','[]','看春長不足，豈更覺身勞。',48,'全唐诗/poet.tang.26000.json','["看春長不足，豈更覺身勞。", "寺裏花枝淨，山中水色高。", "嫩雲輕似絮，新草細如毛。", "併起詩人思，還應費筆毫。"]'),
('7c62a954-ab02-4a02-aa6c-5e037a4bae1c','遊春十二首 七','姚合','唐','唐诗','tang','','[]','悠悠小縣吏，顦顇入新年。',48,'全唐诗/poet.tang.26000.json','["悠悠小縣吏，顦顇入新年。", "遠思遭詩惱，閑情被酒牽。", "戀花林下飲，愛草野中眠。", "疎嬾今成性，誰人肯更憐。"]'),
('8a58a614-17c5-466a-957e-ff337062d218','遊春十二首 八','姚合','唐','唐诗','tang','','[]','處處春光遍，遊人亦不稀。',48,'全唐诗/poet.tang.26000.json','["處處春光遍，遊人亦不稀。", "向陽傾冷酒，看影試新衣。", "嫩樹行移長，幽禽語旋飛。", "同來皆去盡，衝夜獨吟歸。"]'),
('50ca9831-47ce-4abe-b8a5-de350bdfd94a','遊春十二首 九','姚合','唐','唐诗','tang','','[]','朝朝看春色，春色似相憐。',48,'全唐诗/poet.tang.26000.json','["朝朝看春色，春色似相憐。", "酒醒鶯啼裏，詩成蝶舞前。", "摘花盈手露，折竹滿庭煙。", "親故多相笑，疎狂似少年。"]'),
('3b9a1107-1f79-40dd-81c2-32fbcdc0b7cb','遊春十二首 十','姚合','唐','唐诗','tang','','[]','卑官還不惡，行止得逍遙。',48,'全唐诗/poet.tang.26000.json','["卑官還不惡，行止得逍遙。", "晴野花侵路，春陂水上橋。", "塵埃生暖色，藥草長新苗。", "看却煙光散，狂風處處飄。"]'),
('0327b3fd-a962-4cb5-9e0c-83ecaf751252','遊春十二首 十一','姚合','唐','唐诗','tang','','[]','身被春光引，經時更不歸。',48,'全唐诗/poet.tang.26000.json','["身被春光引，經時更不歸。", "嚼花香滿口，書竹粉黏衣。", "弄日鶯狂語，迎風蝶倒飛。", "自知疎嬾性，得事亦應稀。"]'),
('41eae769-5ec5-463e-8398-b9f6493f2855','遊春十二首 十二','姚合','唐','唐诗','tang','','[]','曉脫青衫出，閑行氣味長。',48,'全唐诗/poet.tang.26000.json','["曉脫青衫出，閑行氣味長。", "一瓶春酒色，數頃野花香。", "朝客聞應羨，山僧見亦狂。", "不將僮僕去，恐爲損風光。"]'),
('c4f92a5b-e448-4ebb-b7cc-788dcf57cc56','賞春','姚合','唐','唐诗','tang','','[]','閑人祗是愛春光，迎得春來喜欲狂。',64,'全唐诗/poet.tang.26000.json','["閑人祗是愛春光，迎得春來喜欲狂。", "買酒怕遲教走馬，看花嫌遠自移牀。", "嬌鶯語足方離樹，戲蝶飛高始過牆。", "顛倒醉眠三數日，人間百事不思量。"]'),
('b2d14d5b-7cc1-4243-8557-d9f2fbd1482b','春日即事','姚合','唐','唐诗','tang','','[]','春來眠不得，誰復念生涯。',48,'全唐诗/poet.tang.26000.json','["春來眠不得，誰復念生涯。", "夜聽四鄰樂，朝尋九陌花。", "輕煙浮草色，微雨濯年華。", "乞假非關病，朝衣在酒家。"]'),
('71a6362f-1573-4537-b64b-d7aa7a0717f5','春日江次','姚合','唐','唐诗','tang','','[]','野步出茆齋，閑行坐石臺。',48,'全唐诗/poet.tang.26000.json','["野步出茆齋，閑行坐石臺。", "久悲鄉路遠，猶喜杏花開。", "鷗鷺皆飛去，帆檣何處來？", "因凝千里目，落日尚徘徊。"]'),
('c4a046cc-ff98-437d-b8ae-881274efe64b','揚州春詞三首 一','姚合','唐','唐诗','tang','','[]','廣陵寒食天，無霧復無煙。',48,'全唐诗/poet.tang.26000.json','["廣陵寒食天，無霧復無煙。", "煖日凝花柳，春風散管弦。", "園林多是宅，車馬少於船。", "莫喚遊人住，遊人困不眠。"]'),
('7ded0943-f1e2-4bb8-ae6d-bbd4542b23e7','揚州春詞三首 二','姚合','唐','唐诗','tang','','[]','滿郭是春光，街衢土亦香。',48,'全唐诗/poet.tang.26000.json','["滿郭是春光，街衢土亦香。", "竹風輕履舃，花露膩衣裳。", "谷鳥鳴還豔，山夫到更狂。", "可憐遊賞地，煬帝國傾亡。"]'),
('7f5138f9-63f2-4ee1-b651-c3560b9a60a0','揚州春詞三首 三','姚合','唐','唐诗','tang','','[]','江北煙光裏，淮南勝事多。',48,'全唐诗/poet.tang.26000.json','["江北煙光裏，淮南勝事多。", "市鄽持燭入，鄰里漾船過。", "有地惟栽竹，無家不養鵝。", "春風蕩城郭，滿耳是笙歌。"]'),
('13382b76-2ff1-430b-8475-2d0a3cbdef3f','寒食二首 一','姚合','唐','唐诗','tang','','[]','今朝一百五，出戶雨初晴。',48,'全唐诗/poet.tang.26000.json','["今朝一百五，出戶雨初晴。", "舞愛雙飛蝶，歌聞百囀鶯。", "江深青草岸，花滿白雲城。", "爲政多孱懦，應無酷吏名。"]'),
('6e6b95c4-65b6-4cc9-9b5e-ff5461ed464c','寒食二首 二','姚合','唐','唐诗','tang','','[]','出城煙火少，況復是今朝。',48,'全唐诗/poet.tang.26000.json','["出城煙火少，況復是今朝。", "閑坐將誰語，臨觴只自謠。", "堦前春蘚徧，衣上落花飄。", "伎樂州人戲，使君心寂寥。"]'),
('f5763570-1110-4202-9c30-4c8fff33ff39','暮春書事','姚合','唐','唐诗','tang','','[]','窮巷少芳菲，蒼苔一徑微。',48,'全唐诗/poet.tang.26000.json','["窮巷少芳菲，蒼苔一徑微。", "酒醒聞客別，年長送春歸。", "宿願眠雲嶠，浮名繫鎖闈。", "未因丞相庇，難得脫朝衣。"]'),
('a0a326e6-2128-4fea-ac0c-7a87c934a062','春晚雨中','姚合','唐','唐诗','tang','','[]','寂寂春將老，閑人強自歡。',48,'全唐诗/poet.tang.26000.json','["寂寂春將老，閑人強自歡。", "迎風鶯語澀，帶雨蝶飛難。", "傍砌木初長，眠花景漸闌。", "臨軒平目望，情思若爲寬。"]'),
('2b18f67e-8081-4aac-a7bc-f7800e3feae3','送春','姚合','唐','唐诗','tang','','[]','昨迎今復送，來晚去逡巡。',48,'全唐诗/poet.tang.26000.json','["昨迎今復送，來晚去逡巡。", "芳盡空繁樹，愁多獨病身。", "靜思傾酒嬾，閑望上樓頻。", "爲向春風道，明年早報春。"]'),
('59b515ba-c71f-46fd-98cd-03d889532e88','別春','姚合','唐','唐诗','tang','','[]','留春不得被春欺，春若無情遣泥誰。',64,'全唐诗/poet.tang.26000.json','["留春不得被春欺，春若無情遣泥誰。", "寂寞自疑生冷病，淒涼還似別親知。", "隨風未辨歸何處，澆酒唯求住少時。", "一去近當三百日，從朝至夜是相思。"]'),
('ea0eb551-059a-4cce-8fc6-950155b17ec3','夏夜','姚合','唐','唐诗','tang','','[]','閑齋深夜靜，獨坐又閑行。',48,'全唐诗/poet.tang.26000.json','["閑齋深夜靜，獨坐又閑行。", "密樹月籠影，疎籬水隔聲。", "斷猨時叫谷，棲鳥每搖檉。", "寂寞求名士，誰知此夕情。"]'),
('134127c0-b1fd-4369-b7c8-986f86b06fea','秋日有懷','姚合','唐','唐诗','tang','','[]','秋來不復眠，但覺思悠然。',48,'全唐诗/poet.tang.26000.json','["秋來不復眠，但覺思悠然。", "菊色欲經露，蟲聲漸替蟬。", "詩情生酒裏，心事在山邊。", "舊里無因到，西風又一年。"]'),
('c2e27cd4-9cf4-4679-874e-0aaa3de2b713','秋夕遣懷','姚合','唐','唐诗','tang','','[]','昨宵白露下，秋氣滿山城。',48,'全唐诗/poet.tang.26000.json','["昨宵白露下，秋氣滿山城。", "風勁衣巾脆，窗虛筆墨輕。", "臨書愛真跡，避酒怕狂名。", "祗擬隨麋鹿，悠悠過一生。"]'),
('42efbc7c-2dd8-4d50-b5a9-344642e25223','秋中夜坐','姚合','唐','唐诗','tang','','[]','疎散永無事，不眠常夜分。',24,'全唐诗/poet.tang.26000.json','["疎散永無事，不眠常夜分。", "月中松露滴，風引鶴同聞。"]'),
('0e550ae0-942e-49ad-94d3-9db5f291fceb','同衛尉崔少卿九月六日飲','姚合','唐','唐诗','tang','','[]','酒熟菊還芳，花飄盞亦香。',48,'全唐诗/poet.tang.26000.json','["酒熟菊還芳，花飄盞亦香。", "與君先一醉，舉世待重陽。", "風色初晴利，蟲聲向晚長。", "此時如不飲，心事亦應傷。"]'),
('a52eac00-0de8-4559-94e9-2c92044f126e','九日憶硯山舊居','姚合','唐','唐诗','tang','','[]','帝里閑人少，誰同把酒桮。',48,'全唐诗/poet.tang.26000.json','["帝里閑人少，誰同把酒桮。", "硯山籬下菊，今日幾枝開。", "曉角驚眠起，秋風引病來。", "長年歸思切，更值雁聲催。"]'),
('ca1d24d4-4786-4bef-8d2d-02c62f8f38a8','秋晚江次','姚合','唐','唐诗','tang','','[]','蕭蕭晚景寒，獨立望江壖。',48,'全唐诗/poet.tang.26000.json','["蕭蕭晚景寒，獨立望江壖。", "沙渚幾行鴈，風灣一隻船。", "落霞澄返照，孤嶼隔微煙。", "極目思無盡，鄉心到眼前。"]'),
('e885eaff-e326-4188-91b3-96dee2f198d0','除夜二首 一','姚合','唐','唐诗','tang','','[]','衰殘歸未遂，寂寞此宵情。',48,'全唐诗/poet.tang.26000.json','["衰殘歸未遂，寂寞此宵情。", "舊國當千里，新年隔數更。", "寒猶近北峭，風漸向東生。", "誰見長安陌，晨鐘度火城。"]'),
('a4e5f63d-176c-4677-8f92-f1246e386160','除夜二首 二','姚合','唐','唐诗','tang','','[]','慇懃惜此夜，此夜在逡巡。',48,'全唐诗/poet.tang.26000.json','["慇懃惜此夜，此夜在逡巡。", "燭盡年還別，雞鳴老更新。", "儺聲方去疫，酒色已迎春。", "明日持杯處，誰爲最後人。"]'),
('32984601-8267-4833-afa7-1b425d1faa86','晦日送窮三首 一','姚合','唐','唐诗','tang','','[]','年年到此日，瀝酒拜街中。',24,'全唐诗/poet.tang.26000.json','["年年到此日，瀝酒拜街中。", "萬戶千門看，無人不送窮。"]'),
('2e6a3bc5-b392-4832-a02b-f776b63abfb0','晦日送窮三首 二','姚合','唐','唐诗','tang','','[]','送窮窮不去，相泥欲何爲。',24,'全唐诗/poet.tang.26000.json','["送窮窮不去，相泥欲何爲。", "今日官家宅，淹留又幾時。"]'),
('ce41b67a-3235-459e-8648-1a2d138f203d','晦日送窮三首 三','姚合','唐','唐诗','tang','','[]','古人皆恨別，此別恨消魂。',24,'全唐诗/poet.tang.26000.json','["古人皆恨別，此別恨消魂。", "只是空相送，年年不出門。"]'),
('012c08f7-eb3b-4f39-bd56-b7b85e2820c6','詠雲','姚合','唐','唐诗','tang','','[]','靄靄紛紛不可窮，戛笙歌處盡隨龍。',64,'全唐诗/poet.tang.26000.json','["靄靄紛紛不可窮，戛笙歌處盡隨龍。", "來依銀漢一千里，歸傍巫山十二峰。", "呈瑞每聞開麗色，避風仍見挂喬松。", "憐君翠染雙蟬鬢，鏡裏朝朝近玉容。"]'),
('4d040743-238d-4421-b6ce-701d86f1892a','詠雪','姚合','唐','唐诗','tang','','[]','愁雲殘臘下陽臺，混却乾坤六出開。',64,'全唐诗/poet.tang.26000.json','["愁雲殘臘下陽臺，混却乾坤六出開。", "與月交光呈瑞色，共花爭豔傍寒梅。", "飛隨郢客歌聲遠，散逐宮娥舞袖迴。", "其那知音不相見，剡溪乘興爲君來。"]'),
('8c66a34d-a5d3-4154-a785-5f60f42565ae','郡中對雪','姚合','唐','唐诗','tang','','[]','霏微著草樹，漸布與階平。',48,'全唐诗/poet.tang.26000.json','["霏微著草樹，漸布與階平。", "遠近如空色，飄颺無落聲。", "飛鴉疑翅重，去馬覺蹄輕。", "遙想故山下，樵夫應滯行。"]'),
('1d8f9ea1-7c40-4b6d-9245-64a850c85149','對月','姚合','唐','唐诗','tang','','[]','銀輪玉兔向東流，瑩淨三更正好遊。',32,'全唐诗/poet.tang.26000.json','["銀輪玉兔向東流，瑩淨三更正好遊。", "一片黑雲何處起，皁羅籠却水精毬。"]'),
('372fe890-a023-4ef4-9f6d-4ce2b6291487','八月十五夜看月','姚合','唐','唐诗','tang','','[]','亭亭千萬里，三五復秋中。',48,'全唐诗/poet.tang.26000.json','["亭亭千萬里，三五復秋中。", "此夕光應絕，常時思不同。", "九霄微有露，四海靜無風。", "惆悵逡巡別，誰能看碧空。"]'),
('9b5ecbe4-82b1-4618-90a5-6b803ff38bf9','賦月華臨靜夜','姚合','唐','唐诗','tang','','[]','長空埃𡏖滅，皎皎月華臨。',60,'全唐诗/poet.tang.26000.json','["長空埃𡏖滅，皎皎月華臨。", "色正秋將半，光鮮夜自深。", "九霄晴更徹，四野氣難侵。", "靜照遙山出，孤明列宿沈。", "高人應不寐，驚鵲復何心。"]'),
('7031d564-be3d-4e8c-a178-fa82e689d859','酬任疇協律夏中苦雨見寄','姚合','唐','唐诗','tang','','[]','銀漢波瀾溢，經旬雨未休。',264,'全唐诗/poet.tang.26000.json','["銀漢波瀾溢，經旬雨未休。", "細聽宜隔牖，遠望憶高樓。", "風急飄還斷，雲低落更稠。", "走童驚掣電，飢鳥啄浮漚。", "絲網張空際，蛛繩續瓦溝。", "青蛙多入戶，潢潦欲勝舟。", "雷怒疑山破，池渾似土流。", "灰人漫禳厭，水馬恣沈浮。", "廣陌應翻浪，貧居恐作湫。", "陽精藏不耀，陰氣盛難收。", "遠色重林暮，繁聲四壁秋。", "望晴思見日，防冷欲披裘。", "枕潤眠還嬾，車羸出轉憂。", "散空煙漠漠，迸溜竹修修。", "樹暗蟬吟咽，巢傾燕語愁。", "琴書涼簟淨，燈燭夜窗幽。", "天下那能向，龍邊豈易求。", "濕煙凝竈額，荒草覆牆頭。", "酒思淒方罷，詩情耿始抽。", "下牀先仗屐，汲井恐飄甌。", "危坐徒相憶，佳期未有由。", "勞君寄新什，終日不能酬。"]'),
('6bf4c054-d1e0-432d-8f7a-b1bdb667bc35','和座主相公雨中作','姚合','唐','唐诗','tang','','[]','清氣潤華屋，東風吹雨勻。',72,'全唐诗/poet.tang.26000.json','["清氣潤華屋，東風吹雨勻。", "花低驚豔重，竹淨覺聲真。", "山際凝如霧，雲中散似塵。", "蕭蕭下碧落，點點救生民。", "緩灑雷霆細，微霑瓦礫新。", "詩成難繼和，造化筆通神。"]'),
('0113f856-278b-4fd5-8ff2-ef1516543fbf','惡神行雨','姚合','唐','唐诗','tang','','[]','凶神扇𥳽惡神行，汹湧挨排白霧生。',64,'全唐诗/poet.tang.26000.json','["凶神扇𥳽惡神行，汹湧挨排白霧生。", "風擊水凹波撲凸，雨漴山口地嵌坑。", "龍噴黑氣翻騰滾，鬼掣紅光劈劃揁。", "哮吼忽雷聲揭石，滿天啾唧鬧轟轟。"]'),
('278ca1e4-c864-4792-a5ee-302b3b8ff195','苦雨','姚合','唐','唐诗','tang','','[]','江昏山半晴，南阻絕人行。',48,'全唐诗/poet.tang.26000.json','["江昏山半晴，南阻絕人行。", "葭菼連雲色，松杉共雨聲。", "早秋仍燕舞，深夜更鼉鳴。", "爲報迷津客，訛言未可輕。"]'),
('f10e0221-c19e-48b1-93ad-3e472ff907e7','題鳳翔西郭新亭','姚合','唐','唐诗','tang','','[]','西郭塵埃外，新亭制度奇。',192,'全唐诗/poet.tang.26000.json','["西郭塵埃外，新亭制度奇。", "地形當要處，人力是閑時。", "結搆方殊絕，高低更合宜。", "棟梁清俸買，松竹遠山移。", "佛寺幽難敵，仙家景可追。", "良工慙巧盡，上客恨逢遲。", "兩面寒波漲，當前軟柳垂。", "清虛宜月入，涼冷勝風吹。", "宴賞軍容靜，登臨妓樂隨。", "魚龍聽弦管，鳧鶴識旌旗。", "泛鷁春流闊，飛觴白日欹。", "閑花長在戶，嫩蘚乍緣墀。", "永望情無極，頻來困不辭。", "雲峰晴轉翠，煙樹曉逾滋。", "向野惟貪靜，臨空遽覺危。", "行人如不到，遊樂更何爲。"]'),
('6370019c-cebc-4327-a50a-e1fe227718f3','題金州西園九首 江榭','姚合','唐','唐诗','tang','','[]','亭亭白雲榭，下有清江流。',36,'全唐诗/poet.tang.26000.json','["亭亭白雲榭，下有清江流。", "見江不得親，不如波上鷗。", "有榭江可見，無榭無雙眸。"]'),
('584b73b9-aff3-4486-94cf-78ceb3aef9fc','題金州西園九首 藥堂','姚合','唐','唐诗','tang','','[]','僮僕不到閾，雙扉常自關。',36,'全唐诗/poet.tang.26000.json','["僮僕不到閾，雙扉常自關。", "四壁畫遠水，堂前聳秋山。", "時聞有仙鼠，竊藥簷隙間。"]'),
('f3d670ef-e4f8-4a68-a788-8e4ad1e26a03','題金州西園九首 草閣','姚合','唐','唐诗','tang','','[]','編草覆柏椽，軒扉皆竹織。',36,'全唐诗/poet.tang.26000.json','["編草覆柏椽，軒扉皆竹織。", "閤成似僧居，學僧居未得。", "有時公府勞，還復來此息。"]'),
('55b7ee47-2a20-4fb0-809a-bbad81776117','題金州西園九首 松壇','姚合','唐','唐诗','tang','','[]','盤盤松上蓋，下覆青石壇。',36,'全唐诗/poet.tang.26000.json','["盤盤松上蓋，下覆青石壇。", "月中零露垂，日出露尚漙。", "山翁稱絕境，海橋無所觀。"]'),
('8f56cb26-2cea-40b9-8db2-86a92c47d8bd','題金州西園九首 葼徑','姚合','唐','唐诗','tang','','[]','藥院徑亦高，往來踏葼影。',36,'全唐诗/poet.tang.26000.json','["藥院徑亦高，往來踏葼影。", "方當繁暑日，草屩微微冷。", "愛此不能行，折薪坐煎茗。"]'),
('9e752556-5028-4859-980f-1550bd4050ac','題金州西園九首 垣竹','姚合','唐','唐诗','tang','','[]','種竹愛庭際，亦以資玩賞。',36,'全唐诗/poet.tang.26000.json','["種竹愛庭際，亦以資玩賞。", "窮秋雨蕭條，但見牆垣長。", "宣尼高數仞，固應非土壤。"]'),
('6670ed57-670b-4c27-b984-b3afe617a896','題金州西園九首 石庭','姚合','唐','唐诗','tang','','[]','布石滿山庭，磷磷潔還清。',36,'全唐诗/poet.tang.26000.json','["布石滿山庭，磷磷潔還清。", "幽人常履此，月下屐齒鳴。", "藥草枝葉動，似向山中生。"]'),
('4704b7da-b988-4c89-aa15-502881ebe6a6','題金州西園九首 莓苔','姚合','唐','唐诗','tang','','[]','茅堂階豈高，數寸是苔蘚。',36,'全唐诗/poet.tang.26000.json','["茅堂階豈高，數寸是苔蘚。", "只恐秋雨中，窗戶亦不濺。", "眼前無此物，我情何由遣。"]'),
('c665aab3-22a8-4fdc-9653-597c45ab3592','題金州西園九首 芭蕉屏','姚合','唐','唐诗','tang','','[]','芭蕉叢叢生，月照參差影。',36,'全唐诗/poet.tang.26000.json','["芭蕉叢叢生，月照參差影。", "數葉大如牆，作我門之屏。", "稍稍聞見稀，耳目得安靜。"]'),
('8e0f1791-98e2-4cc2-8b14-4ee2aa1c6664','杏溪十首 杏溪','姚合','唐','唐诗','tang','','[]','桃花四散飛，桃子壓枝垂。',36,'全唐诗/poet.tang.26000.json','["桃花四散飛，桃子壓枝垂。", "寂寂青陰裏，幽人舉步遲。", "慇懃念此徑，我去復來誰。"]'),
('840ef4eb-4fc6-452e-b78d-fb6c5e65db73','杏溪十首 蓮塘','姚合','唐','唐诗','tang','','[]','方塘菡萏高，繁豔相照耀。',36,'全唐诗/poet.tang.26000.json','["方塘菡萏高，繁豔相照耀。", "幽人夜眠起，忽疑野中燒。", "曉尋不知休，白石岸亦峭。"]'),
('b8e031d3-d542-4cd0-b3d9-9f00c2841660','杏溪十首 架水藤','姚合','唐','唐诗','tang','','[]','濛濛紫花藤，下復清溪水。',36,'全唐诗/poet.tang.26000.json','["濛濛紫花藤，下復清溪水。", "若遣隨波流，不如風飄起。", "風飄或近堤，隨波千萬里。"]'),
('174ea8b8-9870-4f2d-b38a-9f54c5a8526c','杏溪十首 石潭','姚合','唐','唐诗','tang','','[]','曉向潭上行，夕就潭邊宿。',36,'全唐诗/poet.tang.26000.json','["曉向潭上行，夕就潭邊宿。", "清冷無波瀾，潎潎魚相逐。", "釣翁坐不起，見我往來熟。"]'),
('04dd77dd-ddb4-4351-ad0d-0cb988262b35','杏溪十首 溪路','姚合','唐','唐诗','tang','','[]','此路何瀟灑，永無公卿跡。',36,'全唐诗/poet.tang.26000.json','["此路何瀟灑，永無公卿跡。", "日日多往來，藜杖與桑屐。", "路邊何所有，磊磊青淥石。"]'),
('a1d34136-d364-4fd6-bc9b-78d139f9d11b','杏溪十首 望江峰','姚合','唐','唐诗','tang','','[]','念昔有此峰，在彼江陵先。',36,'全唐诗/poet.tang.26000.json','["念昔有此峰，在彼江陵先。", "舉世未能知，愚亦望同賢。", "我來心益悶，欲上天公牋。"]'),
('b198c284-e998-44fa-8c3e-eeb07f493739','杏溪十首 杏水','姚合','唐','唐诗','tang','','[]','不與江水接，自出林中央。',36,'全唐诗/poet.tang.26000.json','["不與江水接，自出林中央。", "穿花復遠水，一山聞杏香。", "我來持茗甌，日屢此來嘗。"]'),
('9c830533-c2a4-41a4-94fc-4937bcfbcb74','杏溪十首 渚上竹','姚合','唐','唐诗','tang','','[]','葉葉新春筠，下復清淺流。',36,'全唐诗/poet.tang.26000.json','["葉葉新春筠，下復清淺流。", "微風屢此來，決決復脩脩。", "詩人月下吟，月墮吟不休。"]'),
('7c598b1f-1f69-42bc-9308-32d38c39b674','杏溪十首 楓林堰','姚合','唐','唐诗','tang','','[]','森森楓樹林，護此石門堰。',36,'全唐诗/poet.tang.26000.json','["森森楓樹林，護此石門堰。", "杏隄數里餘，楓影覆亦徧。", "鸕鷀與釣童，質異同所願。"]'),
('aaf9b941-19d9-4fd4-93fc-a21c6bd5a1f9','杏溪十首 石瀨','姚合','唐','唐诗','tang','','[]','散漫復潺湲，半砂半和石。',36,'全唐诗/poet.tang.26000.json','["散漫復潺湲，半砂半和石。", "清風波亦無，歷歷魚可搦。", "我來亦屢久，歸路常日夕。"]'),
('4a839e92-fca6-4b37-9c8b-c31b800975a9','陝下厲玄侍御宅五題 濯纓溪','姚合','唐','唐诗','tang','','[]','舊山寧要去，此有濯纓泉。',48,'全唐诗/poet.tang.26000.json','["舊山寧要去，此有濯纓泉。", "曉景松枝覆，秋光月色連。", "行尋屐齒盡，坐對角巾偏。", "寂寂幽棲處，無妨請俸錢。"]'),
('fd567be7-515c-4931-ba7f-f0610f39fa9f','陝下厲玄侍御宅五題 垂釣亭','姚合','唐','唐诗','tang','','[]','由釣起茅亭，柴扉復竹楹。',48,'全唐诗/poet.tang.26000.json','["由釣起茅亭，柴扉復竹楹。", "波清見絲影，坐久識魚情。", "白鳥依窗宿，青蒲傍砌生。", "欲同漁父舍，須自減逢迎。"]'),
('98f258d0-6177-4a48-bae5-d16d06c65ead','陝下厲玄侍御宅五題 吟詩島','姚合','唐','唐诗','tang','','[]','幽島蘚層層，詩人日日登。',48,'全唐诗/poet.tang.26000.json','["幽島蘚層層，詩人日日登。", "坐危石是榻，吟冷唾成冰。", "靜對唯秋水，同來但老僧。", "竹枝題字處，小篆復誰能。"]'),
('024b4d3d-165f-460b-af56-6dbce46f44ca','陝下厲玄侍御宅五題 竹裏徑','姚合','唐','唐诗','tang','','[]','微徑嬋娟裏，唯聞靜者知。',48,'全唐诗/poet.tang.26000.json','["微徑嬋娟裏，唯聞靜者知。", "跡深苔長處，步狹笋生時。", "高是連幽樹，窮應到曲池。", "紗巾靈壽杖，行樂復相宜。"]'),
('de71500c-c00f-441f-8c1c-fb1b40018138','陝下厲玄侍御宅五題 泛觴泉','姚合','唐','唐诗','tang','','[]','不上酒家樓，池邊日獻酬。',48,'全唐诗/poet.tang.26000.json','["不上酒家樓，池邊日獻酬。", "杯來轉巴字，客坐遶方流。", "酹滴苔紋斷，泉連石岸秋。", "若能山下置，歲晚願同遊。"]'),
('6552573b-a0e9-411d-b4c6-577b5d674fe9','題僧院引泉','姚合','唐','唐诗','tang','','[]','泉眼高千尺，山僧取得歸。',48,'全唐诗/poet.tang.26000.json','["泉眼高千尺，山僧取得歸。", "架空橫竹引，鑿石透渠飛。", "洗藥溪流濁，澆花雨力微。", "朝昏長遶看，護惜似持衣。"]'),
('f2b4e835-9454-43cd-9a23-8d7c4e0d9aad','題家園新池','姚合','唐','唐诗','tang','','[]','數日自穿池，引泉來近陂。',48,'全唐诗/poet.tang.26000.json','["數日自穿池，引泉來近陂。", "尋渠通咽處，遶岸待清時。", "深好求魚養，閑堪與鶴期。", "幽聲聽難盡，入夜睡常遲。"]'),
('1175677a-aec2-4d4e-b5ed-18bc89ecd3bd','詠盆池','姚合','唐','唐诗','tang','','[]','浮萍重疊水團圓，客遶千遭屐齒痕。',32,'全唐诗/poet.tang.26000.json','["浮萍重疊水團圓，客遶千遭屐齒痕。", "莫驚池裏尋常滿，一井清泉是上源。"]'),
('6de8b925-241f-450a-ae35-e8c01a2e5b07','買太湖石','姚合','唐','唐诗','tang','','["\u592a\u6e56"]','我嘗遊太湖，愛石青嵯峨。',156,'全唐诗/poet.tang.26000.json','["我嘗遊太湖，愛石青嵯峨。", "波瀾取不得，自後長咨嗟。", "奇哉賣石翁，不傍豪貴家。", "負石聽苦吟，雖貧亦來過。", "貴我辨識精，取價復不多。", "比之昔所見，珍怪頗更加。", "背面淙注痕，孔隙若琢磨。", "水稱至柔物，湖乃生壯波。", "或云此天生，嵌空亦非他。", "氣質偶不合，如地生江河。", "置之書房前，曉霧常紛羅。", "碧光入四鄰，牆壁難蔽遮。", "客來謂我宅，忽若巖之阿。"]'),
('e8f69fd2-f8fe-4203-9000-c0a4cb8dc914','天竺寺殿前立石','姚合','唐','唐诗','tang','','[]','補天殘片女媧拋，撲落禪門壓地坳。',64,'全唐诗/poet.tang.26000.json','["補天殘片女媧拋，撲落禪門壓地坳。", "霹靂劃深龍舊攫，屈槃痕淺虎新抓。", "苔黏月眼風挑剔，塵結雲頭雨磕敲。", "秋至莫言長矻立，春來自有薜蘿交。"]'),
('bc2fa22c-0b0b-4d01-ba3c-d9df13d07ec8','杭州觀潮','姚合','唐','唐诗','tang','','["\u94b1\u5858\u6c5f"]','樓有章亭號，濤來自古今。',120,'全唐诗/poet.tang.26000.json','["樓有章亭號，濤來自古今。", "勢連蒼海闊，色比白雲深。", "怒雪驅寒氣，狂雷散大音。", "浪高風更起，波急石難沈。", "鳥懼多遙過，龍驚不敢吟。", "坳如開玉穴，危似走瓊岑。", "但褫千人魄，那知伍相心。", "岸摧連古道，洲漲碚叢林。", "跳沫山皆濕，當江日半陰。", "天然與禹鑿，此理遣誰尋。"]'),
('23b8d68c-73a3-4387-aa5b-8c68583eb48e','題李頻新居','姚合','唐','唐诗','tang','','[]','賃居求賤處，深僻任人嫌。',48,'全唐诗/poet.tang.26000.json','["賃居求賤處，深僻任人嫌。", "蓋地花如繡，當門竹勝簾。", "勸僧嘗藥酒，教僕辨書簽。", "庭際山宜小，休令著石添。"]'),
('09eaa482-62b8-402e-81bb-8de415c51746','寄題縱上人院','姚合','唐','唐诗','tang','','[]','營營是與非，前樂後還悲。',48,'全唐诗/poet.tang.26000.json','["營營是與非，前樂後還悲。", "今世已如此，他生願似師。", "禪房空旦暮，畫壁半陳隋。", "遶徑蒼苔跡，幽人來是誰。"]'),
('35fb7b63-c543-4a0d-ade6-5bd5e39326b4','題山寺','姚合','唐','唐诗','tang','','[]','千重山崦裏，樓閣影參差。',72,'全唐诗/poet.tang.26000.json','["千重山崦裏，樓閣影參差。", "未暇尋僧院，先看置寺碑。", "竹深行漸暗，石穩坐多時。", "古塔蟲蛇善，陰廊鳥雀癡。", "雲開上界近，泉落下方遲。", "爲愛青桐葉，因題滿樹詩。"]'),
('04567431-1338-4709-beed-bedfce6ccc9b','題貞女祠','姚合','唐','唐诗','tang','','[]','此女骨爲土，貞名不可移。',48,'全唐诗/poet.tang.26000.json','["此女骨爲土，貞名不可移。", "精靈閟何處，蘋藻奠空祠。", "水石生異狀，杉松無病枝。", "我來方謝雨，延滯失歸期。"]'),
('3248974f-ad6d-4339-9ac8-70bdc9dc591d','題刑部馬員外修行里南街新居','姚合','唐','唐诗','tang','','[]','帝里誰無宅，青山秖屬君。',48,'全唐诗/poet.tang.26000.json','["帝里誰無宅，青山秖屬君。", "閑窗連竹色，幽砌上苔文。", "遠近高低樹，東西南北雲。", "朝朝常獨見，免被四鄰分。"]'),
('6fbc9364-7dd0-4e05-b1fe-342e80ac7c76','題郭侍郎親仁里幽居','姚合','唐','唐诗','tang','','[]','入門塵外思，苔徑藥苗間。',48,'全唐诗/poet.tang.26000.json','["入門塵外思，苔徑藥苗間。", "洞裏應生玉，庭前自有山。", "帝城唯此靜，朝客更誰閑。", "野鶴松中語，時時去復還。"]'),
('f3c65547-c0da-42a7-a771-8ce41049fc61','題宣義池亭','姚合','唐','唐诗','tang','','[]','春入池亭好，風光暖更鮮。',96,'全唐诗/poet.tang.26000.json','["春入池亭好，風光暖更鮮。", "尋芳行不困，逐勝坐還遷。", "細草亂如髮，幽禽鳴似弦。", "苔文翻古篆，石色學秋天。", "花落能漂酒，萍開解避船。", "暫來還愈疾，久住合成仙。", "迸笋搘堦起，垂藤壓樹偏。", "此生應借看，自計買無錢。"]'),
('60f4e2ef-60af-40f6-aafd-39c996e57c73','題薛十二池亭','姚合','唐','唐诗','tang','','[]','每日樹邊消一日，遶池行過又須行。',64,'全唐诗/poet.tang.26000.json','["每日樹邊消一日，遶池行過又須行。", "異花多是非時有，好竹皆當要處生。", "斜立小橋看島勢，遠移幽石作泉聲。", "浮萍著岸風吹歇，水面無塵晚更清。"]'),
('c93f0793-46ae-4c7d-b188-f8a52e5e99c6','題大理崔少卿駙馬林亭','姚合','唐','唐诗','tang','','[]','每來歸意懶，都尉似山人。',48,'全唐诗/poet.tang.26000.json','["每來歸意懶，都尉似山人。", "臺榭栖雙鷺，松篁隔四鄰。", "迸泉清勝雨，深洞暖如春。", "更看題詩處，前軒粉壁新。"]'),
('e0b05844-1d22-4752-9fd3-9a765a68173f','題杭州南亭','姚合','唐','唐诗','tang','','[]','舊隱即雲林，思歸日日深。',48,'全唐诗/poet.tang.26000.json','["舊隱即雲林，思歸日日深。", "如今來此地，無復有前心。", "古石生靈草，長松栖異禽。", "暮潮簷下過，濺浪濕衣襟。"]'),
('8bd2af18-0acb-44ce-8754-cc35d27a5ce5','題鄭駙馬林亭','姚合','唐','唐诗','tang','','[]','東園連宅起，勝事與心期。',72,'全唐诗/poet.tang.26000.json','["東園連宅起，勝事與心期。", "幽洞自生藥，新篁迸入池。", "密林行不盡，芳草坐難移。", "石翠疑無質，鶯歌似有詞。", "莎臺高出樹，蘚壁淨題詩。", "我獨多來賞，九衢人不知。"]'),
('ad501b73-0df1-48ad-b2a0-8f9fcab1f6a6','題厲玄侍御所居','姚合','唐','唐诗','tang','','[]','幽棲一畝宮，清峭似山峰。',48,'全唐诗/poet.tang.26000.json','["幽棲一畝宮，清峭似山峰。", "鄰里不通徑，俸錢唯買松。", "野人時寄宿，谷鳥自相逢。", "朝路牀前是，誰知曉起慵。"]'),
('a36a088e-6b86-4968-90fb-3d991e75ee97','題田將軍宅','姚合','唐','唐诗','tang','','[]','焚香書院最風流，莎草緣牆綠蘚秋。',64,'全唐诗/poet.tang.26000.json','["焚香書院最風流，莎草緣牆綠蘚秋。", "近砌別穿澆藥井，臨街新起看山樓。", "棲禽戀竹明猶在，閑客觀花夜未休。", "好是暗移城裏宅，清涼渾得似江頭。"]'),
('ff9bc85d-b3fa-4b89-87c7-38638ef472ed','題崔駙馬宅','姚合','唐','唐诗','tang','','[]','心在林泉身在城，鳳凰樓下得閑名。',64,'全唐诗/poet.tang.26000.json','["心在林泉身在城，鳳凰樓下得閑名。", "洞中見鑿尋仙路，月裏猶燒煮藥鐺。", "數樹異花皆敕賜，並竿修竹自天生。", "詩人多說離君宅，不得青苔地上行。"]'),
('76465257-317a-4517-9884-587b09e5c849','題河上亭','姚合','唐','唐诗','tang','','[]','亭亭河上亭，魚躑水禽鳴。',72,'全唐诗/poet.tang.26000.json','["亭亭河上亭，魚躑水禽鳴。", "九曲何時盡，千峰今日清。", "晨光秋更遠，暑氣夏常輕。", "桮裏移檣影，琴中有浪聲。", "岸莎連砌靜，漁火入窗明。", "來此多沈醉，神高無宿酲。"]'),
('2a315566-8104-40a5-84c0-13bcb20d4ca0','題長安薛員外水閣','姚合','唐','唐诗','tang','','["\u592a\u6e56"]','亭亭新閣成，風景益鮮明。',72,'全唐诗/poet.tang.26000.json','["亭亭新閣成，風景益鮮明。", "石盡太湖色，水多湘渚聲。", "翠筠和粉長，零露逐荷傾。", "時倚高窗望，幽尋小徑行。", "林疎看鳥語，池近識魚情。", "政暇招閑客，唯將酒送迎。"]'),
('7fd52938-f4e8-4f71-bd12-d4b6e2c47c7f','題梁國公主池亭','姚合','唐','唐诗','tang','','[]','平陽池館枕秦川，門鏁南山一帶煙。',64,'全唐诗/poet.tang.26000.json','["平陽池館枕秦川，門鏁南山一帶煙。", "素柰花開西子面，綠榆枝種沈郎錢。", "裝簾玳瑁隨風落，庭岸鵁鶄趁煖眠。", "寂寞空餘歌舞地，玉簫驚起鳳歸天。"]'),
('fe3c019f-9a7a-4c05-bbff-02bd974a8d7c','寄題尉遲少卿郊居','姚合','唐','唐诗','tang','','[]','卿仕在關東，林居思不窮。',96,'全唐诗/poet.tang.26000.json','["卿仕在關東，林居思不窮。", "朝衣挂壁上，廐馬放田中。", "隅坐唯禪子，隨行只藥童。", "砌莎留宿露，庭竹出清風。", "濃翠生苔點，辛香發桂叢。", "蓮池伊水入，石徑遠山通。", "愚者心還靜，高人跡自同。", "無能相近住，終日羨鄰翁。"]'),
('1c1c8a3b-1b5a-4d60-a7c0-d8675918562a','題永城驛','姚合','唐','唐诗','tang','','[]','秋賦春還計盡違，自知身是拙求知。',64,'全唐诗/poet.tang.26000.json','["秋賦春還計盡違，自知身是拙求知。", "惟思曠海無休日，却喜孤舟似去時。", "連浦一程兼汴宋，夾堤千柳雜唐隋。", "從來此恨皆前達，敢負吾君作楚詞。"]'),
('6e8ae2af-117b-4c99-805b-ba7196359c15','過張邯鄲莊','姚合','唐','唐诗','tang','','[]','客行長似病，煩熱束四肢。',120,'全唐诗/poet.tang.26000.json','["客行長似病，煩熱束四肢。", "到君讀書堂，忽若逢良醫。", "堂前水交流，堂下樹交枝。", "兩門延風涼，洗我昏濁肌。", "與子還往熟，坐臥恣所宜。", "時時相獻酬，文字當酒巵。", "野飯具藜藿，永日亦不飢。", "苟飡非其所，鱠炙爲蒺藜。", "時清士人閑，耕作唯文詞。", "豈獨鄉里薦，當取四海知。"]'),
('5bab6acb-9ea4-4309-b08d-582e28996b83','過楊處士幽居','姚合','唐','唐诗','tang','','[]','引水穿風竹，幽聲勝遠溪。',48,'全唐诗/poet.tang.26000.json','["引水穿風竹，幽聲勝遠溪。", "裁衣延野客，翦翅養山雞。", "酒熟聽琴酌，詩成削樹題。", "惟愁春氣暖，松下雪和泥。"]'),
('9b95e98e-3c2b-4f5c-9a0b-a388bb1d6e7c','過李處士山居','姚合','唐','唐诗','tang','','[]','閑居晝掩扉，門柳蔭蔬畦。',48,'全唐诗/poet.tang.26000.json','["閑居晝掩扉，門柳蔭蔬畦。", "因病方收藥，尋僧始度溪。", "少逢人到戶，時有燕銜泥。", "蕭灑身無事，名高孰與齊。"]'),
('0a6d7665-2c1b-41bf-9c14-a641b299bdf0','過無可僧院','姚合','唐','唐诗','tang','','[]','憶師眠復起，永夜思迢迢。',48,'全唐诗/poet.tang.26000.json','["憶師眠復起，永夜思迢迢。", "月下門方掩，林中寺更遙。", "鐘聲空下界，池色在清宵。", "終擬修禪觀，窗間卷欲燒。"]'),
('6d993954-dd46-4f80-932f-ba03e6db3c2f','過稠上人院','姚合','唐','唐诗','tang','','[]','清羸一飯師，閑院亦披衣。',48,'全唐诗/poet.tang.26000.json','["清羸一飯師，閑院亦披衣。", "應詔常翻譯，修心出是非。", "雪中疎磬度，林際晚風歸。", "蔬食常來此，人間護淨稀。"]'),
('63e41c11-7025-4359-a616-bfa8bce69c4c','過不疑上人院','姚合','唐','唐诗','tang','','[]','九經通大義，內典自應精。',48,'全唐诗/poet.tang.26000.json','["九經通大義，內典自應精。", "簾冷連松影，苔深減覆聲。", "相逢幸此日，相失恐來生。", "覺路何門去，師須引我行。"]'),
('c54b0656-8e85-418f-b0b4-e688745f205c','過曇花寶上人院','姚合','唐','唐诗','tang','','[]','九陌最幽寺，吾師院復深。',48,'全唐诗/poet.tang.26000.json','["九陌最幽寺，吾師院復深。", "煙霜同覆屋，松竹雜成林。", "鳥語境彌寂，客來機自沈。", "早知能到此，應不戴朝簪。"]'),
('d898d902-92cc-45e7-976b-6d80af7564b7','過杜氏江亭','姚合','唐','唐诗','tang','','[]','上國千餘里，逢春且勝遊。',48,'全唐诗/poet.tang.26000.json','["上國千餘里，逢春且勝遊。", "暫聞新鳥戲，似解旅人愁。", "野色吞山盡，江煙襯水流。", "村醪須一醉，無恨滯行舟。"]'),
('fb2d943d-1e88-4e32-8388-2e2154eccafa','過張雲峰院宿','姚合','唐','唐诗','tang','','[]','不喫胡麻飯，杯中自得仙。',72,'全唐诗/poet.tang.26000.json','["不喫胡麻飯，杯中自得仙。", "隔籬招好客，掃室置芳筵。", "家醞香醪嫩，時新異果鮮。", "夜深唯畏曉，坐穩豈思眠。", "棊罷嫌無敵，詩成貴在前。", "明朝題壁上，誰得衆人傳。"]'),
('d1307ffb-b849-4d0c-babc-2192e6775d6c','過欽上人院','姚合','唐','唐诗','tang','','[]','有相無相身，唯師說始真。',48,'全唐诗/poet.tang.26000.json','["有相無相身，唯師說始真。", "修篁半庭影，清磬幾僧鄰。", "古壁丹青落，虛簷鳥雀馴。", "伊余求了義，羸馬往來頻。"]'),
('8aaf1aa9-dbd6-40dc-bce4-4e8c49ebcb21','過無可上人院','姚合','唐','唐诗','tang','','[]','寥寥聽不盡，孤磬與疎鐘。',48,'全唐诗/poet.tang.26000.json','["寥寥聽不盡，孤磬與疎鐘。", "煩惱師長別，清涼我暫逢。", "蟻行經古蘚，鶴毳落深松。", "自想歸時路，塵埃復幾重。"]'),
('eb9851ab-ac4b-4615-9283-22fe95316b2b','過城南僧院','姚合','唐','唐诗','tang','','[]','寺對遠山起，幽居仍是師。',48,'全唐诗/poet.tang.26000.json','["寺對遠山起，幽居仍是師。", "斜陽通暗隙，殘雪落疎籬。", "松靜鶴棲定，廊虛鐘盡遲。", "朝朝趨府吏，來此是相宜。"]'),
('1edbeb66-df42-4c65-8d77-0ba9a7d31474','過靈泉寺','姚合','唐','唐诗','tang','','[]','偶尋靈跡去，幽徑入氳氛。',48,'全唐诗/poet.tang.26000.json','["偶尋靈跡去，幽徑入氳氛。", "轉壑驚飛鳥，穿山踏亂雲。", "水從巖下落，溪向寺前分。", "釋子遊何處，空堂日漸曛。"]'),
('9e9919e1-e9a8-4c27-a2a9-dbb7720daeb6','過天津橋晴望','姚合','唐','唐诗','tang','','[]','閑立津橋上，寒光動遠林。',48,'全唐诗/poet.tang.26000.json','["閑立津橋上，寒光動遠林。", "皇宮對嵩頂，清洛貫城心。", "雪路初晴出，人家向晚深。", "自從王在鎬，天寶至如今。"]'),
('11d844bd-0cb1-403f-a97b-462cb430fa07','春日遊慈恩寺','姚合','唐','唐诗','tang','','[]','年長歸何處，青山未有家。',24,'全唐诗/poet.tang.26000.json','["年長歸何處，青山未有家。", "賞春無酒飲，多看寺中花。"]'),
('f231e5bc-0c93-49b9-9f3b-088ed2139675','遊天台上方','姚合','唐','唐诗','tang','','[]','曉上上方高處立，路人羨我此時身。',32,'全唐诗/poet.tang.26000.json','["曉上上方高處立，路人羨我此時身。", "白雲向我頭上過，我更羨他雲路人。"]'),
('03e86e74-c1a1-4092-a46d-83e0b4e7ad57','遊終南山','姚合','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','策杖度溪橋，雲深步數勞。',48,'全唐诗/poet.tang.26000.json','["策杖度溪橋，雲深步數勞。", "青猿吟嶺際，白鶴坐松梢。", "天外浮煙遠，山根野水交。", "自緣名利繫，好此結蓬茆。"]'),
('d6870a3e-2d02-4314-b5df-38b2b3c59709','遊杏溪蘭若','姚合','唐','唐诗','tang','','[]','踏得度溪灣，晨遊暮不還。',48,'全唐诗/poet.tang.26000.json','["踏得度溪灣，晨遊暮不還。", "月明松影路，春滿杏花山。", "戲狖跳林末，高僧住石間。", "未肯離腰組，來此復何顏。"]'),
('71f6cf11-25ea-4de6-8d21-f9f22e4773cd','遊謝公亭','姚合','唐','唐诗','tang','','[]','行行方避夢，又到謝亭來。',48,'全唐诗/poet.tang.26000.json','["行行方避夢，又到謝亭來。", "舉世皆如此，伊余何處迴？", "竹鮮多透石，泉潔亦無苔。", "坐與僧同語，誰能顧酒杯。"]'),
('c9cef5f1-e469-44e0-9ffd-180de31dccac','遊陽河岸','姚合','唐','唐诗','tang','','[]','終日遊山困，今朝始傍河。',48,'全唐诗/poet.tang.26000.json','["終日遊山困，今朝始傍河。", "尋芳愁路盡，逢景畏人多。", "鳥語催沽酒，魚來似聽歌。", "醉時眠石上，肢體自婆娑。"]'),
('4864005f-1460-4240-b4f9-3297fe15cd62','遊河橋曉望','姚合','唐','唐诗','tang','','[]','閑上津橋立，天涯一望間。',48,'全唐诗/poet.tang.26000.json','["閑上津橋立，天涯一望間。", "秋風波上岸，旭日氣連山。", "偶聖今方變，朝宗豈復還。", "崑崙在蕃界，作將亦何顏。"]'),
('6864d8f3-dbd4-4a91-acd5-a3c38023eb56','秋夜月中登天壇','姚合','唐','唐诗','tang','','["\u79cb\u5929", "\u613f\u671b"]','秋蟾流異彩，齋潔上壇行。',48,'全唐诗/poet.tang.26000.json','["秋蟾流異彩，齋潔上壇行。", "天近星辰大，山深世界清。", "仙飆石上起，海日夜中明。", "何計長來此，閑眠過一生。"]'),
('f9894e81-839e-43aa-bbf6-125454762ef4','遊昊天玄都觀','姚合','唐','唐诗','tang','','[]','性同相見易，紫府共閑行。',72,'全唐诗/poet.tang.26000.json','["性同相見易，紫府共閑行。", "陰徑紅桃落，秋壇白石生。", "蘚文連竹色，鶴語應松聲。", "風定藥香細，樹聲泉氣清。", "垂簷靈草影，遶壁古山名。", "圍外坊無禁，歸時踏月明。"]'),
('dd439caa-f185-42a2-983d-68e3ece591e0','同裴起居厲侍御放朝遊曲江','姚合','唐','唐诗','tang','','[]','暑月放朝頻，青槐路絕塵。',48,'全唐诗/poet.tang.26000.json','["暑月放朝頻，青槐路絕塵。", "雨晴江色出，風動草香新。", "獨立分幽島，同行得靜人。", "此歡宜稍滯，此去與誰親。"]'),
('f66daac3-3440-40ec-9c4d-6c97a930b2b3','曉望華清宮','姚合','唐','唐诗','tang','','[]','曉看樓殿更鮮明，遙隔朱欄見鹿行。',32,'全唐诗/poet.tang.26000.json','["曉看樓殿更鮮明，遙隔朱欄見鹿行。", "武帝自知身不死，教修玉殿號長生。"]'),
('324b5467-2383-424b-be55-8622db12d7fb','夏日登樓晚望','姚合','唐','唐诗','tang','','[]','避暑高樓上，平蕪望不窮。',48,'全唐诗/poet.tang.26000.json','["避暑高樓上，平蕪望不窮。", "鳥穿山色去，人歇樹陰中。", "數帶長河水，千條弱柳風。", "暗思多少事，懶話與芝翁。"]'),
('fbc4422d-cb60-45f6-b042-672758a8aefe','霽後登樓','姚合','唐','唐诗','tang','','[]','高樓初霽後，遠望思無窮。',48,'全唐诗/poet.tang.26000.json','["高樓初霽後，遠望思無窮。", "雨洗青山淨，春蒸大野融。", "碧池舒煖景，若柳嚲和風。", "爲有登臨興，獨吟落照中。"]'),
('7a109da1-0228-4c29-a920-e2afbbbc0f29','早夏郡樓宴集','姚合','唐','唐诗','tang','','[]','官散有閑情，登樓步稍輕。',48,'全唐诗/poet.tang.26000.json','["官散有閑情，登樓步稍輕。", "窗雲帶雨氣，林鳥雜人聲。", "曉日襟前度，微風酒上生。", "城中會難得，掃壁各書名。"]'),
('05436715-6fda-4d1c-be51-fa7247c0d20f','夜宴太僕田卿宅','姚合','唐','唐诗','tang','','[]','故人九寺長，邀我此同歡。',48,'全唐诗/poet.tang.26000.json','["故人九寺長，邀我此同歡。", "永夜開筵靜，中年飲酒難。", "微風侵燭影，疊漏過林端。", "臘後分朝日，天明幾刻殘。"]'),
('52e96ad1-5901-442f-a0c5-ea8e1865aa6a','春日同會衛尉崔少卿宅','姚合','唐','唐诗','tang','','[]','詩家會詩客，池閣曉初晴。',48,'全唐诗/poet.tang.26000.json','["詩家會詩客，池閣曉初晴。", "鳥盡山中語，琴多譜外聲。", "映花相勸酒，入洞各題名。", "疎野常如此，誰人信在城。"]'),
('d9108657-ac67-40a0-ac37-e7c2931f45b3','軍城夜會','姚合','唐','唐诗','tang','','[]','軍城夜禁樂，飲酒每題詩。',48,'全唐诗/poet.tang.26000.json','["軍城夜禁樂，飲酒每題詩。", "坐穩吟難盡，寒多醉較遲。", "遠鐘驚漏壓，微月被燈欺。", "此會誠堪惜，天明是別離。"]'),
('900eb9b7-3280-45ba-83e1-f77334d201e7','晦日宴劉值錄事宅','姚合','唐','唐诗','tang','','[]','花落鶯飛深院靜，滿堂賓客盡詩人。',32,'全唐诗/poet.tang.26000.json','["花落鶯飛深院靜，滿堂賓客盡詩人。", "城中杯酒家家有，唯是君家酒送春。"]'),
('3a3e82c7-28c9-4613-8c9d-08f7992b0d2e','宴光祿田卿宅','姚合','唐','唐诗','tang','','[]','竹裏開華館，珍羞次第嘗。',48,'全唐诗/poet.tang.26000.json','["竹裏開華館，珍羞次第嘗。", "春風酒影動，晴日樂聲長。", "久坐難辭醉，衰年亦暫狂。", "慇懃還繼燭，永夕夢相妨。"]'),
('8c047708-21b3-4271-a42e-405e9da06b24','會將作崔監東園','姚合','唐','唐诗','tang','','[]','牆北走紅塵，牆東接白雲。',48,'全唐诗/poet.tang.26000.json','["牆北走紅塵，牆東接白雲。", "山光衣上見，藥氣酒中聞。", "此會誠堪惜，窮秋日又曛。", "人間唯有醉，醉後復何云。"]'),
('76f37325-0317-44d3-b12a-6be3637cd91e','同諸公會太府韓卿宅','姚合','唐','唐诗','tang','','[]','九寺名卿才思雄，邀歡筆下與杯中。',64,'全唐诗/poet.tang.26000.json','["九寺名卿才思雄，邀歡筆下與杯中。", "六街鼓絕塵埃息，四座筵開語笑同。", "燄燄蘭缸明狹室，丁丁玉漏發深宮。", "即聽雞唱天門曉，吏事相牽西復東。"]'),
('ff1c1524-b482-4f66-9dae-6508eb163802','乞酒','姚合','唐','唐诗','tang','','[]','聞君有美酒，與我正相宜。',48,'全唐诗/poet.tang.26000.json','["聞君有美酒，與我正相宜。", "溢甕清如水，黏杯半似脂。", "豈唯消舊病，且要引新詩。", "況此便便腹，無非是滿巵。"]'),
('f7312605-51e2-41dc-a3d7-56dcb1ee08f5','寄衛拾遺乞酒','姚合','唐','唐诗','tang','','[]','老人罷巵酒，不醉已經年。',48,'全唐诗/poet.tang.26000.json','["老人罷巵酒，不醉已經年。", "自飲君家酒，一杯三日眠。", "味輕花上露，色似洞中泉。", "莫厭時時寄，須知法未傳。"]'),
('8d7e8e90-79e8-49c1-81f5-e16ed2b07c89','乞新茶','姚合','唐','唐诗','tang','','[]','嫩綠微黃碧澗春，採時聞道斷葷辛。',32,'全唐诗/poet.tang.26000.json','["嫩綠微黃碧澗春，採時聞道斷葷辛。", "不將錢買將詩乞，借問山翁有幾人。"]'),
('0736c7a7-9d9f-4423-baec-d2facd1d3085','西掖寓直春曉聞殘漏','姚合','唐','唐诗','tang','','[]','直廬仙掖近，春氣曙猶寒。',72,'全唐诗/poet.tang.26000.json','["直廬仙掖近，春氣曙猶寒。", "隱隱銀河在，丁丁玉漏殘。", "微風飄更切，萬籟雜應難。", "鳳閣明初啓，雞人唱漸闌。", "靜宜來禁裏，清是下雲端。", "我識朝天路，從容自整冠。"]'),
('4abec255-2ea4-40b6-b1ad-ca0459a8ae31','杭州郡齋南亭','姚合','唐','唐诗','tang','','[]','符印懸腰下，東山不得歸。',48,'全唐诗/poet.tang.26000.json','["符印懸腰下，東山不得歸。", "獨行南北近，漸老往還稀。", "迸笋侵窗長，驚蟬出樹飛。", "田田池上葉，長是使君衣。"]'),
('3044eb85-941f-4bbd-8076-2c4529c9cdbb','郡中西園','姚合','唐','唐诗','tang','','[]','西園春欲盡，芳草徑難分。',48,'全唐诗/poet.tang.26000.json','["西園春欲盡，芳草徑難分。", "靜語唯幽鳥，閑眠獨使君。", "密林生雨氣，古石帶潮文。", "雖去清秋遠，朝朝見白雲。"]'),
('f0ffd426-460f-496a-8f30-a444f0bd1316','杭州官舍偶書','姚合','唐','唐诗','tang','','[]','錢塘刺史謾題詩，貧褊無恩懦少威。',64,'全唐诗/poet.tang.26000.json','["錢塘刺史謾題詩，貧褊無恩懦少威。", "春盡酒杯花影在，潮迴畫檻水聲微。", "閑吟山際邀僧上，暮入林中看鶴歸。", "無術理人人自理，朝朝漸覺簿書稀。"]'),
('87525822-00b0-44ca-bad8-7ca4e80d41cf','省直書事','姚合','唐','唐诗','tang','','[]','默默滄江老，官分右掖榮。',120,'全唐诗/poet.tang.26000.json','["默默滄江老，官分右掖榮。", "立朝班近殿，奏直上知名。", "曉霧和香氣，晴樓下樂聲。", "蜀牋金屑膩，月兔筆毫精。", "禁樹霏煙覆，宮牆瑞草生。", "露盤秋更出，玉漏晝還清。", "碧蘚無塵染，寒蟬似鳥鳴。", "竹深雲自宿，天近日先明。", "孱懦難封詔，疎愚但擲觥。", "素飡終日足，寧免衆人輕。"]'),
('a20cb39e-4633-4181-a3c3-8fc2e600f2fd','杭州官舍即事','姚合','唐','唐诗','tang','','[]','臨江府署清，閑臥復閑行。',48,'全唐诗/poet.tang.26000.json','["臨江府署清，閑臥復閑行。", "苔蘚疎塵色，梧桐出雨聲。", "漸除身外事，暗作道家名。", "更喜仙山近，庭前藥自生。"]'),
('558294b9-2644-4a26-ab51-976522de5f42','假日書事呈院中司徒','姚合','唐','唐诗','tang','','[]','十日公府靜，巾櫛起清晨。',48,'全唐诗/poet.tang.26000.json','["十日公府靜，巾櫛起清晨。", "寒蟬近衰柳，古木似高人。", "學佛寧憂老，爲儒自喜貧。", "海山歸未得，芝朮夢中春。"]'),
('c57f2aec-a007-4e0e-9895-2d9d58804753','書縣丞舊廳','姚合','唐','唐诗','tang','','[]','宮殿半山上，人家向下居。',48,'全唐诗/poet.tang.26000.json','["宮殿半山上，人家向下居。", "古廳眠易魘，老吏語多虛。", "雨水澆荒竹，溪沙擁廢渠。", "聖朝收外府，皆是九天除。"]'),
('c0e82d43-7854-4303-9e1a-44389d02c0d5','縣中秋宿','姚合','唐','唐诗','tang','','[]','鼓絕門方掩，蕭條作吏心。',48,'全唐诗/poet.tang.26000.json','["鼓絕門方掩，蕭條作吏心。", "露垂庭際草，螢照竹間禽。", "棊罷嫌無月，眠遲聽盡碪。", "還知未離此，時復更相尋。"]'),
('093a2c08-f627-462c-90ef-6e7faa4b5f76','夏夜宿江驛','姚合','唐','唐诗','tang','','[]','竹屋臨江岸，清宵興自長。',48,'全唐诗/poet.tang.26000.json','["竹屋臨江岸，清宵興自長。", "夜深傾北斗，葉落映橫塘。", "渚鬧漁歌響，風和角糉香。", "却愁南去棹，早晚到瀟湘。"]'),
('2c0eb9fe-83a4-4d5b-936b-68258ced3f99','陝城即事','姚合','唐','唐诗','tang','','["\u9ec4\u6cb3"]','左右分京闕，黃河與宅連。',48,'全唐诗/poet.tang.26000.json','["左右分京闕，黃河與宅連。", "何功來此地，竊位已經年。", "天下才彌小，關中鎮最先。", "隴山望可見，惆悵是窮邊。"]'),
('0744f0eb-b689-4170-82be-d9823d035904','和東都令狐留守相公','姚合','唐','唐诗','tang','','[]','除官東守洛陽宮，恩比藩方任更雄。',64,'全唐诗/poet.tang.26000.json','["除官東守洛陽宮，恩比藩方任更雄。", "拜表出時傳七刻，排班衙日有三公。", "旌旗嚴重臨關外，庭宇清深接禁中。", "三十六峰詩酒思，朝朝閑望與誰同。"]'),
('326751f4-c7e7-4fdd-b45a-daca764b0aeb','和高諫議蒙兼賓客時入翰苑','姚合','唐','唐诗','tang','','[]','兼秩恩歸第一流，時尋仙路向瀛洲。',64,'全唐诗/poet.tang.26000.json','["兼秩恩歸第一流，時尋仙路向瀛洲。", "鐘聲迢遞銀河曉，林色蔥籠玉露秋。", "紫殿講筵鄰御座，青宮賓榻入龍樓。", "從來共結歸山侶，今日多應獨自休。"]'),
('4e987d77-9362-44a2-9790-250e2734bb0b','和盧給事酬裴員外','姚合','唐','唐诗','tang','','[]','南山雪色徹皇州，鐘鼓聲交曉氣浮。',64,'全唐诗/poet.tang.26000.json','["南山雪色徹皇州，鐘鼓聲交曉氣浮。", "鴛鷺簪裾上龍尾，蓬萊宮殿壓鼇頭。", "夕郎夜直吟仙掖，天樂和聲下禁樓。", "贈荅詩成才思敵，病夫欲和幾朝愁。"]'),
('32ef67c2-13f9-418f-98dd-bae41096db16','和裴結端公早朝','姚合','唐','唐诗','tang','','[]','魚鑰千門啓，雞人唱曉傳。',72,'全唐诗/poet.tang.26000.json','["魚鑰千門啓，雞人唱曉傳。", "冕旒臨玉殿，丞相入爐烟。", "列位同居左，分行忝在前。", "仰聞天語近，俯拜珮聲連。", "綵杖祥光動，彤庭霽色鮮。", "威儀誰可紀，柱史有新篇。"]'),
('61f0661d-2ed9-41eb-9041-0bf1d92ae23e','和門下李相餞西蜀相公','姚合','唐','唐诗','tang','','[]','聖朝同舜日，作相有夔龍。',216,'全唐诗/poet.tang.26000.json','["聖朝同舜日，作相有夔龍。", "理化知無外，烝黎盡可封。", "燮和皆達識，出入並登庸。", "武騎增餘勇，儒冠貴所從。", "贈詩全六義，出鎮越千峰。", "連日陳天樂，芳筵疊酒鍾。", "烏臺情已洽，鳳閣分彌濃。", "棧轉旌搖水，崖高馬蹋松。", "恩深施遠俗，化美見前蹤。", "江曉流巴字，山晴聳劍峰。", "雙油擁上宰，四海羨臨邛。", "先路聲華遠，離京詔旨重。", "歲除今向盡，春色即相逢。", "嫩葉抽頳蘂，新苔長翠茸。", "冰銷魚潎潎，林煖鳥噰噰。", "泉落聞難盡，花開看不供。", "青城方眷戀，黃閣竟從容。", "計日歸台席，還聽長樂鐘。"]'),
('89ac2f89-d9b3-4734-aaf2-99683128363e','和座主相公西亭秋日即事','姚合','唐','唐诗','tang','','[]','西亭秋望好，寧要更垂簾。',96,'全唐诗/poet.tang.26000.json','["西亭秋望好，寧要更垂簾。", "夫子牆還峻，酇侯宅過謙。", "微風紅葉下，新雨綠苔黏。", "窗外松初長，欄中藥旋添。", "海圖裝玉軸，書目記牙籤。", "竹色晴連地，山光遠入簷。", "酒濃杯稍重，詩冷語多尖。", "屬和才雖淺，題高免客嫌。"]'),
('88a3d71a-fcb7-449c-9f81-541a41989095','和祕書崔少監春日遊青龍寺僧院','姚合','唐','唐诗','tang','','[]','官清書府足閑時，曉起攀花折柳枝。',64,'全唐诗/poet.tang.26000.json','["官清書府足閑時，曉起攀花折柳枝。", "九陌城中尋不盡，千峰寺裏看相宜。", "高人酒味多和藥，自古風光只屬詩。", "見說往來多靜者，未知前日更逢誰。"]'),
('f9d18743-ad51-44ef-a136-c8b7e8c52d0c','和李紳助教不赴看花','姚合','唐','唐诗','tang','','[]','笑辭聘禮深坊住，門館長閑似退居。',64,'全唐诗/poet.tang.26000.json','["笑辭聘禮深坊住，門館長閑似退居。", "太學官資清品秩，高人公事說經書。", "年華未是登朝晚，春色何因向酒疎。", "且看牡丹吟麗句，不知此外復何如。"]'),
('a92d70c5-5fcc-4edf-ab37-7b240c1aa5da','和李十二舍人冬至日','姚合','唐','唐诗','tang','','[]','獻壽人皆慶，南山復北堂。',24,'全唐诗/poet.tang.26000.json','["獻壽人皆慶，南山復北堂。", "從今千萬日，此日又初長。"]'),
('5ceac367-56cf-499f-96ca-c69b21db27f7','和裴令公新成綠野堂即事','姚合','唐','唐诗','tang','','[]','結搆立嘉名，軒窗四面明。',120,'全唐诗/poet.tang.26000.json','["結搆立嘉名，軒窗四面明。", "丘牆高莫比，蕭宅僻還清。", "池際龜潛戲，庭前藥旋生。", "樹深簷稍邃，石峭徑難平。", "道曠襟情遠，神閑視聽精。", "古今功獨出，大小隱俱成。", "曙雨新苔色，秋風長桂聲。", "攜詩就竹寫，取酒對花傾。", "古寺招僧飯，方塘看鶴行。", "人間無此貴，半仗暮歸城。"]'),
('1d007cd1-4d10-4844-85f2-e1aa0f01b339','和厲玄侍御題戶部李相公廬山西林草堂','姚合','唐','唐诗','tang','','["\u5e90\u5c71"]','茅屋臨江起，登庸復應期。',48,'全唐诗/poet.tang.26000.json','["茅屋臨江起，登庸復應期。", "遙知歸去日，自致太平時。", "幽藥禪僧護，高窗宿鳥窺。", "行人盡歌詠，唯子獨能詩。"]'),
('34b562fa-cc24-4377-a0e5-cc061612c574','和鄭相演楊尚書蜀中唱和詩','姚合','唐','唐诗','tang','','[]','天福坤維厚，忠賢擁節旄。',96,'全唐诗/poet.tang.26000.json','["天福坤維厚，忠賢擁節旄。", "江同渭濱遠，山似傅巖高。", "元氣符才格，文星照筆毫。", "五言全麗則，六義出風騷。", "聖日麻雙下，洪爐柄共操。", "寵榮連雨露，先後比蕭曹。", "唱絕時難和，吟多客詎勞。", "四方雖紙貴，誰怕費錢刀。"]'),
('d4a9a6d2-c898-4d37-9ee1-2a51b0ea684e','和戶部侍郎省中晚歸','姚合','唐','唐诗','tang','','[]','寒日南宮晚，閑吟半醉歸。',48,'全唐诗/poet.tang.26000.json','["寒日南宮晚，閑吟半醉歸。", "位高行路靜，詩好和人稀。", "古樹苔文匝，遙峰雪色微。", "寧知逢彩筆，寂寞有光輝。"]'),
('2c5e32d0-ad46-4431-bd84-27dc624f0e2c','和元八郎中秋居','姚合','唐','唐诗','tang','','[]','聖代無爲化，郎中似散仙。',48,'全唐诗/poet.tang.26000.json','["聖代無爲化，郎中似散仙。", "晚眠隨客醉，夜坐學僧禪。", "酒用林花釀，茶將野水煎。", "人生知此味，獨恨少因緣。"]'),
('418e4101-3c6d-4f69-aa4c-c978fa15d996','和李十二舍人裴四二舍人兩閣老酬白少傅見寄','姚合','唐','唐诗','tang','','[]','罷草王言星歲久，嵩高山色日相親。',96,'全唐诗/poet.tang.26000.json','["罷草王言星歲久，嵩高山色日相親。", "蕭條雨夜吟連曉，撩亂花時看盡春。", "此世逍遙應獨得，古來閑散有誰鄰。", "林中長老呼居士，天下書生仰達人。", "酒挈數瓶杯亦闊，詩成千首語皆新。", "綸闈竝命誠宜賀，不念衰年寄上頻。"]'),
('4abb7bdd-0f7b-4d26-a7bf-7d9cb45ffdfb','和劉禹錫主客冬初拜表懷上都故人','姚合','唐','唐诗','tang','','[]','九陌喧喧騎吏催，百官拜表禁城開。',64,'全唐诗/poet.tang.26000.json','["九陌喧喧騎吏催，百官拜表禁城開。", "林疎曉日明紅葉，塵靜寒霜覆綠苔。", "玉佩聲微班始定，金函光動按初來。", "此時共想朝天客，謝食方從閣裏迴。"]'),
('7c006a51-529f-4cd9-a098-c8b8aedb3d9b','和太僕田卿酬殷堯藩侍御見寄','姚合','唐','唐诗','tang','','[]','往還知分熟，酬贈思同新。',72,'全唐诗/poet.tang.26000.json','["往還知分熟，酬贈思同新。", "嗜飲殷偏逸，閑吟卿亦貧。", "古苔寒更翠，修竹靜無鄰。", "促席燈浮酒，聽鴻霜滿身。", "淺才唯是我，高論更何人。", "攜手宜相訪，窮行少路塵。"]'),
('4dc301ef-b587-41ae-b23a-1181c28c5646','和膳部李郎中秋夕','姚合','唐','唐诗','tang','','[]','淅淅復修修，涼風似水流。',48,'全唐诗/poet.tang.26000.json','["淅淅復修修，涼風似水流。", "此生難免老，舉世大同愁。", "螢影明苔蘚，鴻聲傍斗牛。", "猶分省署直，何日是歸休。"]'),
('c0b32dce-1028-4349-a142-147ca8351df3','和前吏部韓侍郎夜泛南溪','姚合','唐','唐诗','tang','','[]','辭得官來疾漸平，世間難有此高情。',32,'全唐诗/poet.tang.26000.json','["辭得官來疾漸平，世間難有此高情。", "新秋月滿南溪裏，引客乘船處處行。"]'),
('ae183f55-61cf-43bc-ac10-c3f881b9cb74','和王郎中題華州李中丞廳','姚合','唐','唐诗','tang','','[]','蓮華峰下郡齋前，遶砌穿池貯瀑泉。',32,'全唐诗/poet.tang.26000.json','["蓮華峰下郡齋前，遶砌穿池貯瀑泉。", "君到亦應閑不得，主人草聖復詩仙。"]'),
('231798fb-62a3-41c1-85f2-a15597a8a785','和厲玄侍御無可上人會宿見寄','姚合','唐','唐诗','tang','','[]','九衢難會宿，況復是寒天。',48,'全唐诗/poet.tang.26000.json','["九衢難會宿，況復是寒天。", "朝客清貧老，林僧默悟禪。", "眠遲消漏水，吟苦墮寒涎。", "異日來尋我，滄江有釣船。"]'),
('e96cbb93-8aeb-474b-9be7-d17c776f2865','和令狐六員外直夜即事寄上相公','姚合','唐','唐诗','tang','','[]','霜臺同處軒窗接，粉署先登語笑疎。',64,'全唐诗/poet.tang.26000.json','["霜臺同處軒窗接，粉署先登語笑疎。", "皓月滿簾聽玉漏，紫泥盈手發天書。", "吟詩清美招閑客，對酒逍遙臥直廬。", "榮貴人間難有比，相公離此十年餘。"]'),
('2c89afca-2796-43d6-a958-8cc9447b3d9d','答孟侍御早朝見寄','姚合','唐','唐诗','tang','','[]','河傾月向西，九陌鼓聲齊。',48,'全唐诗/poet.tang.26000.json','["河傾月向西，九陌鼓聲齊。", "塵靜霜華遠，烟生曙色低。", "禁門人已度，宮樹鳥猶棲。", "疎懶勞相問，登山有舊梯。"]'),
('09725a96-4f9a-47b2-b3c1-669c6924b53b','和友人新居園上','姚合','唐','唐诗','tang','','[]','新居多野思，不似在京城。',48,'全唐诗/poet.tang.26000.json','["新居多野思，不似在京城。", "牆上雲相壓，庭前竹亂生。", "尋師望藥力，依譜上琴聲。", "好是中秋夜，無塵有月明。"]'),
('efc30050-b23e-4df3-805f-b7e9cba33e60','和裴令公遊南莊憶白二十韋七二賓客','姚合','唐','唐诗','tang','','[]','四郊初雨歇，高樹滴猶殘。',96,'全唐诗/poet.tang.26000.json','["四郊初雨歇，高樹滴猶殘。", "池滿紅蓮濕，雲收綠野寬。", "花開半山曉，竹動數村寒。", "鬬雀翻衣袂，驚魚觸釣竿。", "罇前多野客，膝下盡郎官。", "斸石通泉脈，移松出藥欄。", "關東分務重，天下似公難。", "半醉思韋白，題詩染彩翰。"]'),
('d96af1a6-dad2-49d2-a5fb-5d7beb759583','和李舍人秋日臥疾言懷','姚合','唐','唐诗','tang','','[]','閑臥襟情遠，西風菊漸芳。',96,'全唐诗/poet.tang.26000.json','["閑臥襟情遠，西風菊漸芳。", "虛窗通曉景，珍簟卷秋光。", "果墜青莎徑，塵離綠蘚牆。", "藥匳開靜室，書閣出叢篁。", "對酒吟難盡，思山夢稍長。", "王言生彩筆，朝服惹爐香。", "松影幽連砌，蟲聲冷到牀。", "詩成誰敢和，清思若懷霜。"]'),
('d8561a29-2d40-4a9b-ac47-f20ed7891f33','和李十二舍人直日放朝對雪','姚合','唐','唐诗','tang','','[]','今朝街鼓何人聽，朝客開門對雪眠。',32,'全唐诗/poet.tang.26000.json','["今朝街鼓何人聽，朝客開門對雪眠。", "豈比直廬丹禁裏，九重天近色彌鮮。"]'),
('917c1d6f-4f9d-4045-98bb-147f8a0895cb','荅李頻秀才','姚合','唐','唐诗','tang','','[]','一年離九陌，壁上挂朝袍。',48,'全唐诗/poet.tang.26000.json','["一年離九陌，壁上挂朝袍。", "物外詩情遠，人間酒味高。", "思歸知病長，失寢覺神勞。", "衰老無多思，因君把筆毫。"]'),
('56ba164c-4967-4aa4-86ad-d2c2ff1a6274','荅胡遇','姚合','唐','唐诗','tang','','[]','一會一分離，貧遊少定期。',48,'全唐诗/poet.tang.26000.json','["一會一分離，貧遊少定期。", "酒多爲客穩，米貴入城遲。", "晴日偷將睡，秋山乞與詩。", "縱然眉得展，不似見君時。"]'),
('026a5e3f-fdbf-45ea-9ce1-2f1606357151','荅友人招遊','姚合','唐','唐诗','tang','','[]','不來知盡怪，失意懶春遊。',48,'全唐诗/poet.tang.26000.json','["不來知盡怪，失意懶春遊。", "聞鳥寧驚夢，看花怕引愁。", "賭棋招敵手，沽酒自扶頭。", "何似華筵上，推辭候到籌。"]'),
('19e5e579-39b9-40eb-8e5b-5c847a45a6ae','答竇知言','姚合','唐','唐诗','tang','','["\u9ec4\u6cb3"]','冬日易慘惡，暴風拔山根。',192,'全唐诗/poet.tang.26000.json','["冬日易慘惡，暴風拔山根。", "塵沙落黃河，濁波如地翻。", "飛鳥皆束翼，居人不開門。", "獨我赴省期，冒此馳轂轅。", "陝城城西邊，逢子亦且奔。", "所趨事一心，相見如弟昆。", "我慘得子舒，我寒得子溫。", "同行十日程，僮僕性亦敦。", "到京人事多，日無閑精魂。", "念子珍重我，吐辭發蒙昏。", "反復千萬意，一百六十言。", "格高思清冷，山低濟渾渾。", "嘗聞朋友惠，贈言始爲恩。", "金玉日消費，好句長存存。", "倒篚別收貯，不與俗士論。", "每當清夜吟，使我如哀猿。"]'),
('696e8bff-d484-43e7-8ee5-def174bbe9f2','酬田就','姚合','唐','唐诗','tang','','[]','閑居多僻靜，猶恐道相違。',48,'全唐诗/poet.tang.26000.json','["閑居多僻靜，猶恐道相違。", "只是夜深坐，那堪春未歸。", "嫩苔黏野色，香絮撲人衣。", "縱有野僧到，終朝不話非。"]'),
('7b6f8da6-1f28-477b-9bb6-ad59ccbd8711','酬禮部李員外見寄','姚合','唐','唐诗','tang','','[]','本求仙郡是閑居，豈向郎官更有書。',64,'全唐诗/poet.tang.26000.json','["本求仙郡是閑居，豈向郎官更有書。", "溪石誰思玉匠愛，煙鴻願與弋人疎。", "自來江上眠方穩，舊在城中病悉除。", "唯見君詩難便捨，寒宵吟到曉更初。"]'),
('998db0df-3f42-4f85-9507-818fba6d16ef','酬令狐郎中見寄','姚合','唐','唐诗','tang','','[]','昨是兒童今是翁，人間日月急如風。',32,'全唐诗/poet.tang.26000.json','["昨是兒童今是翁，人間日月急如風。", "常聞欲向滄江去，除我無人與子同。"]'),
('bbe3d5f9-3736-4bc5-8091-236b36dac54d','酬李廓精舍南臺望月見寄','姚合','唐','唐诗','tang','','[]','看月空門裏，詩家境有餘。',48,'全唐诗/poet.tang.26000.json','["看月空門裏，詩家境有餘。", "露寒僧梵出，林靜鳥巢疎。", "遠色當秋半，清光勝夜初。", "獨無臺上思，寂寞守吾廬。"]'),
('e87448b5-e64d-4309-89e8-98d85fdee5ab','酬光祿田卿末伏見寄','姚合','唐','唐诗','tang','','[]','下伏秋期近，還知扇漸疎。',48,'全唐诗/poet.tang.26000.json','["下伏秋期近，還知扇漸疎。", "驚飆墜鄰果，暴雨落江魚。", "貴寺雖同秩，閑曹只管書。", "朝朝廊下食，相庇在肴葅。"]'),
('de7c69e8-5d62-477e-9946-4112d6f80a7b','酬薛奉禮見贈之作','姚合','唐','唐诗','tang','','[]','栖栖滄海一耕人，詔遣江邊作使君。',64,'全唐诗/poet.tang.26000.json','["栖栖滄海一耕人，詔遣江邊作使君。", "山頂雨餘青到地，濤頭風起白連雲。", "詩成客見書牆和，藥熟僧來就鼎分。", "珍重來章相借分，芳名未識已曾聞。"]'),
('9ef4014c-4dba-49e3-a018-67968a51b4e2','酬盧汀諫議','姚合','唐','唐诗','tang','','[]','粟如流水帛如山，依念倉邊語笑間。',64,'全唐诗/poet.tang.26000.json','["粟如流水帛如山，依念倉邊語笑間。", "篇什縱橫文案少，親朋撩亂吏人閑。", "杯觴引滿從衣濕，牆壁書多任手頑。", "遙賀來年二三月，綵衣先輩過春關。"]'),
('3f4ee176-a588-4ae4-b43f-5cc24b784895','酬萬年張郎中見寄','姚合','唐','唐诗','tang','','[]','貢籍常同府，周行今一時。',48,'全唐诗/poet.tang.26000.json','["貢籍常同府，周行今一時。", "諫曹誠已忝，京邑豈相宜。", "黑髮年來盡，滄江歸去遲。", "何時得攜手，林下靜吟詩。"]'),
('0d9dfa37-752e-4739-bd2a-506918e78db0','酬光祿田卿六韻見寄','姚合','唐','唐诗','tang','','[]','以病辭朝謁，迂疎種藥翁。',72,'全唐诗/poet.tang.26000.json','["以病辭朝謁，迂疎種藥翁。", "心彌念魚鳥，詔遣理兵戎。", "遶戶旌旗影，吹人鼓角風。", "雪晴嵩岳頂，樹老陝城宮。", "莅職才微薄，歸山路未通。", "名卿詩句峭，誚我在關東。"]'),
('8d83a81c-ae09-495d-9b25-f1ecc40c2213','酬楊汝士尚書喜人移居','姚合','唐','唐诗','tang','','[]','未得滄江外，衰殘讀藥書。',48,'全唐诗/poet.tang.26000.json','["未得滄江外，衰殘讀藥書。", "聖朝優上秩，仁里許閑居。", "樹對枝相接，泉同井不疎。", "酬章深自鄙，欲寄復躊躕。"]'),
('79aedcac-0b7f-4da7-8056-962e58efd5b3','酬田卿書齋即事見寄','姚合','唐','唐诗','tang','','[]','幽齋琴思靜，晚下紫宸朝。',48,'全唐诗/poet.tang.26000.json','["幽齋琴思靜，晚下紫宸朝。", "舊隱同溪遠，周行隔品遙。", "深槐蟬唧唧，疎竹雨蕭蕭。", "不是相尋懶，煩君舉酒瓢。"]'),
('4026e3f4-b4c8-4abe-b325-79311be570c8','酬張籍司業見寄','姚合','唐','唐诗','tang','','[]','日日在心中，青山青桂叢。',48,'全唐诗/poet.tang.26000.json','["日日在心中，青山青桂叢。", "高人多愛靜，歸路亦應同。", "罷吏方無病，因僧得解空。", "新詩勞見問，吟對竹林風。"]'),
('0a79ffe1-3770-4b6f-854b-c188aabc75d7','謝汾州田大夫寄茸氈[葡]萄','姚合','唐','唐诗','tang','','[]','筐封紫[葡]萄，筒卷白茸毛。',50,'全唐诗/poet.tang.26000.json','["筐封紫[葡]萄，筒卷白茸毛。", "臥煖身應健，含消齒免勞。", "衾衣疎不稱，梨栗鄙難高。", "曉起題詩報，寒澌滿筆毫。"]'),
('624e9c72-afa0-4426-9376-f3f56c6b71eb','牧杭州謝李太尉德裕','姚合','唐','唐诗','tang','','[]','皇恩特許拜杭壇，欲謝旌旄去就難。',32,'全唐诗/poet.tang.26000.json','["皇恩特許拜杭壇，欲謝旌旄去就難。", "偷擬白頭瞻畫戟，四神俱散髮毛寒。"]'),
('2fb114ff-62af-4abb-b68f-e72dc2aea501','杏園宴上謝座主','姚合','唐','唐诗','tang','','[]','得陪桃李植芳叢，別感生成太昊功。',32,'全唐诗/poet.tang.26000.json','["得陪桃李植芳叢，別感生成太昊功。", "今日無言春雨後，似含冷涕謝東風。"]'),
('c5397c43-89d1-4405-903e-0b3a1bd8d0ef','謝韜光上人','姚合','唐','唐诗','tang','','[]','上方清淨無因住，唯願他生得住持。',32,'全唐诗/poet.tang.26000.json','["上方清淨無因住，唯願他生得住持。", "只恐無生復無我，不知何處更逢師。"]'),
('8deda5f3-5d00-4914-9550-c749649dcfbc','謝秦校書與無可上人見訪','姚合','唐','唐诗','tang','','[]','道同無宿約，三伏自從容。',48,'全唐诗/poet.tang.26000.json','["道同無宿約，三伏自從容。", "窗豁山侵座，扇搖風下松。", "客吟多遶竹，僧飯只憑鐘。", "向晚分歸路，莓苔行跡重。"]'),
('773e1702-b06e-457e-9615-8b1dfbc736fa','喜胡遇至','姚合','唐','唐诗','tang','','[]','窮居稀出入，門戶滿塵埃。',72,'全唐诗/poet.tang.26000.json','["窮居稀出入，門戶滿塵埃。", "病少閑人問，貧唯密友來。", "茅齋從埽破，藥酒遣生開。", "多事經時別，還愁不宿迴。", "就林燒嫩筍，遶樹揀香梅。", "相對題新什，遲成舉罰杯。"]'),
('8a27b541-6346-4561-bcfe-db060ed3f10b','喜賈島至','姚合','唐','唐诗','tang','','[]','布囊懸蹇驢，千里到貧居。',48,'全唐诗/poet.tang.26000.json','["布囊懸蹇驢，千里到貧居。", "飲酒誰堪伴，留詩自與書。", "愛眠知不醉，省語似相疎。", "軍吏衣裳窄，還應暗笑余。"]'),
('8d661fae-2f02-4c9b-a1ee-00801d1e783f','喜喻鳧至','姚合','唐','唐诗','tang','','[]','欲出心還懶，閑吟遶寢牀。',48,'全唐诗/poet.tang.26000.json','["欲出心還懶，閑吟遶寢牀。", "道書蟲食盡，酒律客偷將。", "愁至爲多病，貧來減得狂。", "見君何所似，如熱得清涼。"]'),
('eebece54-954a-4d4e-a973-1a05a3461a0b','喜雍陶秋夜訪宿','姚合','唐','唐诗','tang','','[]','曉立侍爐煙，夜歸蓬蓽眠。',48,'全唐诗/poet.tang.26000.json','["曉立侍爐煙，夜歸蓬蓽眠。", "露華明菊上，螢影滅燈前。", "清漏和碪疊，棲禽與葉連。", "高人來此宿，爲似在山顛。"]'),
('34f90471-9c6d-47fe-adb6-46c2ece6c80c','喜賈島雨中訪宿','姚合','唐','唐诗','tang','','[]','雨裏難逢客，閑吟不復眠。',48,'全唐诗/poet.tang.26000.json','["雨裏難逢客，閑吟不復眠。", "蟲聲秋併起，林色夜相連。", "愛酒此生裏，趨朝未老前。", "終須攜手去，滄海棹魚船。"]'),
('e2b2a16e-07c6-466a-94cf-c1d902bee1dd','喜馬戴冬夜見過期無可上人不至 一','姚合','唐','唐诗','tang','','[]','客來初夜裏，藥酒自開封。',48,'全唐诗/poet.tang.26000.json','["客來初夜裏，藥酒自開封。", "老漸多歸思，貧惟長病容。", "苦寒燈焰細，近曉鼓聲重。", "僧可還相捨，深居閉古松。"]'),
('f5ebd75e-3811-4770-ac30-cc9e366d1e08','喜馬戴冬夜見過期無可上人不至 二','姚合','唐','唐诗','tang','','[]','內殿臣相命，開罇話舊時。',48,'全唐诗/poet.tang.26000.json','["內殿臣相命，開罇話舊時。", "夜鐘催鳥絕，積雪阻僧期。", "林靜寒聲遠，天陰曙色遲。", "今宵復何夕，鳴珮坐相隨。"]'),
('54a0c002-ee75-402b-b0fb-47fe69217419','訪僧法通不遇','姚合','唐','唐诗','tang','','[]','訪師師不遇，禮佛佛無言。',24,'全唐诗/poet.tang.26000.json','["訪師師不遇，禮佛佛無言。", "依舊將煩惱，黃昏入宅門。"]'),
('75abb981-e2a9-4a55-a8a1-366910de4ef9','夜期友生不至','姚合','唐','唐诗','tang','','[]','忍寒停酒待君來，酒作凌凘火作灰。',32,'全唐诗/poet.tang.26000.json','["忍寒停酒待君來，酒作凌凘火作灰。", "半夜出門重立望，月明先自下高臺。"]'),
('1da9d370-fa8f-4d3e-a1db-a413a399d3ec','尋僧不遇','姚合','唐','唐诗','tang','','[]','入門愁自散，不假見僧翁。',48,'全唐诗/poet.tang.26000.json','["入門愁自散，不假見僧翁。", "花落煎茶水，松生醒酒風。", "拂牀尋古畫，拔刺看新叢。", "別有遊人見，多疑住此中。"]'),
('5e249bb8-ceed-4243-a7cc-be57765dd95f','過友人山莊','姚合','唐','唐诗','tang','','[]','蕙帶纏腰復野蔬，一莊水竹數房書。',32,'全唐诗/poet.tang.26000.json','["蕙帶纏腰復野蔬，一莊水竹數房書。", "舉頭忽見南山雪，便說休官相近居。"]'),
('dbe2ea20-78e1-4eba-907d-1ff040414545','奉和前司封蘇郎中喜嚴常侍蕭給事見訪驚斑鬢之什','姚合','唐','唐诗','tang','','[]','遶鬢滄浪有幾莖，珥貂相問夕郎驚。',64,'全唐诗/poet.tang.26000.json','["遶鬢滄浪有幾莖，珥貂相問夕郎驚。", "祗應爲酒微微變，不是因年漸漸生。", "東觀詩成號良史，中臺官罷揖高名。", "即提彩筆裁天詔，誰得吟詩自在行。"]'),
('e769bf45-6186-42c0-ac6c-2fa4da5df65d','奉和門下相公雨中寄裴給事','姚合','唐','唐诗','tang','','[]','曉起閑看雨，垂簷自滴堦。',72,'全唐诗/poet.tang.26000.json','["曉起閑看雨，垂簷自滴堦。", "風清想林壑，雲濕似江淮。", "石信浮漚重，泥從積蘚埋。", "氣消濃酒力，心助獨吟懷。", "颯颯通琴韻，蕭蕭靜竹齋。", "綵毫無限思，念與夕郎乖。"]'),
('f14e5242-b74d-4ef0-901e-1a5439b6be4f','答韓湘','姚合','唐','唐诗','tang','','[]','疎散無世用，爲文乏天格。',168,'全唐诗/poet.tang.26000.json','["疎散無世用，爲文乏天格。", "把筆日不休，忽忽有所得。", "所得良自慰，不求他人識。", "子獨訪我來，致詩過相飾。", "君子無浮言，此詩應亦直。", "但慮憂我深，鑒亦隨之惑。", "子在名場中，屢戰還屢北。", "我無數子明，端坐空歎息。", "昨聞過春關，名係吏部籍。", "三十登高科，前塗浩難測。", "詩人多峭冷，如水在胸臆。", "豈隨尋常人，五藏爲酒食。", "期來作酬章，危坐吟到夕。", "難爲間其辭，益貴我紙墨。"]'),
('31eb2976-acd3-42f1-a4d1-4cdad3d0e0cf','奉和四松','姚合','唐','唐诗','tang','','[]','四松相對植，蒼翠映中臺。',120,'全唐诗/poet.tang.26000.json','["四松相對植，蒼翠映中臺。", "擢榦凌空去，移根斸石開。", "陰陽氣潛煦，造化手親栽。", "日月滋佳色，煙霄長異材。", "清音勝在澗，寒影徧生苔。", "靜遶霜霑履，閑看酒滿杯。", "同榮朱戶際，永日白雲隈。", "密葉聞風度，高枝見鶴來。", "賞心難可盡，麗什妙難裁。", "此地無因到，循環幾百回。"]'),
('0a6eb928-6f44-4b20-962f-7db0e774f480','和李補闕曲江看蓮花','姚合','唐','唐诗','tang','','[]','露荷迎曙發，灼灼復田田。',240,'全唐诗/poet.tang.26000.json','["露荷迎曙發，灼灼復田田。", "乍見神應駭，頻來眼尚顛。", "光凝珠有蒂，焰起火無煙。", "粉膩黃絲蘂，心重碧玉錢。", "日浮秋轉麗，雨灑晚彌鮮。", "醉豔酣千朵，愁紅思一川。", "綠莖扶萼正，翠菂滿房圓。", "淡暈還殊衆，繁英得自然。", "高名猶不厭，上客去爭先。", "景逸傾芳酒，懷濃習綵牋。", "海霞寧有態，蜀錦不成妍。", "客至應消病，僧來欲破禪。", "曉多臨水立，夜只傍堤眠。", "金似明沙渚，燈疑宿浦船。", "風驚叢乍密，魚戲影微偏。", "穠彩燒晴霧，殷姿纈碧泉。", "畫工投粉筆，宮女棄花鈿。", "鳥戀驚難起，蜂偷困不前。", "遶行香爛熳，折贈意纏綿。", "誰計江南曲，風流合管弦。"]'),
('150ef6ef-e46c-44bc-8b17-5ec7f827720c','和王郎中召看牡丹','姚合','唐','唐诗','tang','','[]','葩疊萼相重，燒欄復照空。',144,'全唐诗/poet.tang.26000.json','["葩疊萼相重，燒欄復照空。", "妍姿朝景裏，醉豔晚煙中。", "乍怪霞臨砌，還疑燭出籠。", "遶行驚地赤，移坐覺衣紅。", "殷麗開繁朵，香濃發幾叢。", "裁綃樣豈似，染茜色寧同。", "嫩畏人看損，鮮愁日炙融。", "嬋娟涵宿露，爛熳抵春風。", "縱賞襟情合，閑吟景思通。", "客來歸盡懶，鶯戀語無窮。", "萬物珍那比，千金買不充。", "如今難更有，縱有在仙宮。"]'),
('d02aa2b3-298e-4dcf-afb7-69647b6bd959','詠南池嘉蓮','姚合','唐','唐诗','tang','','[]','芙蓉池裏葉田田，一本雙花出碧泉。',64,'全唐诗/poet.tang.26000.json','["芙蓉池裏葉田田，一本雙花出碧泉。", "濃淡共妍香各散，東西分豔蔕相連。", "自知政術無他異，縱是禎祥亦偶然。", "四野人聞皆盡喜，爭來入郭看嘉蓮。"]'),
('d74773a5-dd27-43f6-9440-72fee4727c1c','種葦','姚合','唐','唐诗','tang','','[]','欲種數莖葦，出門來往頻。',48,'全唐诗/poet.tang.26000.json','["欲種數莖葦，出門來往頻。", "近陂收本土，選地問幽人。", "靜看唯思長，初移未覺勻。", "坐中尋竹客，將去更逡巡。"]'),
('eff92657-8145-4ec4-b831-368e55dc7686','採松花','姚合','唐','唐诗','tang','','[]','擬服松花無處學，嵩陽道士忽相教。',32,'全唐诗/poet.tang.26000.json','["擬服松花無處學，嵩陽道士忽相教。", "今朝試上高枝採，不覺傾翻仙鶴巢。"]'),
('7700e970-969a-46bb-9fec-0e29a0d88806','詠新菊','姚合','唐','唐诗','tang','','[]','黃金色未足，摘取且嘗新。',24,'全唐诗/poet.tang.26000.json','["黃金色未足，摘取且嘗新。", "若待重陽日，何曾異衆人。"]'),
('24a164f4-a592-4403-81cc-07f6ab4a714f','楊柳枝詞五首 一','姚合','唐','唐诗','tang','','[]','黃金絲挂粉牆頭，動似顛狂靜似愁。',32,'全唐诗/poet.tang.26000.json','["黃金絲挂粉牆頭，動似顛狂靜似愁。", "遊客見時心自醉，無因得見謝家樓。"]'),
('8c5903f9-caab-4992-a3e9-32c0a50457fe','楊柳枝詞五首 二','姚合','唐','唐诗','tang','','[]','葉葉如眉翠色濃，黃鶯偏戀語從容。',32,'全唐诗/poet.tang.26000.json','["葉葉如眉翠色濃，黃鶯偏戀語從容。", "橋邊陌上無人識，雨濕煙和思萬重。"]'),
('ab4f8fb9-91a4-4302-89a9-aeef2f4fc4c5','楊柳枝詞五首 三','姚合','唐','唐诗','tang','','[]','江上東西離別饒，舊條折盡折新條。',32,'全唐诗/poet.tang.26000.json','["江上東西離別饒，舊條折盡折新條。", "亦知春色人將去，猶勝狂風取次飄。"]'),
('6305916b-6d88-46e0-abfc-f6edb06f4392','楊柳枝詞五首 四','姚合','唐','唐诗','tang','','[]','二月楊花觸處飛，悠悠漠漠自東西。',32,'全唐诗/poet.tang.26000.json','["二月楊花觸處飛，悠悠漠漠自東西。", "謝家詠雪徒相比，吹落庭前便作泥。"]');
